export const SOURCE_CODE =
  '================================================================================\nSNGCE COLLEGE MANAGEMENT APP \u2014 FULL SOURCE CODE\n================================================================================\n\n\n================================================================================\nCATEGORY 1: BACKEND (Motoko)\n================================================================================\n\n--------------------------------------------------------------------------------\nFILE: src/backend/main.mo\n--------------------------------------------------------------------------------\nimport Array "mo:core/Array";\nimport Order "mo:core/Order";\nimport Text "mo:core/Text";\nimport List "mo:core/List";\nimport Map "mo:core/Map";\nimport Iter "mo:core/Iter";\nimport Runtime "mo:core/Runtime";\nimport Nat8 "mo:core/Nat8";\nimport Float "mo:core/Float";\nimport Char "mo:core/Char";\nimport Time "mo:core/Time";\nimport Int "mo:core/Int";\nimport Nat "mo:core/Nat";\nimport Nat16 "mo:core/Nat16";\nimport Nat32 "mo:core/Nat32";\nimport Principal "mo:core/Principal";\nimport AccessControl "authorization/access-control";\nimport MixinAuthorization "authorization/MixinAuthorization";\n\nactor {\n  let accessControlState = AccessControl.initState();\n  include MixinAuthorization(accessControlState);\n\n  // Persistent Storage\n  let academicRecordsStore = Map.empty<Text, AcademicRecord>();\n  let studentPrincipalMap = Map.empty<Principal, Text>(); // Maps principal to studentId\n  let userProfiles = Map.empty<Principal, UserProfile>();\n\n  // ------------ Data Models ------------\n  public type UserProfile = {\n    name : Text;\n    role : Text; // "student" or "staff"\n    studentId : ?Text; // Only for students\n  };\n\n  type Degree = {\n    #bTech;\n    #mTech;\n    #mba;\n  };\n\n  module Degree {\n    public func toText(degree : Degree) : Text {\n      switch (degree) {\n        case (#bTech) { "BTech" };\n        case (#mTech) { "MTech" };\n        case (#mba) { "MBA" };\n      };\n    };\n  };\n\n  let s1 = Nat16.fromNat(1);\n  let s2 = Nat16.fromNat(2);\n  let s8 = Nat16.fromNat(8);\n\n  // Course Model\n  type Course = {\n    branch : Text;\n    degree : Degree;\n    durationYears : Nat16;\n  };\n\n  // Fee Structure Model\n  type FeeStructure = {\n    course : Course;\n    yearSemesterBreakdown : [{ yearOrSemester : Text; amount : Float }];\n  };\n\n  module FeeStructure {\n    public func compare(fee1 : FeeStructure, fee2 : FeeStructure) : Order.Order {\n      switch (Text.compare(fee1.course.branch, fee2.course.branch)) {\n        case (#equal) { Float.compare(fee1.yearSemesterBreakdown[0].amount, fee2.yearSemesterBreakdown[0].amount) };\n        case (order) { order };\n      };\n    };\n  };\n\n  // Faculty Member Model\n  type FacultyMember = {\n    name : Text;\n    qualification : Text;\n    subjectsTaught : [Text];\n    department : Text;\n  };\n\n  module FacultyMember {\n    public func compare(fac1 : FacultyMember, fac2 : FacultyMember) : Order.Order {\n      switch (Text.compare(fac1.department, fac2.department)) {\n        case (#equal) { Text.compare(fac1.name, fac2.name) };\n        case (order) { order };\n      };\n    };\n  };\n\n  // Student Record Model\n  type Student = {\n    studentId : Text;\n    firstName : Text;\n    lastName : Text;\n    department : Text;\n    degree : Degree;\n  };\n\n  module Student {\n    public func compare(stu1 : Student, stu2 : Student) : Order.Order {\n      Text.compare(stu1.lastName, stu2.lastName);\n    };\n  };\n\n  type Subject = {\n    subjectId : Text;\n    name : Text;\n    code : Text;\n    year : Nat;\n    semester : Nat;\n    department : Text;\n  };\n\n  module Subject {\n    public func compare(subj1 : Subject, subj2 : Subject) : Order.Order {\n      switch (Text.compare(subj1.department, subj2.department)) {\n        case (#equal) { Text.compare(subj1.name, subj2.name) };\n        case (order) { order };\n      };\n    };\n  };\n\n  type Attendance = {\n    subjectId : Text;\n    percentage : Float;\n  };\n\n  module Attendance {\n    public func compare(att1 : Attendance, att2 : Attendance) : Order.Order {\n      Float.compare(att1.percentage, att2.percentage);\n    };\n  };\n\n  type Marks = {\n    subjectId : Text;\n    examType : Text;\n    marks : Int;\n  };\n\n  module Marks {\n    public func compare(m1 : Marks, m2 : Marks) : Order.Order {\n      Int.compare(m1.marks, m2.marks);\n    };\n  };\n\n  type Exam = {\n    examId : Text;\n    subjectId : Text;\n    examType : Text;\n    date : Time.Time;\n  };\n\n  module Exam {\n    public func compare(exam1 : Exam, exam2 : Exam) : Order.Order {\n      Int.compare(exam1.date, exam2.date);\n    };\n  };\n\n  type FeesDue = {\n    amount : Float;\n    dueDate : Time.Time;\n    yearSemester : Text;\n  };\n\n  module FeesDue {\n    public func compare(f1 : FeesDue, f2 : FeesDue) : Order.Order {\n      Float.compare(f1.amount, f2.amount);\n    };\n  };\n\n  type AcademicRecord = {\n    student : Student;\n    subjects : [Subject];\n    attendance : [Attendance];\n    marks : [Marks];\n    exams : [Exam];\n    feesDue : [FeesDue];\n  };\n\n  module AcademicRecord {\n    public func compare(rec1 : AcademicRecord, rec2 : AcademicRecord) : Order.Order {\n      Student.compare(rec1.student, rec2.student);\n    };\n  };\n\n  type FAQEntry = {\n    keywords : [Text];\n    response : Text;\n  };\n\n  module FAQEntry {\n    public func compare(faq1 : FAQEntry, faq2 : FAQEntry) : Order.Order {\n      Text.compare(faq1.keywords[0], faq2.keywords[0]);\n    };\n  };\n\n  // ------------ Hardcoded Data ------------\n  let courses : [Course] = [\n    {\n      branch = "Computer Science Engineering";\n      degree = #bTech;\n      durationYears = 4;\n    },\n    {\n      branch = "Mechanical Engineering";\n      degree = #bTech;\n      durationYears = 4;\n    },\n    {\n      branch = "Electrical Engineering";\n      degree = #mTech;\n      durationYears = 2;\n    },\n    {\n      branch = "Business Administration";\n      degree = #mba;\n      durationYears = 2;\n    },\n  ];\n\n  let feeStructures : [FeeStructure] = [\n    {\n      course = courses[0];\n      yearSemesterBreakdown = [\n        { yearOrSemester = "Year 1"; amount = 80000.0 },\n        { yearOrSemester = "Year 2"; amount = 80000.0 },\n        { yearOrSemester = "Year 3"; amount = 75000.0 },\n        { yearOrSemester = "Year 4"; amount = 75000.0 },\n      ];\n    },\n    {\n      course = courses[1];\n      yearSemesterBreakdown = [\n        { yearOrSemester = "Year 1"; amount = 78000.0 },\n        { yearOrSemester = "Year 2"; amount = 78000.0 },\n        { yearOrSemester = "Year 3"; amount = 76000.0 },\n        { yearOrSemester = "Year 4"; amount = 76000.0 },\n      ];\n    },\n    {\n      course = courses[2];\n      yearSemesterBreakdown = [\n        { yearOrSemester = "Year 1"; amount = 120000.0 },\n        { yearOrSemester = "Year 2"; amount = 120000.0 },\n      ];\n    },\n    {\n      course = courses[3];\n      yearSemesterBreakdown = [\n        { yearOrSemester = "Year 1"; amount = 95000.0 },\n        { yearOrSemester = "Year 2"; amount = 95000.0 },\n      ];\n    },\n  ];\n\n  let facultyDirectory : [FacultyMember] = [\n    {\n      name = "Alice Thomas";\n      qualification = "PhD (CSE)";\n      subjectsTaught = ["Data Structures", "Algorithms"];\n      department = "Computer Science";\n    },\n    {\n      name = "Rajesh Kumar";\n      qualification = "MTech (Mechanical)";\n      subjectsTaught = ["Thermodynamics", "Fluid Mechanics"];\n      department = "Mechanical Engineering";\n    },\n    {\n      name = "Nisha Pillai";\n      qualification = "MBA (Finance)";\n      subjectsTaught = ["Managerial Economics", "Accounting"];\n      department = "Business Administration";\n    },\n  ];\n\n  // ------------ Helper Functions ------------\n  // Check if caller is authorized to access a specific student\'s record\n  func canAccessStudentRecord(caller : Principal, studentId : Text) : Bool {\n    // Staff (admins) can access all records\n    if (AccessControl.isAdmin(accessControlState, caller)) {\n      return true;\n    };\n\n    // Students can only access their own records\n    switch (studentPrincipalMap.get(caller)) {\n      case (?callerStudentId) { callerStudentId == studentId };\n      case (null) { false };\n    };\n  };\n\n  // Chatbot Response Matching\n  func normalize(text : Text) : Text {\n    let lower = text.map(\n      func(c) {\n        if (c >= \'A\' and c <= \'Z\') {\n          Char.fromNat32(c.toNat32() + 32);\n        } else {\n          c;\n        };\n      }\n    );\n    let chars = lower.toArray();\n    let filtered = chars.map(func(c) { c }).filter(\n      func(c) { c != \' \' and c != \'?\' and c != \'.\' and c != \',\' }\n    );\n    Text.fromArray(filtered);\n  };\n\n  func equalsIgnoreCase(text1 : Text, text2 : Text) : Bool {\n    normalize(text1) == normalize(text2);\n  };\n\n  func contains(text : Text, substring : Text) : Bool {\n    let textArray = text.toArray();\n    let substringArray = substring.toArray();\n    let textLen = textArray.size();\n    let substringLen = substringArray.size();\n\n    if (substringLen == 0 or substringLen > textLen) {\n      return false;\n    };\n\n    func isSubstringAt(index : Nat) : Bool {\n      func checkChar(pos : Nat) : Bool {\n        if (pos == substringLen) {\n          return true;\n        };\n        if (not equalsIgnoreCase(Text.fromArray([textArray[index + pos]]), Text.fromArray([substringArray[pos]]))) {\n          return false;\n        };\n        checkChar(pos + 1);\n      };\n\n      checkChar(0);\n    };\n\n    func checkIndex(index : Nat) : Bool {\n      if (index > textLen - substringLen) {\n        return false;\n      };\n      if (isSubstringAt(index)) {\n        return true;\n      };\n      checkIndex(index + 1);\n    };\n\n    checkIndex(0);\n  };\n\n  // ------------ User Profile Functions ------------\n  public query ({ caller }) func getCallerUserProfile() : async ?UserProfile {\n    if (not (AccessControl.hasPermission(accessControlState, caller, #user))) {\n      Runtime.trap("Unauthorized: Only users can access profiles");\n    };\n    userProfiles.get(caller);\n  };\n\n  public query ({ caller }) func getUserProfile(user : Principal) : async ?UserProfile {\n    if (caller != user and not AccessControl.isAdmin(accessControlState, caller)) {\n      Runtime.trap("Unauthorized: Can only view your own profile");\n    };\n    userProfiles.get(user);\n  };\n\n  public shared ({ caller }) func saveCallerUserProfile(profile : UserProfile) : async () {\n    if (not (AccessControl.hasPermission(accessControlState, caller, #user))) {\n      Runtime.trap("Unauthorized: Only users can save profiles");\n    };\n    userProfiles.add(caller, profile);\n\n    // If this is a student profile, update the principal mapping\n    switch (profile.studentId) {\n      case (?studentId) {\n        studentPrincipalMap.add(caller, studentId);\n      };\n      case (null) {};\n    };\n  };\n\n  // ------------ Public Functions ------------\n  // Course and Fee Structure Functions (Public - no auth needed)\n  public query ({ caller }) func getAllCourses() : async [Course] {\n    courses;\n  };\n\n  public query ({ caller }) func getAllFeeStructures() : async [FeeStructure] {\n    feeStructures.sort<FeeStructure>();\n  };\n\n  public query ({ caller }) func getFeeStructureByCourse(course : Course) : async FeeStructure {\n    switch (feeStructures.find(func(f) { f.course == course })) {\n      case (?structure) { structure };\n      case (null) { { course; yearSemesterBreakdown = [] } };\n    };\n  };\n\n  // Faculty Directory Functions (Public - no auth needed)\n  public query ({ caller }) func getFacultyDirectory() : async [FacultyMember] {\n    facultyDirectory.sort<FacultyMember>();\n  };\n\n  public query ({ caller }) func getFacultyByDepartment(department : Text) : async [FacultyMember] {\n    facultyDirectory.filter(func(f) { f.department == department }).sort<FacultyMember>(\n    );\n  };\n\n  // Academic Record Functions (Staff only for write, restricted read)\n  public shared ({ caller }) func addOrUpdateAcademicRecord(studentId : Text, record : AcademicRecord) : async () {\n    if (not AccessControl.isAdmin(accessControlState, caller)) {\n      Runtime.trap("Unauthorized: Only staff can add or update records");\n    };\n    academicRecordsStore.add(studentId, record);\n  };\n\n  public query ({ caller }) func getAllAcademicRecords() : async [AcademicRecord] {\n    if (not AccessControl.isAdmin(accessControlState, caller)) {\n      Runtime.trap("Unauthorized: Only staff can view all records");\n    };\n    academicRecordsStore.values().toArray().sort<AcademicRecord>(\n    );\n  };\n\n  public query ({ caller }) func getStudentRecord(studentId : Text) : async AcademicRecord {\n    if (not canAccessStudentRecord(caller, studentId)) {\n      Runtime.trap("Unauthorized: You can only view your own record or you must be staff");\n    };\n\n    switch (academicRecordsStore.get(studentId)) {\n      case (?record) { record };\n      case (null) { Runtime.trap("Student record not found") };\n    };\n  };\n\n  public query ({ caller }) func getOwnRecord() : async AcademicRecord {\n    if (not (AccessControl.hasPermission(accessControlState, caller, #user))) {\n      Runtime.trap("Unauthorized: Only authenticated users can access records");\n    };\n\n    switch (studentPrincipalMap.get(caller)) {\n      case (?studentId) {\n        switch (academicRecordsStore.get(studentId)) {\n          case (?record) { record };\n          case (null) { Runtime.trap("Student record not found") };\n        };\n      };\n      case (null) { Runtime.trap("No student ID associated with this user") };\n    };\n  };\n\n  // Subject, Attendance, Marks, Exam, Fees Functions\n  public query ({ caller }) func getSubjectsByDepartment(department : Text) : async [Subject] {\n    let records = academicRecordsStore.values().toArray();\n    let subjectsList = records.foldLeft(\n      [] : [Subject],\n      func(acc, record) {\n        acc.concat(record.subjects);\n      },\n    );\n    subjectsList.filter(func(s) { s.department == department }).sort<Subject>(\n    );\n  };\n\n  public query ({ caller }) func getAttendanceByStudent(studentId : Text) : async [Attendance] {\n    if (not canAccessStudentRecord(caller, studentId)) {\n      Runtime.trap("Unauthorized: You can only view your own attendance or you must be staff");\n    };\n\n    switch (academicRecordsStore.get(studentId)) {\n      case (?record) { record.attendance.sort<Attendance>() };\n      case (null) { Runtime.trap("Student record not found") };\n    };\n  };\n\n  public query ({ caller }) func getMarksByStudent(studentId : Text) : async [Marks] {\n    if (not canAccessStudentRecord(caller, studentId)) {\n      Runtime.trap("Unauthorized: You can only view your own marks or you must be staff");\n    };\n\n    switch (academicRecordsStore.get(studentId)) {\n      case (?record) { record.marks.sort<Marks>() };\n      case (null) { Runtime.trap("Student record not found") };\n    };\n  };\n\n  public query ({ caller }) func getExamTimetableByDepartment(department : Text) : async [Exam] {\n    let records = academicRecordsStore.values().toArray();\n    let examsList = records.foldLeft(\n      [] : [Exam],\n      func(acc, record) {\n        acc.concat(record.exams);\n      },\n    );\n    examsList.filter(func(e) { e.subjectId == department }).sort<Exam>(\n    );\n  };\n\n  public query ({ caller }) func getFeesDueByStudent(studentId : Text) : async [FeesDue] {\n    if (not canAccessStudentRecord(caller, studentId)) {\n      Runtime.trap("Unauthorized: You can only view your own fees or you must be staff");\n    };\n\n    switch (academicRecordsStore.get(studentId)) {\n      case (?record) { record.feesDue.sort<FeesDue>() };\n      case (null) { Runtime.trap("Student record not found") };\n    };\n  };\n\n  public query ({ caller }) func getDepartmentInfo(department : Text) : async {\n    courses : [Course];\n    faculty : [FacultyMember];\n    subjects : [Subject];\n  } {\n    let records = academicRecordsStore.values().toArray();\n    let subjectsList = records.foldLeft(\n      [] : [Subject],\n      func(acc, record) {\n        acc.concat(record.subjects);\n      },\n    );\n    {\n      courses = courses.filter(func(c) { c.branch == department });\n      faculty = facultyDirectory.filter(func(f) { f.department == department });\n      subjects = subjectsList.filter(func(s) { s.department == department }).sort<Subject>(\n      );\n    };\n  };\n\n  // Chatbot Functionality (Public - no auth needed)\n  let faqEntries : [FAQEntry] = [\n    {\n      keywords = ["admissions", "admission process"];\n      response = "The admission process for SNGCE includes submitting an application form, entrance exam (if applicable), followed by a personal interview.";\n    },\n    {\n      keywords = ["fees", "fee structure"];\n      response = "Fee structure varies by course. Check the \'Fees Structure\' section for detailed breakdown.";\n    },\n    {\n      keywords = ["contact", "contact information"];\n      response = "You can contact SNGCE at: Phone: +91 1234567890, Email: info@sngce.ac.in";\n    },\n  ];\n\n  public query ({ caller }) func getFAQEntries() : async [FAQEntry] {\n    faqEntries.sort<FAQEntry>();\n  };\n\n  public query ({ caller }) func getChatbotResponse(message : Text) : async Text {\n    let normalizedMessage = normalize(message);\n\n    func findFaqEntry(faq : FAQEntry) : Bool {\n      func keywordMatches(keyword : Text) : Bool {\n        contains(normalize(normalizedMessage), normalize(keyword));\n      };\n      switch (faq.keywords.find(keywordMatches)) {\n        case (?_) { true };\n        case (null) { false };\n      };\n    };\n\n    switch (faqEntries.find(findFaqEntry)) {\n      case (?entry) { entry.response };\n      case (null) {\n        "Sorry, I didn\'t understand your question. Please try using different keywords or ask a specific query related to SNGCE.";\n      };\n    };\n  };\n};\n\n\n================================================================================\nCATEGORY 2: ROUTING\n================================================================================\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/App.tsx\n--------------------------------------------------------------------------------\nimport { Toaster } from "@/components/ui/sonner";\nimport {\n  Outlet,\n  RouterProvider,\n  createRootRoute,\n  createRoute,\n  createRouter,\n  redirect,\n} from "@tanstack/react-router";\nimport { Layout } from "./components/Layout";\nimport { AuthProvider, useAuth } from "./contexts/AuthContext";\nimport { ThemeProvider } from "./contexts/ThemeContext";\nimport { AdminDashboard } from "./pages/AdminDashboard";\nimport { ClassifiedPage } from "./pages/ClassifiedPage";\nimport { CoursesPage } from "./pages/CoursesPage";\nimport { FacultyPage } from "./pages/FacultyPage";\nimport { FeesPage } from "./pages/FeesPage";\nimport { HomePage } from "./pages/HomePage";\nimport { LoginPage } from "./pages/LoginPage";\nimport { SplashPage } from "./pages/SplashPage";\nimport { StaffDashboard } from "./pages/StaffDashboard";\nimport { StudentDashboard } from "./pages/StudentDashboard";\n\n// Root route\nconst rootRoute = createRootRoute({\n  component: () => (\n    <AuthProvider>\n      <ThemeProvider>\n        <Outlet />\n        <Toaster richColors />\n      </ThemeProvider>\n    </AuthProvider>\n  ),\n});\n\n// Splash\nconst splashRoute = createRoute({\n  getParentRoute: () => rootRoute,\n  path: "/",\n  component: SplashPage,\n});\n\n// Layout route (wraps pages with navbar + chatbot)\nconst layoutRoute = createRoute({\n  getParentRoute: () => rootRoute,\n  id: "layout",\n  component: Layout,\n});\n\n// Home\nconst homeRoute = createRoute({\n  getParentRoute: () => layoutRoute,\n  path: "/home",\n  component: HomePage,\n});\n\n// Courses\nconst coursesRoute = createRoute({\n  getParentRoute: () => layoutRoute,\n  path: "/courses",\n  component: CoursesPage,\n});\n\n// Fees\nconst feesRoute = createRoute({\n  getParentRoute: () => layoutRoute,\n  path: "/fees",\n  component: FeesPage,\n});\n\n// Faculty\nconst facultyRoute = createRoute({\n  getParentRoute: () => layoutRoute,\n  path: "/faculty",\n  component: FacultyPage,\n});\n\n// Login\nconst loginRoute = createRoute({\n  getParentRoute: () => layoutRoute,\n  path: "/login",\n  component: LoginPage,\n});\n\n// Student dashboard\nconst studentDashboardRoute = createRoute({\n  getParentRoute: () => layoutRoute,\n  path: "/student-dashboard",\n  component: StudentDashboard,\n});\n\n// Staff dashboard\nconst staffDashboardRoute = createRoute({\n  getParentRoute: () => layoutRoute,\n  path: "/staff-dashboard",\n  component: StaffDashboard,\n});\n\n// Admin dashboard\nconst adminDashboardRoute = createRoute({\n  getParentRoute: () => layoutRoute,\n  path: "/admin-dashboard",\n  component: AdminDashboard,\n});\n\n// Classified page\nconst classifiedRoute = createRoute({\n  getParentRoute: () => layoutRoute,\n  path: "/classified",\n  component: ClassifiedPage,\n});\n\n// Build route tree\nconst routeTree = rootRoute.addChildren([\n  splashRoute,\n  layoutRoute.addChildren([\n    homeRoute,\n    coursesRoute,\n    feesRoute,\n    facultyRoute,\n    loginRoute,\n    studentDashboardRoute,\n    staffDashboardRoute,\n    adminDashboardRoute,\n    classifiedRoute,\n  ]),\n]);\n\nconst router = createRouter({ routeTree });\n\ndeclare module "@tanstack/react-router" {\n  interface Register {\n    router: typeof router;\n  }\n}\n\nexport default function App() {\n  return <RouterProvider router={router} />;\n}\n\n\n================================================================================\nCATEGORY 3: PAGES\n================================================================================\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/pages/SplashPage.tsx\n--------------------------------------------------------------------------------\nimport { useNavigate } from "@tanstack/react-router";\nimport { useEffect } from "react";\n\nexport function SplashPage() {\n  const navigate = useNavigate();\n\n  useEffect(() => {\n    const timer = setTimeout(() => {\n      navigate({ to: "/home" });\n    }, 3800);\n    return () => clearTimeout(timer);\n  }, [navigate]);\n\n  return (\n    <div\n      className="fixed inset-0 z-[100] flex flex-col items-center justify-center overflow-hidden"\n      style={{\n        background:\n          "linear-gradient(135deg, #0a0a0a 0%, #111111 40%, #0d0d0d 100%)",\n      }}\n    >\n      {/* Background college image */}\n      <div\n        className="absolute inset-0 opacity-20"\n        style={{\n          backgroundImage:\n            "url(\'https://images.unsplash.com/photo-1562774053-701939374585?w=1920&q=80\')",\n          backgroundSize: "cover",\n          backgroundPosition: "center",\n          filter: "grayscale(60%) blur(2px)",\n        }}\n      />\n\n      {/* Radial glow */}\n      <div\n        className="absolute inset-0"\n        style={{\n          background:\n            "radial-gradient(ellipse 60% 50% at 50% 50%, rgba(255,255,255,0.04) 0%, transparent 70%)",\n        }}\n      />\n\n      {/* Content */}\n      <div className="relative z-10 flex flex-col items-center gap-4 text-center px-8">\n        {/* Welcome to */}\n        <p\n          className="text-white/60 text-lg font-sans tracking-widest uppercase"\n          style={{\n            opacity: 0,\n            animation: "fadeInUp 0.8s ease 0.4s forwards",\n          }}\n        >\n          Welcome to\n        </p>\n\n        {/* SNGCE */}\n        <h1\n          className="font-display font-bold text-white"\n          style={{\n            fontSize: "clamp(3rem, 10vw, 6rem)",\n            opacity: 0,\n            animation:\n              "expandLetters 1.2s cubic-bezier(0.23, 1, 0.32, 1) 0.9s forwards",\n          }}\n        >\n          SNGCE\n        </h1>\n\n        {/* Full name */}\n        <p\n          className="text-white/50 text-sm sm:text-base font-sans max-w-md leading-relaxed"\n          style={{\n            opacity: 0,\n            animation: "subtitleFade 0.9s ease 2.0s forwards",\n          }}\n        >\n          Sree Narayana Gurukulam College of Engineering\n          <br />\n          <span className="text-white/35 text-xs">\n            Kadayirippu, Ernakulam, Kerala\n          </span>\n        </p>\n\n        {/* Progress bar */}\n        <div className="mt-8 w-40 h-0.5 bg-white/10 rounded-full overflow-hidden">\n          <div\n            className="h-full bg-white/40 rounded-full"\n            style={{\n              width: 0,\n              animation: "progressBar 2.8s ease 0.5s forwards",\n            }}\n          />\n        </div>\n      </div>\n\n      {/* Subtle grain overlay */}\n      <div\n        className="absolute inset-0 pointer-events-none opacity-30"\n        style={{\n          backgroundImage:\n            "url(\\"data:image/svg+xml,%3Csvg viewBox=\'0 0 200 200\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'noiseFilter\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.85\' numOctaves=\'3\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23noiseFilter)\'/%3E%3C/svg%3E\\")",\n          backgroundRepeat: "repeat",\n          backgroundSize: "150px",\n        }}\n      />\n    </div>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/pages/HomePage.tsx\n--------------------------------------------------------------------------------\nimport { Link } from "@tanstack/react-router";\nimport {\n  BookOpen,\n  Bot,\n  ChevronRight,\n  DollarSign,\n  GraduationCap,\n  Mail,\n  MapPin,\n  MessageCircle,\n  Phone,\n  Send,\n  ShieldCheck,\n  Sparkles,\n  UserCircle,\n  Users,\n} from "lucide-react";\nimport { useRef, useState } from "react";\nimport { useTheme } from "../contexts/ThemeContext";\n\nconst QUICK_CHIPS = [\n  { label: "Courses \ud83d\udcda", query: "Courses" },\n  { label: "Fees \ud83d\udcb0", query: "Fees" },\n  { label: "Admissions \ud83c\udf93", query: "Admissions" },\n  { label: "Contact \ud83d\udcde", query: "Contact" },\n];\n\nconst navCards = [\n  {\n    to: "#chatbot",\n    icon: MessageCircle,\n    label: "AI Assistant",\n    desc: "Get instant answers",\n    ocid: "home.chatbot.card",\n    isChatbot: true,\n    isHighlighted: true,\n  },\n  {\n    to: "/courses",\n    icon: BookOpen,\n    label: "Courses Offered",\n    desc: "B.Tech, M.Tech & MBA programs",\n    ocid: "home.courses.card",\n  },\n  {\n    to: "/fees",\n    icon: DollarSign,\n    label: "Fee Structure",\n    desc: "Semester-wise fee breakdown",\n    ocid: "home.fees.card",\n  },\n  {\n    to: "/faculty",\n    icon: Users,\n    label: "Faculty Directory",\n    desc: "Meet our expert faculty",\n    ocid: "home.faculty.card",\n  },\n  {\n    to: "/login?tab=student",\n    icon: GraduationCap,\n    label: "Student Portal",\n    desc: "Access your academic records",\n    ocid: "home.student.card",\n  },\n  {\n    to: "/login?tab=staff",\n    icon: ShieldCheck,\n    label: "Staff Portal",\n    desc: "Manage student records",\n    ocid: "home.staff.card",\n  },\n];\n\nfunction openChatbotWithMessage(message: string) {\n  // Step 1: Open the chatbot widget\n  const openBtn = document.querySelector<HTMLButtonElement>(\n    \'[data-ocid="chatbot.open_modal_button"]\',\n  );\n  if (openBtn) {\n    openBtn.click();\n  }\n\n  // Step 2: After a short delay, inject the message and submit\n  setTimeout(() => {\n    const chatInput = document.querySelector<HTMLInputElement>(\n      \'[data-ocid="chatbot.input"]\',\n    );\n    if (chatInput) {\n      // Use React\'s native input value setter so React state updates properly\n      const nativeInputValueSetter = Object.getOwnPropertyDescriptor(\n        window.HTMLInputElement.prototype,\n        "value",\n      )?.set;\n      if (nativeInputValueSetter) {\n        nativeInputValueSetter.call(chatInput, message);\n        chatInput.dispatchEvent(new Event("input", { bubbles: true }));\n      }\n\n      // Small additional delay for React to sync state before clicking submit\n      setTimeout(() => {\n        const submitBtn = document.querySelector<HTMLButtonElement>(\n          \'[data-ocid="chatbot.submit_button"]\',\n        );\n        submitBtn?.click();\n      }, 80);\n    }\n  }, 120);\n}\n\nexport function HomePage() {\n  const { theme } = useTheme();\n  const isDark = theme === "dark";\n  const [heroInput, setHeroInput] = useState("");\n  const heroInputRef = useRef<HTMLInputElement>(null);\n\n  const handleHeroSubmit = () => {\n    const text = heroInput.trim();\n    if (!text) return;\n    setHeroInput("");\n    openChatbotWithMessage(text);\n  };\n\n  const handleHeroChip = (query: string) => {\n    openChatbotWithMessage(query);\n  };\n\n  return (\n    <div className="relative min-h-screen overflow-x-hidden">\n      {/* Background image */}\n      <div className="fixed inset-0 -z-10">\n        <img\n          src="https://images.unsplash.com/photo-1562774053-701939374585?w=1920&q=80"\n          alt="College campus"\n          className="w-full h-full object-cover"\n          style={{\n            filter: isDark\n              ? "grayscale(40%) brightness(0.35)"\n              : "grayscale(20%) brightness(0.75)",\n          }}\n        />\n        <div\n          className={\n            isDark\n              ? "bg-overlay absolute inset-0"\n              : "bg-overlay-light absolute inset-0"\n          }\n        />\n      </div>\n\n      {/* Hero */}\n      <section className="relative pt-28 pb-10 px-4 sm:px-6 text-center">\n        <div className="max-w-3xl mx-auto">\n          <div className="inline-flex items-center gap-2 glass-sm px-4 py-1.5 rounded-full text-xs font-medium text-muted-foreground mb-6">\n            <MapPin size={12} />\n            Kadayirippu, Kolenchery, Ernakulam, Kerala\n          </div>\n          <h1\n            className="font-display font-bold text-foreground leading-tight mb-4 text-shadow"\n            style={{ fontSize: "clamp(2.2rem, 6vw, 4rem)" }}\n          >\n            Sree Narayana Gurukulam\n            <br />\n            <span className="text-foreground/70">College of Engineering</span>\n          </h1>\n          <p className="text-muted-foreground text-base sm:text-lg max-w-xl mx-auto leading-relaxed mb-8">\n            Empowering future engineers with excellence in education,\n            innovation, and research since 2002.\n          </p>\n          <div className="flex flex-wrap gap-3 justify-center">\n            <Link\n              to="/courses"\n              data-ocid="home.explore.primary_button"\n              className="glass-btn px-6 py-3 flex items-center gap-2 font-medium text-foreground"\n            >\n              Explore Courses\n              <ChevronRight size={16} />\n            </Link>\n            <Link\n              to="/login"\n              data-ocid="home.login.secondary_button"\n              className="glass-pill px-6 py-3 flex items-center gap-2 font-medium text-foreground"\n            >\n              <UserCircle size={16} />\n              Student Login\n            </Link>\n          </div>\n        </div>\n      </section>\n\n      {/* \u2500\u2500 AI Chatbot Hero \u2500\u2500 */}\n      <section className="px-4 sm:px-6 pb-10">\n        <div className="max-w-5xl mx-auto">\n          {/* Outer glow wrapper */}\n          <div\n            className="rounded-2xl p-[1px]"\n            style={{\n              background: isDark\n                ? "linear-gradient(135deg, rgba(255,255,255,0.18) 0%, rgba(255,255,255,0.06) 50%, rgba(255,255,255,0.14) 100%)"\n                : "linear-gradient(135deg, rgba(255,255,255,0.90) 0%, rgba(255,255,255,0.50) 50%, rgba(255,255,255,0.80) 100%)",\n              boxShadow: isDark\n                ? "0 0 48px rgba(255,255,255,0.06), 0 12px 40px rgba(0,0,0,0.45)"\n                : "0 0 48px rgba(255,255,255,0.55), 0 12px 40px rgba(0,0,0,0.10)",\n            }}\n          >\n            <div\n              className="glass rounded-2xl px-6 sm:px-10 py-8 sm:py-10 flex flex-col gap-6"\n              style={{ borderRadius: "15px" }}\n            >\n              {/* Header row */}\n              <div className="flex flex-col sm:flex-row sm:items-center gap-3">\n                <div\n                  className="glass-sm w-12 h-12 rounded-2xl flex items-center justify-center flex-shrink-0 animate-pulse-glow"\n                  style={{\n                    background: isDark\n                      ? "rgba(255,255,255,0.12)"\n                      : "rgba(255,255,255,0.75)",\n                  }}\n                >\n                  <Bot size={24} className="text-foreground" />\n                </div>\n                <div>\n                  <div className="flex items-center gap-2">\n                    <h2 className="font-display font-bold text-foreground text-xl sm:text-2xl leading-tight">\n                      SNGCE AI Assistant\n                    </h2>\n                    <span className="inline-flex items-center gap-1 glass-sm px-2 py-0.5 rounded-full text-[10px] font-medium text-muted-foreground">\n                      <Sparkles size={10} />\n                      Gemini AI\n                    </span>\n                  </div>\n                  <p className="text-muted-foreground text-sm mt-0.5">\n                    Ask me anything \u2014 courses, fees, admissions, faculty, or\n                    navigate the portal\n                  </p>\n                </div>\n              </div>\n\n              {/* Input row */}\n              <div className="flex gap-2 sm:gap-3">\n                <input\n                  ref={heroInputRef}\n                  type="text"\n                  value={heroInput}\n                  onChange={(e) => setHeroInput(e.target.value)}\n                  onKeyDown={(e) => e.key === "Enter" && handleHeroSubmit()}\n                  placeholder="e.g. What B.Tech courses does SNGCE offer?"\n                  data-ocid="home.chatbot_hero.input"\n                  className="flex-1 glass-sm px-4 py-3 text-sm sm:text-base text-foreground placeholder:text-muted-foreground bg-transparent outline-none rounded-xl border-none"\n                />\n                <button\n                  type="button"\n                  onClick={handleHeroSubmit}\n                  disabled={!heroInput.trim()}\n                  data-ocid="home.chatbot_hero.submit_button"\n                  className="glass-btn px-4 sm:px-5 py-3 flex items-center gap-2 text-foreground font-medium disabled:opacity-40 disabled:cursor-not-allowed whitespace-nowrap"\n                  aria-label="Ask the AI assistant"\n                >\n                  <Send size={16} />\n                  <span className="hidden sm:inline">Ask now</span>\n                </button>\n              </div>\n\n              {/* Quick chips */}\n              <div className="flex flex-wrap gap-2">\n                {QUICK_CHIPS.map((chip) => (\n                  <button\n                    key={chip.label}\n                    type="button"\n                    onClick={() => handleHeroChip(chip.query)}\n                    className="glass-sm px-3.5 py-1.5 rounded-full text-sm text-muted-foreground hover:text-foreground transition-colors cursor-pointer font-medium"\n                  >\n                    {chip.label}\n                  </button>\n                ))}\n              </div>\n            </div>\n          </div>\n        </div>\n      </section>\n\n      {/* Quick Nav Cards */}\n      <section className="px-4 sm:px-6 pb-16">\n        <div className="max-w-5xl mx-auto">\n          <h2 className="font-display font-semibold text-lg text-foreground/70 mb-6 text-center tracking-wide uppercase text-sm">\n            Quick Access\n          </h2>\n          <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 sm:gap-4">\n            {navCards.map((card) => {\n              const Icon = card.icon;\n              const CardContent = (\n                <div\n                  className={`glass p-5 flex flex-col gap-3 group hover:scale-[1.02] transition-transform duration-200 cursor-pointer h-full${card.isHighlighted ? " border border-foreground/20" : ""}`}\n                >\n                  <div className="glass-sm w-10 h-10 rounded-xl flex items-center justify-center group-hover:bg-foreground/10 transition-colors">\n                    <Icon size={20} className="text-foreground/70" />\n                  </div>\n                  <div>\n                    <p className="font-display font-semibold text-foreground text-sm leading-snug">\n                      {card.label}\n                    </p>\n                    <p className="text-muted-foreground text-xs mt-0.5 leading-relaxed">\n                      {card.desc}\n                    </p>\n                  </div>\n                  <ChevronRight\n                    size={14}\n                    className="text-muted-foreground mt-auto self-end group-hover:translate-x-1 transition-transform"\n                  />\n                </div>\n              );\n\n              if (card.isChatbot) {\n                return (\n                  <button\n                    type="button"\n                    key={card.label}\n                    data-ocid={card.ocid}\n                    onClick={() => {\n                      const btn = document.querySelector<HTMLButtonElement>(\n                        \'[data-ocid="chatbot.open_modal_button"]\',\n                      );\n                      btn?.click();\n                    }}\n                    className="text-left"\n                  >\n                    {CardContent}\n                  </button>\n                );\n              }\n              return (\n                <Link key={card.label} to={card.to} data-ocid={card.ocid}>\n                  {CardContent}\n                </Link>\n              );\n            })}\n          </div>\n        </div>\n      </section>\n\n      {/* Stats */}\n      <section className="px-4 sm:px-6 pb-16">\n        <div className="max-w-5xl mx-auto">\n          <div className="glass rounded-2xl p-6 grid grid-cols-2 sm:grid-cols-4 gap-6 text-center">\n            {[\n              { value: "23+", label: "Years of Excellence" },\n              { value: "3000+", label: "Students Enrolled" },\n              { value: "150+", label: "Faculty Members" },\n              { value: "10", label: "Departments" },\n            ].map((stat) => (\n              <div key={stat.label}>\n                <p className="font-display font-bold text-3xl text-foreground">\n                  {stat.value}\n                </p>\n                <p className="text-muted-foreground text-xs mt-1">\n                  {stat.label}\n                </p>\n              </div>\n            ))}\n          </div>\n        </div>\n      </section>\n\n      {/* Footer */}\n      <footer className="border-t border-white/10 px-4 sm:px-6 py-8">\n        <div className="max-w-5xl mx-auto">\n          <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 mb-6">\n            <div>\n              <h3 className="font-display font-bold text-foreground mb-2">\n                SNGCE\n              </h3>\n              <p className="text-muted-foreground text-xs leading-relaxed">\n                Sree Narayana Gurukulam College of Engineering, Kadayirippu,\n                Kolenchery, Ernakulam \u2014 established 2002. Approved by AICTE,\n                affiliated to APJ Abdul Kalam Technological University (KTU).\n                Managed by Sree Narayana Gurukulam Charitable Trust.\n              </p>\n            </div>\n            <div>\n              <h3 className="font-medium text-foreground text-sm mb-2">\n                Quick Links\n              </h3>\n              <div className="flex flex-col gap-1">\n                {["/courses", "/fees", "/faculty"].map((to) => (\n                  <Link\n                    key={to}\n                    to={to}\n                    className="text-muted-foreground text-xs hover:text-foreground transition-colors capitalize"\n                  >\n                    {to.replace("/", "")}\n                  </Link>\n                ))}\n              </div>\n            </div>\n            <div>\n              <h3 className="font-medium text-foreground text-sm mb-2">\n                Contact\n              </h3>\n              <div className="flex flex-col gap-1.5">\n                <div className="flex items-center gap-1.5 text-muted-foreground text-xs">\n                  <MapPin size={12} /> Kadayirippu P.O, Kolenchery, Ernakulam,\n                  Kerala 682311\n                </div>\n                <div className="flex items-center gap-1.5 text-muted-foreground text-xs">\n                  <Phone size={12} /> 0484-2597800 (30 Lines)\n                </div>\n                <div className="flex items-center gap-1.5 text-muted-foreground text-xs">\n                  <Mail size={12} /> info@sngce.ac.in\n                </div>\n              </div>\n            </div>\n          </div>\n          <div className="border-t border-white/10 pt-4 text-center text-muted-foreground text-xs">\n            \u00a9 {new Date().getFullYear()}. Built with love by SNGCE\n          </div>\n        </div>\n      </footer>\n    </div>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/pages/LoginPage.tsx\n--------------------------------------------------------------------------------\nimport { useNavigate } from "@tanstack/react-router";\nimport {\n  Eye,\n  EyeOff,\n  GraduationCap,\n  Info,\n  LogIn,\n  ShieldAlert,\n  ShieldCheck,\n} from "lucide-react";\nimport { useEffect, useState } from "react";\nimport { toast } from "sonner";\nimport { useAuth } from "../contexts/AuthContext";\nimport { useTheme } from "../contexts/ThemeContext";\n\n// Helper to read tab from URL\nfunction getTabFromSearch(): "student" | "staff" | "admin" {\n  const params = new URLSearchParams(window.location.search);\n  const tab = params.get("tab");\n  if (tab === "staff") return "staff";\n  if (tab === "admin") return "admin";\n  return "student";\n}\n\n// Demo credentials\nconst DEMO_STUDENTS: Record<\n  string,\n  { password: string; name: string; dept: string }\n> = {\n  STU001: {\n    password: "pass123",\n    name: "Arjun Menon",\n    dept: "Computer Science",\n  },\n  STU002: {\n    password: "pass123",\n    name: "Priya Nair",\n    dept: "Electronics & Communication",\n  },\n  STU003: {\n    password: "pass123",\n    name: "Rahul Krishnan",\n    dept: "Mechanical Engineering",\n  },\n};\n\nconst DEMO_STAFF: Record<string, { password: string; name: string }> = {\n  STAFF001: { password: "pass123", name: "Dr. Rajan Pillai" },\n  STAFF002: { password: "pass123", name: "Prof. Suja Thomas" },\n};\n\nconst DEMO_ADMIN: Record<string, { password: string; name: string }> = {\n  ADMIN001: { password: "admin123", name: "Principal Admin" },\n};\n\nexport function LoginPage() {\n  const navigate = useNavigate();\n  const { login, isLoggedIn, role } = useAuth();\n  const { theme } = useTheme();\n  const isDark = theme === "dark";\n\n  const [activeTab, setActiveTab] = useState<"student" | "staff" | "admin">(\n    getTabFromSearch,\n  );\n  const [id, setId] = useState("");\n  const [password, setPassword] = useState("");\n  const [showPass, setShowPass] = useState(false);\n  const [loading, setLoading] = useState(false);\n  const [error, setError] = useState("");\n\n  // Redirect if already logged in\n  useEffect(() => {\n    if (isLoggedIn) {\n      if (role === "student") navigate({ to: "/student-dashboard" });\n      else if (role === "admin") navigate({ to: "/admin-dashboard" });\n      else navigate({ to: "/staff-dashboard" });\n    }\n  }, [isLoggedIn, role, navigate]);\n\n  const handleLogin = async (e: React.FormEvent) => {\n    e.preventDefault();\n    setError("");\n    setLoading(true);\n\n    await new Promise((r) => setTimeout(r, 700));\n\n    if (activeTab === "student") {\n      const student = DEMO_STUDENTS[id.toUpperCase()];\n      if (!student || student.password !== password) {\n        setError("Invalid Student ID or password.");\n        setLoading(false);\n        return;\n      }\n      login("student", student.name, id.toUpperCase());\n      toast.success(`Welcome back, ${student.name}!`);\n      navigate({ to: "/student-dashboard" });\n    } else if (activeTab === "admin") {\n      const admin = DEMO_ADMIN[id.toUpperCase()];\n      if (!admin || admin.password !== password) {\n        setError("Invalid Admin ID or password.");\n        setLoading(false);\n        return;\n      }\n      login("admin", admin.name);\n      toast.success(`Welcome, ${admin.name}!`);\n      navigate({ to: "/admin-dashboard" });\n    } else {\n      const staff = DEMO_STAFF[id.toUpperCase()];\n      if (!staff || staff.password !== password) {\n        setError("Invalid Staff ID or password.");\n        setLoading(false);\n        return;\n      }\n      login("staff", staff.name);\n      toast.success(`Welcome, ${staff.name}!`);\n      navigate({ to: "/staff-dashboard" });\n    }\n\n    setLoading(false);\n  };\n\n  return (\n    <div className="relative min-h-screen flex items-center justify-center">\n      {/* BG */}\n      <div className="fixed inset-0 -z-10">\n        <img\n          src="https://images.unsplash.com/photo-1562774053-701939374585?w=1920&q=80"\n          alt="Campus"\n          className="w-full h-full object-cover"\n          style={{\n            filter: isDark\n              ? "grayscale(60%) brightness(0.20)"\n              : "grayscale(20%) brightness(0.75)",\n          }}\n        />\n        <div\n          className={\n            isDark\n              ? "bg-overlay absolute inset-0"\n              : "bg-overlay-light absolute inset-0"\n          }\n        />\n      </div>\n\n      <div className="w-full max-w-md px-4 py-10">\n        {/* Card */}\n        <div className="glass rounded-2xl p-8">\n          {/* Header */}\n          <div className="text-center mb-8">\n            <div className="glass-sm w-14 h-14 rounded-2xl flex items-center justify-center mx-auto mb-4">\n              {activeTab === "student" ? (\n                <GraduationCap size={24} className="text-foreground/70" />\n              ) : activeTab === "admin" ? (\n                <ShieldAlert size={24} className="text-foreground/70" />\n              ) : (\n                <ShieldCheck size={24} className="text-foreground/70" />\n              )}\n            </div>\n            <h1 className="font-display font-bold text-2xl text-foreground">\n              Sign In\n            </h1>\n            <p className="text-muted-foreground text-sm mt-1">\n              Access your SNGCE portal\n            </p>\n          </div>\n\n          {/* Tab switcher */}\n          <div className="glass-sm flex rounded-xl p-1 mb-6">\n            <button\n              type="button"\n              onClick={() => {\n                setActiveTab("student");\n                setError("");\n                setId("");\n                setPassword("");\n              }}\n              data-ocid="login.student.tab"\n              className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium transition-all ${\n                activeTab === "student"\n                  ? "bg-foreground/10 text-foreground"\n                  : "text-muted-foreground hover:text-foreground"\n              }`}\n            >\n              <GraduationCap size={15} />\n              Student\n            </button>\n            <button\n              type="button"\n              onClick={() => {\n                setActiveTab("staff");\n                setError("");\n                setId("");\n                setPassword("");\n              }}\n              data-ocid="login.staff.tab"\n              className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium transition-all ${\n                activeTab === "staff"\n                  ? "bg-foreground/10 text-foreground"\n                  : "text-muted-foreground hover:text-foreground"\n              }`}\n            >\n              <ShieldCheck size={15} />\n              Staff\n            </button>\n            <button\n              type="button"\n              onClick={() => {\n                setActiveTab("admin");\n                setError("");\n                setId("");\n                setPassword("");\n              }}\n              data-ocid="login.admin.tab"\n              className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-medium transition-all ${\n                activeTab === "admin"\n                  ? "bg-foreground/10 text-foreground"\n                  : "text-muted-foreground hover:text-foreground"\n              }`}\n            >\n              <ShieldAlert size={15} />\n              Admin\n            </button>\n          </div>\n\n          {/* Form */}\n          <form onSubmit={handleLogin} className="flex flex-col gap-4">\n            <div>\n              <label\n                htmlFor="user-id"\n                className="text-xs font-medium text-muted-foreground mb-1.5 block"\n              >\n                {activeTab === "student"\n                  ? "Student ID"\n                  : activeTab === "admin"\n                    ? "Admin ID"\n                    : "Staff ID"}\n              </label>\n              <input\n                id="user-id"\n                type="text"\n                value={id}\n                onChange={(e) => setId(e.target.value)}\n                placeholder={\n                  activeTab === "student"\n                    ? "e.g. STU001"\n                    : activeTab === "admin"\n                      ? "e.g. ADMIN001"\n                      : "e.g. STAFF001"\n                }\n                data-ocid="login.id.input"\n                required\n                autoComplete="username"\n                className="glass-sm w-full px-4 py-3 text-sm text-foreground placeholder:text-muted-foreground bg-transparent outline-none rounded-xl border-0 ring-0 focus:ring-1 focus:ring-foreground/20"\n              />\n            </div>\n            <div>\n              <label\n                htmlFor="password"\n                className="text-xs font-medium text-muted-foreground mb-1.5 block"\n              >\n                Password\n              </label>\n              <div className="relative">\n                <input\n                  id="password"\n                  type={showPass ? "text" : "password"}\n                  value={password}\n                  onChange={(e) => setPassword(e.target.value)}\n                  placeholder="Enter password"\n                  data-ocid="login.password.input"\n                  required\n                  autoComplete="current-password"\n                  className="glass-sm w-full px-4 py-3 pr-11 text-sm text-foreground placeholder:text-muted-foreground bg-transparent outline-none rounded-xl border-0"\n                />\n                <button\n                  type="button"\n                  onClick={() => setShowPass((v) => !v)}\n                  data-ocid="login.showpassword.toggle"\n                  className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"\n                  tabIndex={-1}\n                >\n                  {showPass ? <EyeOff size={16} /> : <Eye size={16} />}\n                </button>\n              </div>\n            </div>\n\n            {/* Error */}\n            {error && (\n              <p\n                className="text-xs text-destructive text-center"\n                data-ocid="login.error_state"\n              >\n                {error}\n              </p>\n            )}\n\n            {/* Submit */}\n            <button\n              type="submit"\n              disabled={loading || !id || !password}\n              data-ocid="login.submit_button"\n              className="glass-btn py-3 w-full flex items-center justify-center gap-2 font-semibold text-sm text-foreground disabled:opacity-50 disabled:cursor-not-allowed mt-1"\n            >\n              {loading ? (\n                <span\n                  className="flex items-center gap-2"\n                  data-ocid="login.loading_state"\n                >\n                  <span className="w-4 h-4 border-2 border-foreground/30 border-t-foreground rounded-full animate-spin" />\n                  Signing in\u2026\n                </span>\n              ) : (\n                <>\n                  <LogIn size={16} />\n                  Sign In\n                </>\n              )}\n            </button>\n          </form>\n\n          {/* Demo credentials */}\n          <div className="mt-5 glass-sm rounded-xl p-4">\n            <div className="flex items-center gap-1.5 text-muted-foreground text-xs mb-2.5">\n              <Info size={13} />\n              <span className="font-medium">Demo Credentials</span>\n            </div>\n            {activeTab === "student" ? (\n              <div className="flex flex-col gap-1 text-xs">\n                {Object.entries(DEMO_STUDENTS).map(([sid, s]) => (\n                  <button\n                    key={sid}\n                    type="button"\n                    onClick={() => {\n                      setId(sid);\n                      setPassword(s.password);\n                    }}\n                    className="flex items-center justify-between hover:text-foreground text-muted-foreground transition-colors group"\n                  >\n                    <span className="font-mono">{sid}</span>\n                    <span className="text-muted-foreground/60">{s.name}</span>\n                    <span className="glass-sm px-2 py-0.5 text-[10px] opacity-0 group-hover:opacity-100 transition-opacity">\n                      Use\n                    </span>\n                  </button>\n                ))}\n                <p className="text-muted-foreground/50 text-[10px] mt-1">\n                  Password: pass123 for all\n                </p>\n              </div>\n            ) : activeTab === "admin" ? (\n              <div className="flex flex-col gap-1 text-xs">\n                {Object.entries(DEMO_ADMIN).map(([sid, s]) => (\n                  <button\n                    key={sid}\n                    type="button"\n                    onClick={() => {\n                      setId(sid);\n                      setPassword(s.password);\n                    }}\n                    className="flex items-center justify-between hover:text-foreground text-muted-foreground transition-colors group"\n                  >\n                    <span className="font-mono">{sid}</span>\n                    <span className="text-muted-foreground/60">{s.name}</span>\n                    <span className="glass-sm px-2 py-0.5 text-[10px] opacity-0 group-hover:opacity-100 transition-opacity">\n                      Use\n                    </span>\n                  </button>\n                ))}\n                <p className="text-muted-foreground/50 text-[10px] mt-1">\n                  Password: admin123\n                </p>\n              </div>\n            ) : (\n              <div className="flex flex-col gap-1 text-xs">\n                {Object.entries(DEMO_STAFF).map(([sid, s]) => (\n                  <button\n                    key={sid}\n                    type="button"\n                    onClick={() => {\n                      setId(sid);\n                      setPassword(s.password);\n                    }}\n                    className="flex items-center justify-between hover:text-foreground text-muted-foreground transition-colors group"\n                  >\n                    <span className="font-mono">{sid}</span>\n                    <span className="text-muted-foreground/60">{s.name}</span>\n                    <span className="glass-sm px-2 py-0.5 text-[10px] opacity-0 group-hover:opacity-100 transition-opacity">\n                      Use\n                    </span>\n                  </button>\n                ))}\n                <p className="text-muted-foreground/50 text-[10px] mt-1">\n                  Password: pass123 for all\n                </p>\n              </div>\n            )}\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/pages/CoursesPage.tsx\n--------------------------------------------------------------------------------\nimport { Badge } from "@/components/ui/badge";\nimport { Skeleton } from "@/components/ui/skeleton";\nimport { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";\nimport { BookOpen, Clock, GraduationCap } from "lucide-react";\nimport { Degree } from "../backend";\nimport { useTheme } from "../contexts/ThemeContext";\nimport { useAllCourses } from "../hooks/useQueries";\n\nconst degreeLabels: Record<string, string> = {\n  bTech: "B.Tech",\n  mTech: "M.Tech",\n  mba: "MBA",\n};\n\nconst degreeColors: Record<string, string> = {\n  bTech: "bg-blue-500/15 text-blue-400",\n  mTech: "bg-purple-500/15 text-purple-400",\n  mba: "bg-amber-500/15 text-amber-400",\n};\n\nexport function CoursesPage() {\n  const { data: courses, isLoading } = useAllCourses();\n  const { theme } = useTheme();\n  const isDark = theme === "dark";\n\n  const grouped = {\n    bTech: courses?.filter((c) => c.degree === Degree.bTech) ?? [],\n    mTech: courses?.filter((c) => c.degree === Degree.mTech) ?? [],\n    mba: courses?.filter((c) => c.degree === Degree.mba) ?? [],\n  };\n\n  return (\n    <div className="relative min-h-screen">\n      {/* BG */}\n      <div className="fixed inset-0 -z-10">\n        <img\n          src="https://images.unsplash.com/photo-1541339907198-e08756dedf3f?w=1920&q=80"\n          alt="Campus"\n          className="w-full h-full object-cover"\n          style={{\n            filter: isDark\n              ? "grayscale(50%) brightness(0.25)"\n              : "grayscale(20%) brightness(0.80)",\n          }}\n        />\n        <div\n          className={\n            isDark\n              ? "bg-overlay absolute inset-0"\n              : "bg-overlay-light absolute inset-0"\n          }\n        />\n      </div>\n\n      <div className="max-w-5xl mx-auto px-4 sm:px-6 py-10">\n        {/* Header */}\n        <div className="mb-8">\n          <div className="flex items-center gap-3 mb-2">\n            <div className="glass-sm p-2 rounded-xl">\n              <BookOpen size={20} className="text-foreground/70" />\n            </div>\n            <h1 className="font-display font-bold text-2xl sm:text-3xl text-foreground">\n              Courses Offered\n            </h1>\n          </div>\n          <p className="text-muted-foreground text-sm">\n            SNGCE offers a range of undergraduate and postgraduate programs\n            approved by AICTE and affiliated to APJ Abdul Kalam Technological\n            University (KTU). Established in 2002, managed by Sree Narayana\n            Gurukulam Charitable Trust.\n          </p>\n        </div>\n\n        {isLoading ? (\n          <div\n            className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4"\n            data-ocid="courses.loading_state"\n          >\n            {Array.from({ length: 6 }).map((_, i) => (\n              // biome-ignore lint/suspicious/noArrayIndexKey: skeleton loader\n              <div key={i} className="glass p-5 flex flex-col gap-3">\n                <Skeleton className="h-5 w-24 bg-foreground/10" />\n                <Skeleton className="h-4 w-32 bg-foreground/10" />\n                <Skeleton className="h-4 w-20 bg-foreground/10" />\n              </div>\n            ))}\n          </div>\n        ) : (\n          <Tabs defaultValue="bTech" data-ocid="courses.tab">\n            <TabsList className="glass mb-6 p-1 h-auto flex gap-1 bg-transparent">\n              {Object.entries(degreeLabels).map(([key, label]) => (\n                <TabsTrigger\n                  key={key}\n                  value={key}\n                  data-ocid={`courses.${key}.tab`}\n                  className="glass-btn px-4 py-2 text-sm data-[state=active]:bg-foreground/10 data-[state=active]:text-foreground rounded-xl"\n                >\n                  {label} ({grouped[key as keyof typeof grouped].length})\n                </TabsTrigger>\n              ))}\n            </TabsList>\n\n            {Object.entries(grouped).map(([key, list]) => (\n              <TabsContent key={key} value={key}>\n                {list.length === 0 ? (\n                  <div\n                    className="glass rounded-2xl p-12 text-center"\n                    data-ocid="courses.empty_state"\n                  >\n                    <GraduationCap\n                      size={40}\n                      className="text-muted-foreground mx-auto mb-3"\n                    />\n                    <p className="text-muted-foreground">\n                      No courses found for this category.\n                    </p>\n                  </div>\n                ) : (\n                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">\n                    {list.map((course, i) => (\n                      <div\n                        key={`${course.branch}-${i}`}\n                        className="glass p-5 flex flex-col gap-4 hover:scale-[1.01] transition-transform"\n                        data-ocid={`courses.item.${i + 1}`}\n                      >\n                        <div className="flex items-start justify-between gap-2">\n                          <h3 className="font-display font-semibold text-foreground text-base leading-snug">\n                            {course.branch}\n                          </h3>\n                          <Badge\n                            className={`text-xs shrink-0 border-0 ${degreeColors[key] ?? ""}`}\n                          >\n                            {degreeLabels[key] ?? key}\n                          </Badge>\n                        </div>\n                        <div className="flex items-center gap-1.5 text-muted-foreground text-xs">\n                          <Clock size={13} />\n                          {course.durationYears} Year\n                          {course.durationYears > 1 ? "s" : ""} Program\n                        </div>\n                        <div className="flex items-center gap-1.5 text-muted-foreground text-xs">\n                          <GraduationCap size={13} />\n                          Affiliated to APJ KTU\n                        </div>\n                      </div>\n                    ))}\n                  </div>\n                )}\n              </TabsContent>\n            ))}\n          </Tabs>\n        )}\n      </div>\n    </div>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/pages/FeesPage.tsx\n--------------------------------------------------------------------------------\nimport {\n  Accordion,\n  AccordionContent,\n  AccordionItem,\n  AccordionTrigger,\n} from "@/components/ui/accordion";\nimport { Skeleton } from "@/components/ui/skeleton";\nimport { ChevronDown, DollarSign } from "lucide-react";\nimport { Degree } from "../backend";\nimport { useTheme } from "../contexts/ThemeContext";\nimport { useAllFeeStructures } from "../hooks/useQueries";\n\nconst degreeLabels: Record<string, string> = {\n  bTech: "B.Tech",\n  mTech: "M.Tech",\n  mba: "MBA",\n};\n\nfunction formatAmount(amount: number) {\n  return new Intl.NumberFormat("en-IN", {\n    style: "currency",\n    currency: "INR",\n    maximumFractionDigits: 0,\n  }).format(amount);\n}\n\nexport function FeesPage() {\n  const { data: feeStructures, isLoading } = useAllFeeStructures();\n  const { theme } = useTheme();\n  const isDark = theme === "dark";\n\n  return (\n    <div className="relative min-h-screen">\n      {/* BG */}\n      <div className="fixed inset-0 -z-10">\n        <img\n          src="https://images.unsplash.com/photo-1607237138185-eedd9c632b0b?w=1920&q=80"\n          alt="Campus building"\n          className="w-full h-full object-cover"\n          style={{\n            filter: isDark\n              ? "grayscale(50%) brightness(0.25)"\n              : "grayscale(20%) brightness(0.80)",\n          }}\n        />\n        <div\n          className={\n            isDark\n              ? "bg-overlay absolute inset-0"\n              : "bg-overlay-light absolute inset-0"\n          }\n        />\n      </div>\n\n      <div className="max-w-4xl mx-auto px-4 sm:px-6 py-10">\n        {/* Header */}\n        <div className="mb-8">\n          <div className="flex items-center gap-3 mb-2">\n            <div className="glass-sm p-2 rounded-xl">\n              <DollarSign size={20} className="text-foreground/70" />\n            </div>\n            <h1 className="font-display font-bold text-2xl sm:text-3xl text-foreground">\n              Fee Structure\n            </h1>\n          </div>\n          <p className="text-muted-foreground text-sm">\n            Detailed semester/year-wise fee breakdown for all programs. Fees are\n            subject to university revision.\n          </p>\n        </div>\n\n        {isLoading ? (\n          <div className="flex flex-col gap-3" data-ocid="fees.loading_state">\n            {Array.from({ length: 4 }).map((_, i) => (\n              // biome-ignore lint/suspicious/noArrayIndexKey: skeleton loader\n              <div key={i} className="glass p-5 flex flex-col gap-3">\n                <Skeleton className="h-5 w-48 bg-foreground/10" />\n                <Skeleton className="h-4 w-32 bg-foreground/10" />\n              </div>\n            ))}\n          </div>\n        ) : !feeStructures?.length ? (\n          <div\n            className="glass rounded-2xl p-12 text-center"\n            data-ocid="fees.empty_state"\n          >\n            <DollarSign\n              size={40}\n              className="text-muted-foreground mx-auto mb-3"\n            />\n            <p className="text-muted-foreground">\n              Fee structure not available.\n            </p>\n          </div>\n        ) : (\n          <Accordion type="multiple" className="flex flex-col gap-3">\n            {feeStructures.map((fs, i) => {\n              const total = fs.yearSemesterBreakdown.reduce(\n                (acc, row) => acc + row.amount,\n                0,\n              );\n              const key = `${fs.course.branch}-${fs.course.degree}`;\n              return (\n                <AccordionItem\n                  key={key}\n                  value={`fee-${i}`}\n                  className="glass border-0 rounded-2xl overflow-hidden"\n                  data-ocid={`fees.item.${i + 1}`}\n                >\n                  <AccordionTrigger className="px-5 py-4 hover:no-underline hover:bg-foreground/5 transition-colors [&>svg]:hidden">\n                    <div className="flex items-center justify-between w-full gap-4">\n                      <div className="text-left">\n                        <p className="font-display font-semibold text-foreground text-base">\n                          {fs.course.branch}\n                        </p>\n                        <p className="text-muted-foreground text-xs mt-0.5">\n                          {degreeLabels[fs.course.degree] ?? fs.course.degree} \u00b7{" "}\n                          {fs.course.durationYears} Years\n                        </p>\n                      </div>\n                      <div className="flex items-center gap-3 shrink-0">\n                        <span className="text-foreground font-semibold text-sm">\n                          {formatAmount(total)} total\n                        </span>\n                        <ChevronDown\n                          size={16}\n                          className="text-muted-foreground"\n                        />\n                      </div>\n                    </div>\n                  </AccordionTrigger>\n                  <AccordionContent className="px-5 pb-5">\n                    <div className="glass-sm rounded-xl overflow-hidden">\n                      <table className="w-full text-sm">\n                        <thead>\n                          <tr className="border-b border-white/10">\n                            <th className="text-left text-xs text-muted-foreground font-medium px-4 py-2.5">\n                              Year / Semester\n                            </th>\n                            <th className="text-right text-xs text-muted-foreground font-medium px-4 py-2.5">\n                              Amount\n                            </th>\n                          </tr>\n                        </thead>\n                        <tbody>\n                          {fs.yearSemesterBreakdown.map((row) => (\n                            <tr\n                              key={row.yearOrSemester}\n                              className="border-b border-white/5 last:border-0 hover:bg-foreground/5 transition-colors"\n                            >\n                              <td className="px-4 py-3 text-foreground">\n                                {row.yearOrSemester}\n                              </td>\n                              <td className="px-4 py-3 text-foreground text-right font-medium">\n                                {formatAmount(row.amount)}\n                              </td>\n                            </tr>\n                          ))}\n                          <tr className="bg-foreground/5">\n                            <td className="px-4 py-3 font-semibold text-foreground">\n                              Total\n                            </td>\n                            <td className="px-4 py-3 font-bold text-foreground text-right">\n                              {formatAmount(total)}\n                            </td>\n                          </tr>\n                        </tbody>\n                      </table>\n                    </div>\n                  </AccordionContent>\n                </AccordionItem>\n              );\n            })}\n          </Accordion>\n        )}\n      </div>\n    </div>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/pages/FacultyPage.tsx\n--------------------------------------------------------------------------------\nimport { Skeleton } from "@/components/ui/skeleton";\nimport { Award, Search, Users } from "lucide-react";\nimport { useMemo, useState } from "react";\nimport type { FacultyMember } from "../backend.d";\nimport { useTheme } from "../contexts/ThemeContext";\nimport { useFacultyDirectory } from "../hooks/useQueries";\n\nexport function FacultyPage() {\n  const { data: faculty, isLoading } = useFacultyDirectory();\n  const { theme } = useTheme();\n  const isDark = theme === "dark";\n  const [selectedDept, setSelectedDept] = useState<string>("All");\n  const [search, setSearch] = useState("");\n\n  const departments = useMemo(() => {\n    const depts = Array.from(\n      new Set(faculty?.map((f: FacultyMember) => f.department) ?? []),\n    );\n    return ["All", ...depts.sort()];\n  }, [faculty]);\n\n  const filtered = useMemo(() => {\n    let list = faculty ?? [];\n    if (selectedDept !== "All")\n      list = list.filter((f: FacultyMember) => f.department === selectedDept);\n    if (search.trim()) {\n      const q = search.toLowerCase();\n      list = list.filter(\n        (f: FacultyMember) =>\n          f.name.toLowerCase().includes(q) ||\n          f.qualification.toLowerCase().includes(q) ||\n          f.subjectsTaught.some((s: string) => s.toLowerCase().includes(q)),\n      );\n    }\n    return list;\n  }, [faculty, selectedDept, search]);\n\n  const getInitials = (name: string) =>\n    name\n      .split(" ")\n      .map((w) => w[0])\n      .slice(0, 2)\n      .join("")\n      .toUpperCase();\n\n  return (\n    <div className="relative min-h-screen">\n      {/* BG */}\n      <div className="fixed inset-0 -z-10">\n        <img\n          src="https://images.unsplash.com/photo-1523050854058-8df90110c9f1?w=1920&q=80"\n          alt="University hallway"\n          className="w-full h-full object-cover"\n          style={{\n            filter: isDark\n              ? "grayscale(50%) brightness(0.25)"\n              : "grayscale(20%) brightness(0.80)",\n          }}\n        />\n        <div\n          className={\n            isDark\n              ? "bg-overlay absolute inset-0"\n              : "bg-overlay-light absolute inset-0"\n          }\n        />\n      </div>\n\n      <div className="max-w-5xl mx-auto px-4 sm:px-6 py-10">\n        {/* Header */}\n        <div className="mb-6">\n          <div className="flex items-center gap-3 mb-2">\n            <div className="glass-sm p-2 rounded-xl">\n              <Users size={20} className="text-foreground/70" />\n            </div>\n            <h1 className="font-display font-bold text-2xl sm:text-3xl text-foreground">\n              Faculty Directory\n            </h1>\n          </div>\n          <p className="text-muted-foreground text-sm">\n            Meet our dedicated faculty members who bring expertise and passion\n            to every classroom.\n          </p>\n        </div>\n\n        {/* Filters */}\n        <div className="flex flex-col sm:flex-row gap-3 mb-6">\n          {/* Search */}\n          <div className="glass-sm flex items-center gap-2 px-3 py-2 rounded-xl flex-1">\n            <Search size={15} className="text-muted-foreground shrink-0" />\n            <input\n              type="text"\n              value={search}\n              onChange={(e) => setSearch(e.target.value)}\n              placeholder="Search by name, subject\u2026"\n              data-ocid="faculty.search_input"\n              className="bg-transparent text-sm text-foreground placeholder:text-muted-foreground outline-none w-full"\n            />\n          </div>\n          {/* Department */}\n          <div className="flex gap-2 flex-wrap">\n            {departments.slice(0, 5).map((dept) => (\n              <button\n                type="button"\n                key={dept}\n                onClick={() => setSelectedDept(dept)}\n                data-ocid={`faculty.dept.${dept.toLowerCase().replace(/\\s+/g, "_")}.button`}\n                className={`glass-btn px-3 py-1.5 text-xs font-medium transition-all ${\n                  selectedDept === dept\n                    ? "bg-foreground/15 text-foreground"\n                    : "text-muted-foreground"\n                }`}\n              >\n                {dept}\n              </button>\n            ))}\n            {departments.length > 5 && (\n              <select\n                value={selectedDept}\n                onChange={(e) => setSelectedDept(e.target.value)}\n                data-ocid="faculty.dept.select"\n                className="glass-btn px-3 py-1.5 text-xs font-medium text-foreground bg-transparent outline-none cursor-pointer"\n              >\n                {departments.map((d) => (\n                  <option key={d} value={d} className="bg-background">\n                    {d}\n                  </option>\n                ))}\n              </select>\n            )}\n          </div>\n        </div>\n\n        {isLoading ? (\n          <div\n            className="grid grid-cols-1 sm:grid-cols-2 gap-4"\n            data-ocid="faculty.loading_state"\n          >\n            {Array.from({ length: 6 }).map((_, i) => (\n              // biome-ignore lint/suspicious/noArrayIndexKey: skeleton loader\n              <div key={i} className="glass p-5 flex gap-4">\n                <Skeleton className="w-12 h-12 rounded-full bg-foreground/10 shrink-0" />\n                <div className="flex flex-col gap-2 flex-1">\n                  <Skeleton className="h-5 w-32 bg-foreground/10" />\n                  <Skeleton className="h-4 w-24 bg-foreground/10" />\n                  <Skeleton className="h-4 w-40 bg-foreground/10" />\n                </div>\n              </div>\n            ))}\n          </div>\n        ) : filtered.length === 0 ? (\n          <div\n            className="glass rounded-2xl p-12 text-center"\n            data-ocid="faculty.empty_state"\n          >\n            <Users size={40} className="text-muted-foreground mx-auto mb-3" />\n            <p className="text-muted-foreground">No faculty members found.</p>\n          </div>\n        ) : (\n          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">\n            {filtered.map((member: FacultyMember, i: number) => (\n              <div\n                key={`${member.name}-${i}`}\n                className="glass p-5 flex gap-4 hover:scale-[1.01] transition-transform"\n                data-ocid={`faculty.item.${i + 1}`}\n              >\n                {/* Avatar */}\n                <div className="glass-sm w-12 h-12 rounded-full flex items-center justify-center shrink-0 text-foreground font-display font-bold text-sm">\n                  {getInitials(member.name)}\n                </div>\n                {/* Info */}\n                <div className="flex-1 min-w-0">\n                  <p className="font-display font-semibold text-foreground text-sm">\n                    {member.name}\n                  </p>\n                  <div className="flex items-center gap-1.5 text-muted-foreground text-xs mt-0.5">\n                    <Award size={11} />\n                    {member.qualification}\n                  </div>\n                  <div className="mt-2 flex flex-wrap gap-1.5">\n                    <span className="glass-sm px-2 py-0.5 text-xs text-foreground/70 rounded-full">\n                      {member.department}\n                    </span>\n                  </div>\n                  <div className="mt-2">\n                    <p className="text-muted-foreground text-xs mb-1 font-medium">\n                      Subjects:\n                    </p>\n                    <div className="flex flex-wrap gap-1">\n                      {member.subjectsTaught.map((subj: string) => (\n                        <span\n                          key={subj}\n                          className="glass-sm px-2 py-0.5 text-xs text-foreground/60 rounded-lg"\n                        >\n                          {subj}\n                        </span>\n                      ))}\n                    </div>\n                  </div>\n                </div>\n              </div>\n            ))}\n          </div>\n        )}\n      </div>\n    </div>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/pages/StudentDashboard.tsx\n--------------------------------------------------------------------------------\nimport { Progress } from "@/components/ui/progress";\nimport { Skeleton } from "@/components/ui/skeleton";\nimport { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";\nimport { useNavigate } from "@tanstack/react-router";\nimport {\n  AlertTriangle,\n  BarChart2,\n  Calendar,\n  DollarSign,\n  GraduationCap,\n} from "lucide-react";\nimport { useEffect } from "react";\nimport type { Attendance, Exam, FeesDue, Marks } from "../backend.d";\nimport { useAuth } from "../contexts/AuthContext";\nimport { useTheme } from "../contexts/ThemeContext";\nimport {\n  useAttendanceByStudent,\n  useExamTimetable,\n  useFeesDue,\n  useMarksByStudent,\n} from "../hooks/useQueries";\n\nfunction formatDate(time: bigint): string {\n  const ms = Number(time) / 1_000_000;\n  return new Date(ms).toLocaleDateString("en-IN", {\n    day: "2-digit",\n    month: "short",\n    year: "numeric",\n  });\n}\n\nfunction formatAmount(amount: number) {\n  return new Intl.NumberFormat("en-IN", {\n    style: "currency",\n    currency: "INR",\n    maximumFractionDigits: 0,\n  }).format(amount);\n}\n\nexport function StudentDashboard() {\n  const { isLoggedIn, role, studentId, userName } = useAuth();\n  const navigate = useNavigate();\n  const { theme } = useTheme();\n  const isDark = theme === "dark";\n\n  const department = "Computer Science"; // Default department for timetable\n\n  useEffect(() => {\n    if (!isLoggedIn || role !== "student") {\n      navigate({ to: "/login" });\n    }\n  }, [isLoggedIn, role, navigate]);\n\n  const { data: attendance, isLoading: loadingAttendance } =\n    useAttendanceByStudent(studentId);\n  const { data: marks, isLoading: loadingMarks } = useMarksByStudent(studentId);\n  const { data: exams, isLoading: loadingExams } = useExamTimetable(department);\n  const { data: feesDue, isLoading: loadingFees } = useFeesDue(studentId);\n\n  if (!isLoggedIn || role !== "student") return null;\n\n  const overallAttendance =\n    attendance && attendance.length > 0\n      ? Math.round(\n          attendance.reduce(\n            (acc: number, a: Attendance) => acc + a.percentage,\n            0,\n          ) / attendance.length,\n        )\n      : 0;\n\n  const totalFeesDue =\n    feesDue?.reduce((acc: number, f: FeesDue) => acc + f.amount, 0) ?? 0;\n\n  return (\n    <div className="relative min-h-screen">\n      {/* BG */}\n      <div className="fixed inset-0 -z-10">\n        <img\n          src="https://images.unsplash.com/photo-1562774053-701939374585?w=1920&q=80"\n          alt="Campus"\n          className="w-full h-full object-cover"\n          style={{\n            filter: isDark\n              ? "grayscale(60%) brightness(0.20)"\n              : "grayscale(20%) brightness(0.75)",\n          }}\n        />\n        <div\n          className={\n            isDark\n              ? "bg-overlay absolute inset-0"\n              : "bg-overlay-light absolute inset-0"\n          }\n        />\n      </div>\n\n      <div className="max-w-4xl mx-auto px-4 sm:px-6 py-10">\n        {/* Profile header */}\n        <div className="glass rounded-2xl p-6 mb-6">\n          <div className="flex items-center gap-4">\n            <div className="glass-sm w-14 h-14 rounded-2xl flex items-center justify-center shrink-0 font-display font-bold text-xl text-foreground">\n              {userName?.charAt(0) ?? "S"}\n            </div>\n            <div>\n              <h1 className="font-display font-bold text-xl text-foreground">\n                {userName}\n              </h1>\n              <p className="text-muted-foreground text-sm">\n                {studentId} \u00b7 {department}\n              </p>\n            </div>\n            <div className="ml-auto grid grid-cols-2 gap-3 text-center hidden sm:grid">\n              <div className="glass-sm px-4 py-2 rounded-xl">\n                <p className="font-bold text-lg text-foreground">\n                  {overallAttendance}%\n                </p>\n                <p className="text-muted-foreground text-xs">Attendance</p>\n              </div>\n              <div className="glass-sm px-4 py-2 rounded-xl">\n                <p className="font-bold text-lg text-foreground">\n                  {formatAmount(totalFeesDue)}\n                </p>\n                <p className="text-muted-foreground text-xs">Fees Due</p>\n              </div>\n            </div>\n          </div>\n        </div>\n\n        {/* Tabs */}\n        <Tabs defaultValue="attendance">\n          <TabsList className="glass mb-6 p-1 h-auto flex gap-1 bg-transparent w-full">\n            {[\n              { value: "attendance", label: "Attendance", icon: GraduationCap },\n              { value: "marks", label: "Marks", icon: BarChart2 },\n              { value: "exams", label: "Timetable", icon: Calendar },\n              { value: "fees", label: "Fees Due", icon: DollarSign },\n            ].map(({ value, label, icon: Icon }) => (\n              <TabsTrigger\n                key={value}\n                value={value}\n                data-ocid={`student.${value}.tab`}\n                className="flex-1 flex items-center justify-center gap-1.5 py-2 text-xs sm:text-sm data-[state=active]:bg-foreground/10 data-[state=active]:text-foreground rounded-xl font-medium"\n              >\n                <Icon size={14} />\n                <span className="hidden sm:inline">{label}</span>\n              </TabsTrigger>\n            ))}\n          </TabsList>\n\n          {/* Attendance */}\n          <TabsContent value="attendance">\n            {loadingAttendance ? (\n              <div\n                className="flex flex-col gap-3"\n                data-ocid="student.attendance.loading_state"\n              >\n                {(["s1", "s2", "s3", "s4", "s5"] as const).map((k) => (\n                  <div key={k} className="glass p-4 flex gap-3 items-center">\n                    <Skeleton className="h-4 w-32 bg-foreground/10" />\n                    <Skeleton className="h-3 flex-1 bg-foreground/10" />\n                    <Skeleton className="h-4 w-10 bg-foreground/10" />\n                  </div>\n                ))}\n              </div>\n            ) : !attendance?.length ? (\n              <div\n                className="glass rounded-2xl p-12 text-center"\n                data-ocid="student.attendance.empty_state"\n              >\n                <GraduationCap\n                  size={40}\n                  className="text-muted-foreground mx-auto mb-3"\n                />\n                <p className="text-muted-foreground">\n                  No attendance records found.\n                </p>\n              </div>\n            ) : (\n              <div className="flex flex-col gap-3">\n                {attendance.map((a: Attendance, i: number) => {\n                  const pct = Math.round(a.percentage);\n                  const isLow = pct < 75;\n                  return (\n                    <div\n                      key={`${a.subjectId}-${i}`}\n                      className={`glass p-4 flex flex-col sm:flex-row sm:items-center gap-3 ${isLow ? "border border-amber-500/30" : ""}`}\n                      data-ocid={`student.attendance.item.${i + 1}`}\n                    >\n                      <div className="sm:w-48 flex-shrink-0 flex items-center gap-2">\n                        {isLow && (\n                          <AlertTriangle\n                            size={14}\n                            className="text-amber-500 shrink-0"\n                          />\n                        )}\n                        <span className="text-sm font-medium text-foreground">\n                          {a.subjectId}\n                        </span>\n                      </div>\n                      <div className="flex-1 flex items-center gap-3">\n                        <Progress\n                          value={pct}\n                          className={`h-2 flex-1 ${isLow ? "bg-amber-500/10" : "bg-foreground/10"}`}\n                        />\n                        <span\n                          className={`text-sm font-bold w-10 text-right ${isLow ? "text-amber-400" : "text-foreground"}`}\n                        >\n                          {pct}%\n                        </span>\n                      </div>\n                    </div>\n                  );\n                })}\n              </div>\n            )}\n          </TabsContent>\n\n          {/* Marks */}\n          <TabsContent value="marks">\n            {loadingMarks ? (\n              <div\n                className="glass rounded-2xl p-6"\n                data-ocid="student.marks.loading_state"\n              >\n                <Skeleton className="h-6 w-full mb-3 bg-foreground/10" />\n                {(["a", "b", "c", "d"] as const).map((k) => (\n                  <Skeleton\n                    key={k}\n                    className="h-10 w-full mb-2 bg-foreground/10"\n                  />\n                ))}\n              </div>\n            ) : !marks?.length ? (\n              <div\n                className="glass rounded-2xl p-12 text-center"\n                data-ocid="student.marks.empty_state"\n              >\n                <BarChart2\n                  size={40}\n                  className="text-muted-foreground mx-auto mb-3"\n                />\n                <p className="text-muted-foreground">No marks records found.</p>\n              </div>\n            ) : (\n              <div className="glass rounded-2xl overflow-hidden">\n                <table className="w-full text-sm">\n                  <thead>\n                    <tr className="border-b border-white/10">\n                      <th className="text-left text-xs text-muted-foreground font-medium px-5 py-3">\n                        Subject\n                      </th>\n                      <th className="text-left text-xs text-muted-foreground font-medium px-5 py-3">\n                        Exam Type\n                      </th>\n                      <th className="text-right text-xs text-muted-foreground font-medium px-5 py-3">\n                        Marks\n                      </th>\n                    </tr>\n                  </thead>\n                  <tbody>\n                    {marks.map((m: Marks, i: number) => (\n                      <tr\n                        key={`${m.subjectId}-${m.examType}-${i}`}\n                        className="border-b border-white/5 last:border-0 hover:bg-foreground/5 transition-colors"\n                        data-ocid={`student.marks.item.${i + 1}`}\n                      >\n                        <td className="px-5 py-3 text-foreground">\n                          {m.subjectId}\n                        </td>\n                        <td className="px-5 py-3 text-muted-foreground capitalize">\n                          {m.examType}\n                        </td>\n                        <td className="px-5 py-3 text-right font-semibold text-foreground">\n                          {Number(m.marks)}\n                        </td>\n                      </tr>\n                    ))}\n                  </tbody>\n                </table>\n              </div>\n            )}\n          </TabsContent>\n\n          {/* Exam Timetable */}\n          <TabsContent value="exams">\n            {loadingExams ? (\n              <div\n                className="flex flex-col gap-3"\n                data-ocid="student.exams.loading_state"\n              >\n                {(["e1", "e2", "e3", "e4"] as const).map((k) => (\n                  <div key={k} className="glass p-4">\n                    <Skeleton className="h-5 w-40 mb-2 bg-foreground/10" />\n                    <Skeleton className="h-4 w-24 bg-foreground/10" />\n                  </div>\n                ))}\n              </div>\n            ) : !exams?.length ? (\n              <div\n                className="glass rounded-2xl p-12 text-center"\n                data-ocid="student.exams.empty_state"\n              >\n                <Calendar\n                  size={40}\n                  className="text-muted-foreground mx-auto mb-3"\n                />\n                <p className="text-muted-foreground">\n                  No upcoming exams scheduled.\n                </p>\n              </div>\n            ) : (\n              <div className="flex flex-col gap-3">\n                {exams.map((exam: Exam, i: number) => (\n                  <div\n                    key={exam.examId ?? i}\n                    className="glass p-4 flex items-center gap-4"\n                    data-ocid={`student.exams.item.${i + 1}`}\n                  >\n                    <div className="glass-sm rounded-xl px-3 py-2 text-center min-w-[56px]">\n                      <p className="font-bold text-sm text-foreground leading-tight">\n                        {new Date(Number(exam.date) / 1_000_000).getDate()}\n                      </p>\n                      <p className="text-muted-foreground text-[10px]">\n                        {new Date(Number(exam.date) / 1_000_000).toLocaleString(\n                          "en-IN",\n                          { month: "short" },\n                        )}\n                      </p>\n                    </div>\n                    <div>\n                      <p className="font-medium text-foreground text-sm">\n                        {exam.subjectId}\n                      </p>\n                      <p className="text-muted-foreground text-xs capitalize mt-0.5">\n                        {exam.examType} \u00b7 {formatDate(exam.date)}\n                      </p>\n                    </div>\n                  </div>\n                ))}\n              </div>\n            )}\n          </TabsContent>\n\n          {/* Fees Due */}\n          <TabsContent value="fees">\n            {loadingFees ? (\n              <div\n                className="flex flex-col gap-3"\n                data-ocid="student.fees.loading_state"\n              >\n                {(["f1", "f2", "f3"] as const).map((k) => (\n                  <div key={k} className="glass p-4">\n                    <Skeleton className="h-5 w-40 mb-2 bg-foreground/10" />\n                    <Skeleton className="h-4 w-24 bg-foreground/10" />\n                  </div>\n                ))}\n              </div>\n            ) : !feesDue?.length ? (\n              <div\n                className="glass rounded-2xl p-12 text-center"\n                data-ocid="student.fees.empty_state"\n              >\n                <DollarSign\n                  size={40}\n                  className="text-muted-foreground mx-auto mb-3"\n                />\n                <p className="text-muted-foreground">\n                  No outstanding fees. You\'re all clear!\n                </p>\n              </div>\n            ) : (\n              <div className="flex flex-col gap-3">\n                {/* Summary */}\n                <div className="glass rounded-2xl p-4 flex items-center justify-between">\n                  <div>\n                    <p className="text-muted-foreground text-xs">\n                      Total Outstanding\n                    </p>\n                    <p className="font-display font-bold text-2xl text-foreground mt-0.5">\n                      {formatAmount(totalFeesDue)}\n                    </p>\n                  </div>\n                  <AlertTriangle size={20} className="text-amber-400" />\n                </div>\n\n                {feesDue.map((fee: FeesDue, i: number) => (\n                  <div\n                    key={`${fee.yearSemester}-${i}`}\n                    className="glass p-4 flex items-center justify-between"\n                    data-ocid={`student.fees.item.${i + 1}`}\n                  >\n                    <div>\n                      <p className="font-medium text-foreground text-sm">\n                        {fee.yearSemester}\n                      </p>\n                      <p className="text-muted-foreground text-xs mt-0.5">\n                        Due: {formatDate(fee.dueDate)}\n                      </p>\n                    </div>\n                    <p className="font-bold text-foreground">\n                      {formatAmount(fee.amount)}\n                    </p>\n                  </div>\n                ))}\n              </div>\n            )}\n          </TabsContent>\n        </Tabs>\n      </div>\n    </div>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/pages/StaffDashboard.tsx\n--------------------------------------------------------------------------------\nimport { Skeleton } from "@/components/ui/skeleton";\nimport { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";\nimport { useNavigate } from "@tanstack/react-router";\nimport {\n  BarChart2,\n  Calendar,\n  DollarSign,\n  GraduationCap,\n  Plus,\n  Save,\n  Search,\n  ShieldCheck,\n  Trash2,\n  UserCircle,\n} from "lucide-react";\nimport { useEffect, useState } from "react";\nimport { toast } from "sonner";\nimport { Degree } from "../backend";\nimport type {\n  AcademicRecord,\n  Attendance,\n  Exam,\n  FeesDue,\n  Marks,\n} from "../backend.d";\nimport { useAuth } from "../contexts/AuthContext";\nimport { useTheme } from "../contexts/ThemeContext";\nimport { useSaveAcademicRecord, useStudentRecord } from "../hooks/useQueries";\n\nfunction makeDefaultRecord(studentId: string): AcademicRecord {\n  return {\n    student: {\n      studentId,\n      firstName: "",\n      lastName: "",\n      department: "",\n      degree: Degree.bTech,\n    },\n    attendance: [],\n    marks: [],\n    exams: [],\n    feesDue: [],\n    subjects: [],\n  };\n}\n\nexport function StaffDashboard() {\n  const { isLoggedIn, role, userName } = useAuth();\n  const navigate = useNavigate();\n  const { theme } = useTheme();\n  const isDark = theme === "dark";\n\n  const [searchId, setSearchId] = useState("");\n  const [loadedId, setLoadedId] = useState<string | null>(null);\n  const [localRecord, setLocalRecord] = useState<AcademicRecord | null>(null);\n\n  useEffect(() => {\n    if (!isLoggedIn || role !== "staff") {\n      navigate({ to: "/login" });\n    }\n  }, [isLoggedIn, role, navigate]);\n\n  const { data: fetchedRecord, isLoading: loadingRecord } =\n    useStudentRecord(loadedId);\n  const { mutateAsync: saveRecord, isPending: saving } =\n    useSaveAcademicRecord();\n\n  useEffect(() => {\n    if (fetchedRecord) {\n      setLocalRecord(JSON.parse(JSON.stringify(fetchedRecord)));\n    } else if (loadedId && !loadingRecord) {\n      setLocalRecord(makeDefaultRecord(loadedId));\n    }\n  }, [fetchedRecord, loadedId, loadingRecord]);\n\n  if (!isLoggedIn || role !== "staff") return null;\n\n  const handleLoad = () => {\n    const id = searchId.trim().toUpperCase();\n    if (!id) return;\n    setLoadedId(id);\n    setLocalRecord(null);\n  };\n\n  const handleSave = async () => {\n    if (!localRecord || !loadedId) return;\n    try {\n      await saveRecord({ studentId: loadedId, record: localRecord });\n      toast.success("Student record saved successfully!");\n    } catch {\n      toast.error("Failed to save. Please try again.");\n    }\n  };\n\n  // Attendance helpers\n  const addAttendance = () => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      return {\n        ...prev,\n        attendance: [...prev.attendance, { subjectId: "", percentage: 0 }],\n      };\n    });\n  };\n  const updateAttendance = (\n    i: number,\n    field: keyof Attendance,\n    value: string | number,\n  ) => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      const att = [...prev.attendance];\n      att[i] = {\n        ...att[i],\n        [field]: field === "percentage" ? Number(value) : value,\n      };\n      return { ...prev, attendance: att };\n    });\n  };\n  const removeAttendance = (i: number) => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      return {\n        ...prev,\n        attendance: prev.attendance.filter((_, idx) => idx !== i),\n      };\n    });\n  };\n\n  // Marks helpers\n  const addMark = () => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      return {\n        ...prev,\n        marks: [\n          ...prev.marks,\n          { subjectId: "", examType: "", marks: BigInt(0) },\n        ],\n      };\n    });\n  };\n  const updateMark = (\n    i: number,\n    field: keyof Marks,\n    value: string | bigint,\n  ) => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      const m = [...prev.marks];\n      m[i] = {\n        ...m[i],\n        [field]: field === "marks" ? BigInt(String(value)) : value,\n      };\n      return { ...prev, marks: m };\n    });\n  };\n  const removeMark = (i: number) => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      return { ...prev, marks: prev.marks.filter((_, idx) => idx !== i) };\n    });\n  };\n\n  // Fees helpers\n  const addFee = () => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      return {\n        ...prev,\n        feesDue: [\n          ...prev.feesDue,\n          {\n            yearSemester: "",\n            amount: 0,\n            dueDate: BigInt(Date.now() * 1_000_000),\n          },\n        ],\n      };\n    });\n  };\n  const updateFee = (\n    i: number,\n    field: "yearSemester" | "amount" | "dueDate",\n    value: string | number,\n  ) => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      const f = [...prev.feesDue];\n      if (field === "amount") {\n        f[i] = { ...f[i], amount: Number(value) };\n      } else if (field === "dueDate") {\n        const ms = new Date(String(value)).getTime();\n        f[i] = { ...f[i], dueDate: BigInt(ms * 1_000_000) };\n      } else {\n        f[i] = { ...f[i], yearSemester: String(value) };\n      }\n      return { ...prev, feesDue: f };\n    });\n  };\n  const removeFee = (i: number) => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      return { ...prev, feesDue: prev.feesDue.filter((_, idx) => idx !== i) };\n    });\n  };\n\n  // Exam helpers\n  const addExam = () => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      return {\n        ...prev,\n        exams: [\n          ...prev.exams,\n          {\n            examId: `EXAM_${Date.now()}`,\n            subjectId: "",\n            examType: "",\n            date: BigInt(Date.now() * 1_000_000),\n          },\n        ],\n      };\n    });\n  };\n  const updateExam = (i: number, field: keyof Exam, value: string | bigint) => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      const exs = [...prev.exams];\n      if (field === "date") {\n        const ms = new Date(String(value)).getTime();\n        exs[i] = { ...exs[i], date: BigInt(ms * 1_000_000) };\n      } else {\n        exs[i] = { ...exs[i], [field]: value };\n      }\n      return { ...prev, exams: exs };\n    });\n  };\n  const removeExam = (i: number) => {\n    setLocalRecord((prev) => {\n      if (!prev) return prev;\n      return { ...prev, exams: prev.exams.filter((_, idx) => idx !== i) };\n    });\n  };\n\n  const inputClass =\n    "glass-sm px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground bg-transparent outline-none rounded-xl border-0 w-full";\n\n  return (\n    <div className="relative min-h-screen">\n      {/* BG */}\n      <div className="fixed inset-0 -z-10">\n        <img\n          src="https://images.unsplash.com/photo-1541339907198-e08756dedf3f?w=1920&q=80"\n          alt="Campus"\n          className="w-full h-full object-cover"\n          style={{\n            filter: isDark\n              ? "grayscale(60%) brightness(0.20)"\n              : "grayscale(20%) brightness(0.75)",\n          }}\n        />\n        <div\n          className={\n            isDark\n              ? "bg-overlay absolute inset-0"\n              : "bg-overlay-light absolute inset-0"\n          }\n        />\n      </div>\n\n      <div className="max-w-4xl mx-auto px-4 sm:px-6 py-10">\n        {/* Header */}\n        <div className="glass rounded-2xl p-5 mb-6 flex items-center gap-4">\n          <div className="glass-sm w-12 h-12 rounded-2xl flex items-center justify-center shrink-0">\n            <ShieldCheck size={20} className="text-foreground/70" />\n          </div>\n          <div>\n            <h1 className="font-display font-bold text-xl text-foreground">\n              {userName}\n            </h1>\n            <p className="text-muted-foreground text-sm">\n              Staff Dashboard \u00b7 Manage Student Records\n            </p>\n          </div>\n        </div>\n\n        {/* Student search */}\n        <div className="glass rounded-2xl p-5 mb-6">\n          <h2 className="font-semibold text-foreground text-sm mb-3">\n            Load Student Record\n          </h2>\n          <div className="flex gap-2">\n            <div className="flex-1 glass-sm flex items-center gap-2 px-3 py-2 rounded-xl">\n              <UserCircle\n                size={16}\n                className="text-muted-foreground shrink-0"\n              />\n              <input\n                type="text"\n                value={searchId}\n                onChange={(e) => setSearchId(e.target.value)}\n                onKeyDown={(e) => e.key === "Enter" && handleLoad()}\n                placeholder="Enter Student ID (e.g. STU001)"\n                data-ocid="staff.studentid.input"\n                className="bg-transparent text-sm text-foreground placeholder:text-muted-foreground outline-none w-full"\n              />\n            </div>\n            <button\n              type="button"\n              onClick={handleLoad}\n              data-ocid="staff.load.button"\n              className="glass-btn px-4 py-2 flex items-center gap-2 text-sm font-medium text-foreground"\n            >\n              <Search size={15} />\n              Load\n            </button>\n          </div>\n        </div>\n\n        {/* Loading state */}\n        {loadingRecord && (\n          <div\n            className="glass rounded-2xl p-6"\n            data-ocid="staff.record.loading_state"\n          >\n            <Skeleton className="h-6 w-48 mb-4 bg-foreground/10" />\n            {(["sk1", "sk2", "sk3", "sk4"] as const).map((k) => (\n              <Skeleton key={k} className="h-10 w-full mb-2 bg-foreground/10" />\n            ))}\n          </div>\n        )}\n\n        {/* Record editor */}\n        {localRecord && !loadingRecord && (\n          <>\n            {/* Student info */}\n            <div className="glass rounded-2xl p-5 mb-4">\n              <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">\n                {[\n                  { label: "First Name", field: "firstName" as const },\n                  { label: "Last Name", field: "lastName" as const },\n                  { label: "Department", field: "department" as const },\n                ].map(({ label, field }) => (\n                  <div key={field}>\n                    <label\n                      htmlFor={`student-${field}`}\n                      className="text-xs text-muted-foreground mb-1 block"\n                    >\n                      {label}\n                    </label>\n                    <input\n                      id={`student-${field}`}\n                      type="text"\n                      value={localRecord.student[field] ?? ""}\n                      onChange={(e) =>\n                        setLocalRecord((prev) =>\n                          prev\n                            ? {\n                                ...prev,\n                                student: {\n                                  ...prev.student,\n                                  [field]: e.target.value,\n                                },\n                              }\n                            : prev,\n                        )\n                      }\n                      data-ocid={`staff.student.${field}.input`}\n                      className={inputClass}\n                    />\n                  </div>\n                ))}\n              </div>\n            </div>\n\n            <Tabs defaultValue="attendance">\n              <TabsList className="glass mb-4 p-1 h-auto flex gap-1 bg-transparent w-full">\n                {[\n                  {\n                    value: "attendance",\n                    label: "Attendance",\n                    icon: GraduationCap,\n                  },\n                  { value: "marks", label: "Marks", icon: BarChart2 },\n                  { value: "exams", label: "Exams", icon: Calendar },\n                  { value: "fees", label: "Fees Due", icon: DollarSign },\n                ].map(({ value, label, icon: Icon }) => (\n                  <TabsTrigger\n                    key={value}\n                    value={value}\n                    data-ocid={`staff.${value}.tab`}\n                    className="flex-1 flex items-center justify-center gap-1.5 py-2 text-xs sm:text-sm data-[state=active]:bg-foreground/10 rounded-xl font-medium"\n                  >\n                    <Icon size={13} />\n                    <span className="hidden sm:inline">{label}</span>\n                  </TabsTrigger>\n                ))}\n              </TabsList>\n\n              {/* Attendance editor */}\n              <TabsContent value="attendance">\n                <div className="glass rounded-2xl p-5 flex flex-col gap-3">\n                  <div className="flex items-center justify-between mb-1">\n                    <h3 className="font-semibold text-foreground text-sm">\n                      Attendance Records\n                    </h3>\n                    <button\n                      type="button"\n                      onClick={addAttendance}\n                      data-ocid="staff.attendance.add_button"\n                      className="glass-btn px-3 py-1.5 flex items-center gap-1.5 text-xs text-foreground"\n                    >\n                      <Plus size={13} /> Add\n                    </button>\n                  </div>\n                  {localRecord.attendance.length === 0 ? (\n                    <p\n                      className="text-muted-foreground text-sm text-center py-4"\n                      data-ocid="staff.attendance.empty_state"\n                    >\n                      No records. Click Add to begin.\n                    </p>\n                  ) : (\n                    localRecord.attendance.map((a: Attendance, i: number) => (\n                      <div\n                        key={`att-${i}-${a.subjectId}`}\n                        className="flex gap-2 items-center"\n                        data-ocid={`staff.attendance.item.${i + 1}`}\n                      >\n                        <input\n                          type="text"\n                          value={a.subjectId}\n                          onChange={(e) =>\n                            updateAttendance(i, "subjectId", e.target.value)\n                          }\n                          placeholder="Subject ID"\n                          data-ocid="staff.attendance.subject.input"\n                          className={inputClass}\n                        />\n                        <input\n                          type="number"\n                          value={a.percentage}\n                          onChange={(e) =>\n                            updateAttendance(i, "percentage", e.target.value)\n                          }\n                          placeholder="%"\n                          min={0}\n                          max={100}\n                          className={`${inputClass} w-20`}\n                        />\n                        <button\n                          type="button"\n                          onClick={() => removeAttendance(i)}\n                          data-ocid={`staff.attendance.delete_button.${i + 1}`}\n                          className="glass-btn p-2 text-destructive shrink-0"\n                        >\n                          <Trash2 size={14} />\n                        </button>\n                      </div>\n                    ))\n                  )}\n                </div>\n              </TabsContent>\n\n              {/* Marks editor */}\n              <TabsContent value="marks">\n                <div className="glass rounded-2xl p-5 flex flex-col gap-3">\n                  <div className="flex items-center justify-between mb-1">\n                    <h3 className="font-semibold text-foreground text-sm">\n                      Marks Records\n                    </h3>\n                    <button\n                      type="button"\n                      onClick={addMark}\n                      data-ocid="staff.marks.add_button"\n                      className="glass-btn px-3 py-1.5 flex items-center gap-1.5 text-xs text-foreground"\n                    >\n                      <Plus size={13} /> Add\n                    </button>\n                  </div>\n                  {localRecord.marks.length === 0 ? (\n                    <p\n                      className="text-muted-foreground text-sm text-center py-4"\n                      data-ocid="staff.marks.empty_state"\n                    >\n                      No records. Click Add to begin.\n                    </p>\n                  ) : (\n                    localRecord.marks.map((m: Marks, i: number) => (\n                      <div\n                        key={`mark-${i}-${m.subjectId}`}\n                        className="flex gap-2 items-center"\n                        data-ocid={`staff.marks.item.${i + 1}`}\n                      >\n                        <input\n                          type="text"\n                          value={m.subjectId}\n                          onChange={(e) =>\n                            updateMark(i, "subjectId", e.target.value)\n                          }\n                          placeholder="Subject ID"\n                          className={inputClass}\n                        />\n                        <input\n                          type="text"\n                          value={m.examType}\n                          onChange={(e) =>\n                            updateMark(i, "examType", e.target.value)\n                          }\n                          placeholder="Exam Type"\n                          className={`${inputClass} w-28`}\n                        />\n                        <input\n                          type="number"\n                          value={Number(m.marks)}\n                          onChange={(e) =>\n                            updateMark(i, "marks", e.target.value)\n                          }\n                          placeholder="Marks"\n                          className={`${inputClass} w-20`}\n                        />\n                        <button\n                          type="button"\n                          onClick={() => removeMark(i)}\n                          data-ocid={`staff.marks.delete_button.${i + 1}`}\n                          className="glass-btn p-2 text-destructive shrink-0"\n                        >\n                          <Trash2 size={14} />\n                        </button>\n                      </div>\n                    ))\n                  )}\n                </div>\n              </TabsContent>\n\n              {/* Exams editor */}\n              <TabsContent value="exams">\n                <div className="glass rounded-2xl p-5 flex flex-col gap-3">\n                  <div className="flex items-center justify-between mb-1">\n                    <h3 className="font-semibold text-foreground text-sm">\n                      Exam Timetable\n                    </h3>\n                    <button\n                      type="button"\n                      onClick={addExam}\n                      data-ocid="staff.exams.add_button"\n                      className="glass-btn px-3 py-1.5 flex items-center gap-1.5 text-xs text-foreground"\n                    >\n                      <Plus size={13} /> Add\n                    </button>\n                  </div>\n                  {localRecord.exams.length === 0 ? (\n                    <p\n                      className="text-muted-foreground text-sm text-center py-4"\n                      data-ocid="staff.exams.empty_state"\n                    >\n                      No exams scheduled.\n                    </p>\n                  ) : (\n                    localRecord.exams.map((exam: Exam, i: number) => (\n                      <div\n                        key={`exam-${exam.examId || i}`}\n                        className="flex gap-2 items-center flex-wrap"\n                        data-ocid={`staff.exams.item.${i + 1}`}\n                      >\n                        <input\n                          type="text"\n                          value={exam.subjectId}\n                          onChange={(e) =>\n                            updateExam(i, "subjectId", e.target.value)\n                          }\n                          placeholder="Subject ID"\n                          className={inputClass}\n                        />\n                        <input\n                          type="text"\n                          value={exam.examType}\n                          onChange={(e) =>\n                            updateExam(i, "examType", e.target.value)\n                          }\n                          placeholder="Exam Type"\n                          className={`${inputClass} w-28`}\n                        />\n                        <input\n                          type="date"\n                          value={\n                            new Date(Number(exam.date) / 1_000_000)\n                              .toISOString()\n                              .split("T")[0]\n                          }\n                          onChange={(e) =>\n                            updateExam(i, "date", e.target.value)\n                          }\n                          className={`${inputClass} w-36`}\n                        />\n                        <button\n                          type="button"\n                          onClick={() => removeExam(i)}\n                          data-ocid={`staff.exams.delete_button.${i + 1}`}\n                          className="glass-btn p-2 text-destructive shrink-0"\n                        >\n                          <Trash2 size={14} />\n                        </button>\n                      </div>\n                    ))\n                  )}\n                </div>\n              </TabsContent>\n\n              {/* Fees editor */}\n              <TabsContent value="fees">\n                <div className="glass rounded-2xl p-5 flex flex-col gap-3">\n                  <div className="flex items-center justify-between mb-1">\n                    <h3 className="font-semibold text-foreground text-sm">\n                      Fees Due\n                    </h3>\n                    <button\n                      type="button"\n                      onClick={addFee}\n                      data-ocid="staff.fees.add_button"\n                      className="glass-btn px-3 py-1.5 flex items-center gap-1.5 text-xs text-foreground"\n                    >\n                      <Plus size={13} /> Add\n                    </button>\n                  </div>\n                  {localRecord.feesDue.length === 0 ? (\n                    <p\n                      className="text-muted-foreground text-sm text-center py-4"\n                      data-ocid="staff.fees.empty_state"\n                    >\n                      No fees due records.\n                    </p>\n                  ) : (\n                    localRecord.feesDue.map((fee: FeesDue, i: number) => (\n                      <div\n                        key={`fee-${i}-${fee.yearSemester}`}\n                        className="flex gap-2 items-center flex-wrap"\n                        data-ocid={`staff.fees.item.${i + 1}`}\n                      >\n                        <input\n                          type="text"\n                          value={fee.yearSemester}\n                          onChange={(e) =>\n                            updateFee(i, "yearSemester", e.target.value)\n                          }\n                          placeholder="Year/Semester"\n                          className={inputClass}\n                        />\n                        <input\n                          type="number"\n                          value={fee.amount}\n                          onChange={(e) =>\n                            updateFee(i, "amount", e.target.value)\n                          }\n                          placeholder="Amount (\u20b9)"\n                          className={`${inputClass} w-28`}\n                        />\n                        <input\n                          type="date"\n                          value={\n                            new Date(Number(fee.dueDate) / 1_000_000)\n                              .toISOString()\n                              .split("T")[0]\n                          }\n                          onChange={(e) =>\n                            updateFee(i, "dueDate", e.target.value)\n                          }\n                          className={`${inputClass} w-36`}\n                        />\n                        <button\n                          type="button"\n                          onClick={() => removeFee(i)}\n                          data-ocid={`staff.fees.delete_button.${i + 1}`}\n                          className="glass-btn p-2 text-destructive shrink-0"\n                        >\n                          <Trash2 size={14} />\n                        </button>\n                      </div>\n                    ))\n                  )}\n                </div>\n              </TabsContent>\n            </Tabs>\n\n            {/* Save button */}\n            <div className="mt-4 flex justify-end">\n              <button\n                type="button"\n                onClick={handleSave}\n                disabled={saving}\n                data-ocid="staff.save.primary_button"\n                className="glass-btn px-6 py-3 flex items-center gap-2 font-semibold text-foreground disabled:opacity-50"\n              >\n                {saving ? (\n                  <span\n                    className="flex items-center gap-2"\n                    data-ocid="staff.save.loading_state"\n                  >\n                    <span className="w-4 h-4 border-2 border-foreground/30 border-t-foreground rounded-full animate-spin" />\n                    Saving\u2026\n                  </span>\n                ) : (\n                  <>\n                    <Save size={16} />\n                    Save Changes\n                  </>\n                )}\n              </button>\n            </div>\n          </>\n        )}\n      </div>\n    </div>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/pages/AdminDashboard.tsx\n--------------------------------------------------------------------------------\nimport { useNavigate } from "@tanstack/react-router";\nimport {\n  Eye,\n  EyeOff,\n  FileText,\n  Lock,\n  Plus,\n  ShieldAlert,\n  Trash2,\n} from "lucide-react";\nimport { useEffect, useState } from "react";\nimport { toast } from "sonner";\nimport { useAuth } from "../contexts/AuthContext";\nimport { useTheme } from "../contexts/ThemeContext";\n\nconst CLASSIFIED_KEY = "sngce_classified";\n\nconst CATEGORIES = [\n  "Internal Circular",\n  "Exam Paper",\n  "Confidential Notice",\n  "Staff Document",\n  "Administrative Order",\n  "Financial Report",\n];\n\nexport interface ClassifiedItem {\n  id: string;\n  title: string;\n  category: string;\n  content: string;\n  uniquePassword: string;\n  createdAt: string;\n}\n\nfunction loadItems(): ClassifiedItem[] {\n  try {\n    const raw = localStorage.getItem(CLASSIFIED_KEY);\n    return raw ? JSON.parse(raw) : [];\n  } catch {\n    return [];\n  }\n}\n\nfunction saveItems(items: ClassifiedItem[]) {\n  localStorage.setItem(CLASSIFIED_KEY, JSON.stringify(items));\n}\n\nexport function AdminDashboard() {\n  const { isLoggedIn, role, userName } = useAuth();\n  const navigate = useNavigate();\n  const { theme } = useTheme();\n  const isDark = theme === "dark";\n\n  const [items, setItems] = useState<ClassifiedItem[]>(loadItems);\n\n  // Form state\n  const [title, setTitle] = useState("");\n  const [category, setCategory] = useState(CATEGORIES[0]);\n  const [content, setContent] = useState("");\n  const [uniquePassword, setUniquePassword] = useState("");\n  const [showNewPass, setShowNewPass] = useState(false);\n  const [revealedIds, setRevealedIds] = useState<Set<string>>(new Set());\n\n  useEffect(() => {\n    if (!isLoggedIn || role !== "admin") {\n      navigate({ to: "/login" });\n    }\n  }, [isLoggedIn, role, navigate]);\n\n  if (!isLoggedIn || role !== "admin") return null;\n\n  const handleAdd = (e: React.FormEvent) => {\n    e.preventDefault();\n    if (!title.trim() || !content.trim() || !uniquePassword.trim()) {\n      toast.error("Please fill in all fields.");\n      return;\n    }\n    const newItem: ClassifiedItem = {\n      id: `classified_${Date.now()}`,\n      title: title.trim(),\n      category,\n      content: content.trim(),\n      uniquePassword: uniquePassword.trim(),\n      createdAt: new Date().toLocaleString("en-IN", {\n        day: "2-digit",\n        month: "short",\n        year: "numeric",\n        hour: "2-digit",\n        minute: "2-digit",\n      }),\n    };\n    const updated = [newItem, ...items];\n    setItems(updated);\n    saveItems(updated);\n    setTitle("");\n    setCategory(CATEGORIES[0]);\n    setContent("");\n    setUniquePassword("");\n    toast.success("Classified item added successfully.");\n  };\n\n  const handleDelete = (id: string) => {\n    const updated = items.filter((item) => item.id !== id);\n    setItems(updated);\n    saveItems(updated);\n    setRevealedIds((prev) => {\n      const next = new Set(prev);\n      next.delete(id);\n      return next;\n    });\n    toast.success("Item deleted.");\n  };\n\n  const toggleReveal = (id: string) => {\n    setRevealedIds((prev) => {\n      const next = new Set(prev);\n      if (next.has(id)) next.delete(id);\n      else next.add(id);\n      return next;\n    });\n  };\n\n  const inputClass =\n    "glass-sm w-full px-4 py-3 text-sm text-foreground placeholder:text-muted-foreground bg-transparent outline-none rounded-xl border-0 focus:ring-1 focus:ring-foreground/20";\n\n  return (\n    <div className="relative min-h-screen">\n      {/* Background */}\n      <div className="fixed inset-0 -z-10">\n        <img\n          src="https://images.unsplash.com/photo-1541339907198-e08756dedf3f?w=1920&q=80"\n          alt="Campus"\n          className="w-full h-full object-cover"\n          style={{\n            filter: isDark\n              ? "grayscale(60%) brightness(0.20)"\n              : "grayscale(20%) brightness(0.75)",\n          }}\n        />\n        <div\n          className={\n            isDark\n              ? "bg-overlay absolute inset-0"\n              : "bg-overlay-light absolute inset-0"\n          }\n        />\n      </div>\n\n      <div className="max-w-4xl mx-auto px-4 sm:px-6 py-10">\n        {/* Header */}\n        <div className="glass rounded-2xl p-5 mb-6 flex items-center gap-4">\n          <div className="glass-sm w-12 h-12 rounded-2xl flex items-center justify-center shrink-0">\n            <ShieldAlert size={20} className="text-foreground/70" />\n          </div>\n          <div>\n            <h1 className="font-display font-bold text-xl text-foreground">\n              {userName}\n            </h1>\n            <p className="text-muted-foreground text-sm">\n              Admin Dashboard \u00b7 Classified Information Manager\n            </p>\n          </div>\n          <div className="ml-auto flex items-center gap-2">\n            <div className="glass-sm px-3 py-1.5 rounded-xl flex items-center gap-1.5 text-xs text-muted-foreground">\n              <Lock size={12} />\n              <span>{items.length} classified items</span>\n            </div>\n          </div>\n        </div>\n\n        {/* Add New Item Form */}\n        <div className="glass rounded-2xl p-5 mb-6">\n          <h2 className="font-semibold text-foreground text-sm mb-4 flex items-center gap-2">\n            <Plus size={15} className="text-foreground/70" />\n            Add New Classified Item\n          </h2>\n          <form\n            onSubmit={handleAdd}\n            className="flex flex-col gap-4"\n            data-ocid="admin.classified.panel"\n          >\n            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">\n              <div>\n                <label\n                  htmlFor="classified-title"\n                  className="text-xs font-medium text-muted-foreground mb-1.5 block"\n                >\n                  Title\n                </label>\n                <input\n                  id="classified-title"\n                  type="text"\n                  value={title}\n                  onChange={(e) => setTitle(e.target.value)}\n                  placeholder="e.g. Semester Exam Guidelines"\n                  data-ocid="admin.title.input"\n                  required\n                  className={inputClass}\n                />\n              </div>\n              <div>\n                <label\n                  htmlFor="classified-category"\n                  className="text-xs font-medium text-muted-foreground mb-1.5 block"\n                >\n                  Category\n                </label>\n                <select\n                  id="classified-category"\n                  value={category}\n                  onChange={(e) => setCategory(e.target.value)}\n                  data-ocid="admin.category.select"\n                  className={`${inputClass} cursor-pointer`}\n                >\n                  {CATEGORIES.map((cat) => (\n                    <option\n                      key={cat}\n                      value={cat}\n                      className="bg-background text-foreground"\n                    >\n                      {cat}\n                    </option>\n                  ))}\n                </select>\n              </div>\n            </div>\n\n            <div>\n              <label\n                htmlFor="classified-content"\n                className="text-xs font-medium text-muted-foreground mb-1.5 block"\n              >\n                Content\n              </label>\n              <textarea\n                id="classified-content"\n                value={content}\n                onChange={(e) => setContent(e.target.value)}\n                placeholder="Enter the confidential content here..."\n                rows={4}\n                data-ocid="admin.content.textarea"\n                required\n                className={`${inputClass} resize-none`}\n              />\n            </div>\n\n            <div>\n              <label\n                htmlFor="classified-password"\n                className="text-xs font-medium text-muted-foreground mb-1.5 block"\n              >\n                Unique Access Password{" "}\n                <span className="text-muted-foreground/60">\n                  (Admin-only \u2014 staff cannot set or change this)\n                </span>\n              </label>\n              <div className="relative">\n                <input\n                  id="classified-password"\n                  type={showNewPass ? "text" : "password"}\n                  value={uniquePassword}\n                  onChange={(e) => setUniquePassword(e.target.value)}\n                  placeholder="Set a unique password for this document"\n                  data-ocid="admin.password.input"\n                  required\n                  className={`${inputClass} pr-11`}\n                />\n                <button\n                  type="button"\n                  onClick={() => setShowNewPass((v) => !v)}\n                  data-ocid="admin.showpassword.toggle"\n                  tabIndex={-1}\n                  className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"\n                >\n                  {showNewPass ? <EyeOff size={16} /> : <Eye size={16} />}\n                </button>\n              </div>\n            </div>\n\n            <button\n              type="submit"\n              data-ocid="admin.classified.submit_button"\n              className="glass-btn py-3 w-full flex items-center justify-center gap-2 font-semibold text-sm text-foreground"\n            >\n              <Lock size={15} />\n              Add Classified Item\n            </button>\n          </form>\n        </div>\n\n        {/* Classified Documents List */}\n        <div>\n          <h2 className="font-semibold text-foreground text-sm mb-3 flex items-center gap-2 px-1">\n            <FileText size={15} className="text-foreground/70" />\n            Classified Documents\n          </h2>\n\n          {items.length === 0 ? (\n            <div\n              className="glass rounded-2xl p-10 flex flex-col items-center gap-3 text-center"\n              data-ocid="admin.classified.empty_state"\n            >\n              <div className="glass-sm w-12 h-12 rounded-2xl flex items-center justify-center">\n                <Lock size={20} className="text-foreground/40" />\n              </div>\n              <p className="text-muted-foreground text-sm">\n                No classified documents yet.\n              </p>\n              <p className="text-muted-foreground/60 text-xs">\n                Add your first item using the form above.\n              </p>\n            </div>\n          ) : (\n            <div className="flex flex-col gap-3">\n              {items.map((item, idx) => {\n                const isRevealed = revealedIds.has(item.id);\n                return (\n                  <div\n                    key={item.id}\n                    className="glass rounded-2xl p-5"\n                    data-ocid={`admin.classified.item.${idx + 1}`}\n                  >\n                    <div className="flex items-start justify-between gap-3 mb-3">\n                      <div className="flex-1 min-w-0">\n                        <div className="flex items-center gap-2 flex-wrap mb-1">\n                          <h3 className="font-semibold text-foreground text-sm truncate">\n                            {item.title}\n                          </h3>\n                          <span className="glass-sm px-2 py-0.5 rounded-full text-[10px] text-muted-foreground shrink-0">\n                            {item.category}\n                          </span>\n                        </div>\n                        <p className="text-xs text-muted-foreground/60">\n                          {item.createdAt}\n                        </p>\n                      </div>\n                      <button\n                        type="button"\n                        onClick={() => handleDelete(item.id)}\n                        data-ocid={`admin.classified.delete_button.${idx + 1}`}\n                        className="glass-btn p-2 text-destructive shrink-0"\n                        aria-label="Delete item"\n                      >\n                        <Trash2 size={14} />\n                      </button>\n                    </div>\n\n                    {/* Content preview */}\n                    <p className="text-xs text-muted-foreground mb-3 line-clamp-2">\n                      {item.content}\n                    </p>\n\n                    {/* Password reveal */}\n                    <div className="glass-sm rounded-xl px-3 py-2 flex items-center justify-between gap-2">\n                      <div className="flex items-center gap-2 min-w-0">\n                        <Lock\n                          size={12}\n                          className="text-muted-foreground shrink-0"\n                        />\n                        <span className="text-xs text-muted-foreground font-mono truncate">\n                          {isRevealed\n                            ? item.uniquePassword\n                            : "\u2022".repeat(\n                                Math.min(item.uniquePassword.length, 12),\n                              )}\n                        </span>\n                      </div>\n                      <button\n                        type="button"\n                        onClick={() => toggleReveal(item.id)}\n                        data-ocid={`admin.classified.toggle.${idx + 1}`}\n                        className="glass-btn p-1.5 text-muted-foreground hover:text-foreground shrink-0"\n                        aria-label={\n                          isRevealed ? "Hide password" : "Show password"\n                        }\n                      >\n                        {isRevealed ? <EyeOff size={13} /> : <Eye size={13} />}\n                      </button>\n                    </div>\n                  </div>\n                );\n              })}\n            </div>\n          )}\n        </div>\n      </div>\n    </div>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/pages/ClassifiedPage.tsx\n--------------------------------------------------------------------------------\nimport { useNavigate } from "@tanstack/react-router";\nimport { Eye, EyeOff, FileText, Lock, ShieldAlert, Unlock } from "lucide-react";\nimport { useEffect, useState } from "react";\nimport { toast } from "sonner";\nimport { useAuth } from "../contexts/AuthContext";\nimport { useTheme } from "../contexts/ThemeContext";\nimport type { ClassifiedItem } from "./AdminDashboard";\n\nconst CLASSIFIED_KEY = "sngce_classified";\n\nfunction loadItems(): ClassifiedItem[] {\n  try {\n    const raw = localStorage.getItem(CLASSIFIED_KEY);\n    return raw ? JSON.parse(raw) : [];\n  } catch {\n    return [];\n  }\n}\n\nconst CATEGORY_COLORS: Record<string, string> = {\n  "Internal Circular": "text-blue-400",\n  "Exam Paper": "text-amber-400",\n  "Confidential Notice": "text-red-400",\n  "Staff Document": "text-green-400",\n  "Administrative Order": "text-purple-400",\n  "Financial Report": "text-cyan-400",\n};\n\nexport function ClassifiedPage() {\n  const { isLoggedIn, role } = useAuth();\n  const navigate = useNavigate();\n  const { theme } = useTheme();\n  const isDark = theme === "dark";\n\n  const [items] = useState<ClassifiedItem[]>(loadItems);\n  const [unlockedIds, setUnlockedIds] = useState<Set<string>>(new Set());\n  const [passwordInputs, setPasswordInputs] = useState<Record<string, string>>(\n    {},\n  );\n  const [showPassIds, setShowPassIds] = useState<Set<string>>(new Set());\n  const [errorIds, setErrorIds] = useState<Set<string>>(new Set());\n\n  useEffect(() => {\n    if (!isLoggedIn || (role !== "staff" && role !== "admin")) {\n      navigate({ to: "/login" });\n    }\n  }, [isLoggedIn, role, navigate]);\n\n  if (!isLoggedIn || (role !== "staff" && role !== "admin")) return null;\n\n  const handleUnlock = (item: ClassifiedItem) => {\n    const entered = (passwordInputs[item.id] ?? "").trim();\n    if (entered === item.uniquePassword) {\n      setUnlockedIds((prev) => {\n        const next = new Set(prev);\n        next.add(item.id);\n        return next;\n      });\n      setErrorIds((prev) => {\n        const next = new Set(prev);\n        next.delete(item.id);\n        return next;\n      });\n      toast.success("Document unlocked.");\n    } else {\n      setErrorIds((prev) => {\n        const next = new Set(prev);\n        next.add(item.id);\n        return next;\n      });\n      toast.error("Incorrect password. Try again.");\n    }\n  };\n\n  const handleLock = (id: string) => {\n    setUnlockedIds((prev) => {\n      const next = new Set(prev);\n      next.delete(id);\n      return next;\n    });\n    setPasswordInputs((prev) => {\n      const next = { ...prev };\n      delete next[id];\n      return next;\n    });\n    setErrorIds((prev) => {\n      const next = new Set(prev);\n      next.delete(id);\n      return next;\n    });\n  };\n\n  const toggleShowPass = (id: string) => {\n    setShowPassIds((prev) => {\n      const next = new Set(prev);\n      if (next.has(id)) next.delete(id);\n      else next.add(id);\n      return next;\n    });\n  };\n\n  return (\n    <div className="relative min-h-screen">\n      {/* Background */}\n      <div className="fixed inset-0 -z-10">\n        <img\n          src="https://images.unsplash.com/photo-1562774053-701939374585?w=1920&q=80"\n          alt="Campus"\n          className="w-full h-full object-cover"\n          style={{\n            filter: isDark\n              ? "grayscale(60%) brightness(0.20)"\n              : "grayscale(20%) brightness(0.75)",\n          }}\n        />\n        <div\n          className={\n            isDark\n              ? "bg-overlay absolute inset-0"\n              : "bg-overlay-light absolute inset-0"\n          }\n        />\n      </div>\n\n      <div className="max-w-3xl mx-auto px-4 sm:px-6 py-10">\n        {/* Header */}\n        <div className="glass rounded-2xl p-5 mb-6 flex items-center gap-4">\n          <div className="glass-sm w-12 h-12 rounded-2xl flex items-center justify-center shrink-0">\n            <ShieldAlert size={20} className="text-foreground/70" />\n          </div>\n          <div>\n            <h1 className="font-display font-bold text-xl text-foreground">\n              Classified Information\n            </h1>\n            <p className="text-muted-foreground text-sm">\n              Enter the unique password to unlock each document\n            </p>\n          </div>\n          <div className="ml-auto">\n            <div className="glass-sm px-3 py-1.5 rounded-xl flex items-center gap-1.5 text-xs text-muted-foreground">\n              <Lock size={12} />\n              <span>{items.length} documents</span>\n            </div>\n          </div>\n        </div>\n\n        {/* Info notice */}\n        <div className="glass-sm rounded-xl px-4 py-3 mb-6 flex items-start gap-2.5">\n          <Lock size={14} className="text-muted-foreground shrink-0 mt-0.5" />\n          <p className="text-xs text-muted-foreground">\n            These documents are classified. Each requires a unique password set\n            exclusively by the{" "}\n            <strong className="text-foreground/80">Admin</strong>. Staff members\n            can only <em>unlock</em> documents using the password provided by\n            the Admin \u2014 staff cannot set, change, or reset any document\n            passwords.\n          </p>\n        </div>\n\n        {/* Empty state */}\n        {items.length === 0 ? (\n          <div\n            className="glass rounded-2xl p-12 flex flex-col items-center gap-3 text-center"\n            data-ocid="classified.empty_state"\n          >\n            <div className="glass-sm w-14 h-14 rounded-2xl flex items-center justify-center">\n              <FileText size={24} className="text-foreground/30" />\n            </div>\n            <p className="text-foreground text-sm font-medium">\n              No classified documents available.\n            </p>\n            <p className="text-muted-foreground/60 text-xs">\n              Contact admin to add classified documents.\n            </p>\n          </div>\n        ) : (\n          <div className="flex flex-col gap-4" data-ocid="classified.list">\n            {items.map((item, idx) => {\n              const isUnlocked = unlockedIds.has(item.id);\n              const isError = errorIds.has(item.id);\n              const showPass = showPassIds.has(item.id);\n              const colorClass =\n                CATEGORY_COLORS[item.category] ?? "text-muted-foreground";\n\n              return (\n                <div\n                  key={item.id}\n                  className="glass rounded-2xl overflow-hidden"\n                  data-ocid={`classified.item.${idx + 1}`}\n                >\n                  {/* Item header */}\n                  <div className="p-5">\n                    <div className="flex items-start justify-between gap-3">\n                      <div className="flex-1 min-w-0">\n                        <div className="flex items-center gap-2 flex-wrap mb-1">\n                          <h3 className="font-semibold text-foreground text-sm">\n                            {item.title}\n                          </h3>\n                          <span\n                            className={`glass-sm px-2 py-0.5 rounded-full text-[10px] font-medium ${colorClass}`}\n                          >\n                            {item.category}\n                          </span>\n                        </div>\n                        <p className="text-xs text-muted-foreground/60">\n                          {item.createdAt}\n                        </p>\n                      </div>\n                      <div className="shrink-0">\n                        {isUnlocked ? (\n                          <div className="flex items-center gap-1 glass-sm px-2.5 py-1 rounded-xl">\n                            <Unlock size={12} className="text-green-400" />\n                            <span className="text-[10px] text-green-400 font-medium">\n                              Unlocked\n                            </span>\n                          </div>\n                        ) : (\n                          <div className="flex items-center gap-1 glass-sm px-2.5 py-1 rounded-xl">\n                            <Lock size={12} className="text-muted-foreground" />\n                            <span className="text-[10px] text-muted-foreground font-medium">\n                              Locked\n                            </span>\n                          </div>\n                        )}\n                      </div>\n                    </div>\n                  </div>\n\n                  {/* Unlocked content */}\n                  {isUnlocked && (\n                    <div className="px-5 pb-4">\n                      <div className="glass-sm rounded-xl p-4 mb-3">\n                        <p className="text-sm text-foreground whitespace-pre-wrap leading-relaxed">\n                          {item.content}\n                        </p>\n                      </div>\n                      <button\n                        type="button"\n                        onClick={() => handleLock(item.id)}\n                        data-ocid={`classified.lock.button.${idx + 1}`}\n                        className="glass-btn px-4 py-2 flex items-center gap-2 text-xs font-medium text-muted-foreground hover:text-foreground"\n                      >\n                        <Lock size={13} />\n                        Lock Document\n                      </button>\n                    </div>\n                  )}\n\n                  {/* Password input when locked */}\n                  {!isUnlocked && (\n                    <div className="px-5 pb-5">\n                      <div className="flex gap-2">\n                        <div className="relative flex-1">\n                          <input\n                            type={showPass ? "text" : "password"}\n                            value={passwordInputs[item.id] ?? ""}\n                            onChange={(e) =>\n                              setPasswordInputs((prev) => ({\n                                ...prev,\n                                [item.id]: e.target.value,\n                              }))\n                            }\n                            onKeyDown={(e) =>\n                              e.key === "Enter" && handleUnlock(item)\n                            }\n                            placeholder="Enter unique password to unlock"\n                            data-ocid={`classified.password.input.${idx + 1}`}\n                            className={`glass-sm w-full px-3 py-2.5 pr-10 text-sm text-foreground placeholder:text-muted-foreground bg-transparent outline-none rounded-xl border-0 focus:ring-1 ${\n                              isError\n                                ? "ring-1 ring-destructive/50 focus:ring-destructive"\n                                : "focus:ring-foreground/20"\n                            }`}\n                          />\n                          <button\n                            type="button"\n                            onClick={() => toggleShowPass(item.id)}\n                            data-ocid={`classified.showpassword.toggle.${idx + 1}`}\n                            tabIndex={-1}\n                            className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"\n                          >\n                            {showPass ? (\n                              <EyeOff size={14} />\n                            ) : (\n                              <Eye size={14} />\n                            )}\n                          </button>\n                        </div>\n                        <button\n                          type="button"\n                          onClick={() => handleUnlock(item)}\n                          data-ocid={`classified.unlock.button.${idx + 1}`}\n                          className="glass-btn px-4 py-2 flex items-center gap-2 text-sm font-medium text-foreground shrink-0"\n                        >\n                          <Unlock size={14} />\n                          Unlock\n                        </button>\n                      </div>\n                      {isError && (\n                        <p\n                          className="text-xs text-destructive mt-1.5"\n                          data-ocid={`classified.password.error_state.${idx + 1}`}\n                        >\n                          Incorrect password. Please try again.\n                        </p>\n                      )}\n                    </div>\n                  )}\n                </div>\n              );\n            })}\n          </div>\n        )}\n      </div>\n    </div>\n  );\n}\n\n\n================================================================================\nCATEGORY 4: COMPONENTS\n================================================================================\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/components/Layout.tsx\n--------------------------------------------------------------------------------\nimport { Outlet } from "@tanstack/react-router";\nimport { ChatbotWidget } from "./ChatbotWidget";\nimport { Navbar } from "./Navbar";\n\nexport function Layout() {\n  return (\n    <div className="min-h-screen relative">\n      <Navbar />\n      <main className="pt-16">\n        <Outlet />\n      </main>\n      <ChatbotWidget />\n    </div>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/components/Navbar.tsx\n--------------------------------------------------------------------------------\nimport { Link, useLocation } from "@tanstack/react-router";\nimport {\n  Lock,\n  LogOut,\n  Menu,\n  Moon,\n  ShieldAlert,\n  Sun,\n  User,\n  X,\n} from "lucide-react";\nimport { useState } from "react";\nimport { useAuth } from "../contexts/AuthContext";\nimport { useTheme } from "../contexts/ThemeContext";\n\nexport function Navbar() {\n  const { theme, toggleTheme } = useTheme();\n  const { isLoggedIn, role, userName, logout } = useAuth();\n  const location = useLocation();\n  const [mobileOpen, setMobileOpen] = useState(false);\n\n  const navLinks = [\n    { to: "/home", label: "Home" },\n    { to: "/courses", label: "Courses" },\n    { to: "/fees", label: "Fees" },\n    { to: "/faculty", label: "Faculty" },\n  ];\n\n  const isActive = (to: string) => location.pathname === to;\n\n  return (\n    <header className="fixed top-0 left-0 right-0 z-50">\n      <nav className="glass-sm mx-3 mt-3 px-4 py-3 flex items-center justify-between">\n        {/* Logo */}\n        <Link\n          to="/home"\n          data-ocid="nav.home.link"\n          className="flex items-center gap-2 group"\n        >\n          <div className="w-8 h-8 rounded-lg bg-foreground/10 flex items-center justify-center group-hover:bg-foreground/20 transition-colors">\n            <span className="font-display font-bold text-xs text-foreground">\n              SG\n            </span>\n          </div>\n          <span className="font-display font-bold text-lg tracking-tight text-foreground">\n            SNGCE\n          </span>\n        </Link>\n\n        {/* Desktop nav */}\n        <div className="hidden md:flex items-center gap-1">\n          {navLinks.map((link) => (\n            <Link\n              key={link.to}\n              to={link.to}\n              data-ocid={`nav.${link.label.toLowerCase()}.link`}\n              className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all ${\n                isActive(link.to)\n                  ? "bg-foreground/10 text-foreground"\n                  : "text-muted-foreground hover:text-foreground hover:bg-foreground/5"\n              }`}\n            >\n              {link.label}\n            </Link>\n          ))}\n          {(role === "staff" || role === "admin") && (\n            <Link\n              to="/classified"\n              data-ocid="nav.classified.link"\n              className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all flex items-center gap-1.5 ${\n                isActive("/classified")\n                  ? "bg-foreground/10 text-foreground"\n                  : "text-muted-foreground hover:text-foreground hover:bg-foreground/5"\n              }`}\n            >\n              <Lock size={13} />\n              Classified\n            </Link>\n          )}\n          {role === "admin" && (\n            <Link\n              to="/admin-dashboard"\n              data-ocid="nav.admin.link"\n              className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-all flex items-center gap-1.5 ${\n                isActive("/admin-dashboard")\n                  ? "bg-foreground/10 text-foreground"\n                  : "text-muted-foreground hover:text-foreground hover:bg-foreground/5"\n              }`}\n            >\n              <ShieldAlert size={13} />\n              Admin Panel\n            </Link>\n          )}\n        </div>\n\n        {/* Right controls */}\n        <div className="flex items-center gap-2">\n          {/* Theme toggle */}\n          <button\n            type="button"\n            onClick={toggleTheme}\n            data-ocid="nav.theme.toggle"\n            className="glass-btn p-2 text-muted-foreground hover:text-foreground"\n            aria-label="Toggle theme"\n          >\n            {theme === "dark" ? <Sun size={16} /> : <Moon size={16} />}\n          </button>\n\n          {/* Auth */}\n          {isLoggedIn ? (\n            <div className="flex items-center gap-2">\n              <Link\n                to={\n                  role === "student"\n                    ? "/student-dashboard"\n                    : role === "admin"\n                      ? "/admin-dashboard"\n                      : "/staff-dashboard"\n                }\n                data-ocid="nav.dashboard.link"\n                className="glass-btn px-3 py-1.5 flex items-center gap-1.5 text-sm font-medium text-foreground"\n              >\n                <User size={14} />\n                <span className="hidden sm:inline">{userName}</span>\n              </Link>\n              <button\n                type="button"\n                onClick={logout}\n                data-ocid="nav.logout.button"\n                className="glass-btn p-2 text-muted-foreground hover:text-destructive"\n                aria-label="Logout"\n              >\n                <LogOut size={16} />\n              </button>\n            </div>\n          ) : (\n            <Link\n              to="/login"\n              data-ocid="nav.login.link"\n              className="glass-btn px-4 py-2 text-sm font-medium text-foreground"\n            >\n              Login\n            </Link>\n          )}\n\n          {/* Mobile menu toggle */}\n          <button\n            type="button"\n            onClick={() => setMobileOpen((v) => !v)}\n            data-ocid="nav.menu.toggle"\n            className="md:hidden glass-btn p-2 text-muted-foreground"\n            aria-label="Toggle menu"\n          >\n            {mobileOpen ? <X size={16} /> : <Menu size={16} />}\n          </button>\n        </div>\n      </nav>\n\n      {/* Mobile menu */}\n      {mobileOpen && (\n        <div className="md:hidden glass mx-3 mt-1 px-4 py-3 flex flex-col gap-1">\n          {navLinks.map((link) => (\n            <Link\n              key={link.to}\n              to={link.to}\n              onClick={() => setMobileOpen(false)}\n              data-ocid={`nav.mobile.${link.label.toLowerCase()}.link`}\n              className={`px-3 py-2 rounded-lg text-sm font-medium transition-all ${\n                isActive(link.to)\n                  ? "bg-foreground/10 text-foreground"\n                  : "text-muted-foreground hover:text-foreground hover:bg-foreground/5"\n              }`}\n            >\n              {link.label}\n            </Link>\n          ))}\n          {(role === "staff" || role === "admin") && (\n            <Link\n              to="/classified"\n              onClick={() => setMobileOpen(false)}\n              data-ocid="nav.mobile.classified.link"\n              className={`px-3 py-2 rounded-lg text-sm font-medium transition-all flex items-center gap-1.5 ${\n                isActive("/classified")\n                  ? "bg-foreground/10 text-foreground"\n                  : "text-muted-foreground hover:text-foreground hover:bg-foreground/5"\n              }`}\n            >\n              <Lock size={13} />\n              Classified\n            </Link>\n          )}\n          {role === "admin" && (\n            <Link\n              to="/admin-dashboard"\n              onClick={() => setMobileOpen(false)}\n              data-ocid="nav.mobile.admin.link"\n              className={`px-3 py-2 rounded-lg text-sm font-medium transition-all flex items-center gap-1.5 ${\n                isActive("/admin-dashboard")\n                  ? "bg-foreground/10 text-foreground"\n                  : "text-muted-foreground hover:text-foreground hover:bg-foreground/5"\n              }`}\n            >\n              <ShieldAlert size={13} />\n              Admin Panel\n            </Link>\n          )}\n        </div>\n      )}\n    </header>\n  );\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/components/ChatbotWidget.tsx\n--------------------------------------------------------------------------------\nimport { useNavigate } from "@tanstack/react-router";\nimport { Bot, MessageCircle, Navigation, Send, X } from "lucide-react";\nimport { useEffect, useRef, useState } from "react";\nimport { type ChatMessage, generateResponse } from "../utils/chatEngine";\nimport { type GeminiMessage, callGemini } from "../utils/geminiApi";\n\ninterface Message {\n  id: string;\n  role: "user" | "bot";\n  text: string;\n  isMulti?: boolean;\n}\n\n/** Detect if a message contains multiple distinct questions */\nfunction detectMultipleQueries(text: string): boolean {\n  const questionMarks = (text.match(/\\?/g) || []).length;\n  if (questionMarks >= 2) return true;\n  const numbered = /\\b[1-9]\\.\\s/.test(text) && text.includes("?");\n  if (numbered) return true;\n  const keywords =\n    /\\b(also|and also|what about|plus|additionally|another question|second question)\\b/i.test(\n      text,\n    );\n  if (keywords && text.includes("?")) return true;\n  return false;\n}\n\nconst WELCOME: Message = {\n  id: "welcome",\n  role: "bot",\n  text: "Hey! \ud83d\udc4b I\'m SNGCE Assistant \u2014 your college guide powered by AI. Ask me anything about courses, fees, faculty, admissions, or anything else. I can also take you to any page in the portal!",\n};\n\n/** Render bot text: handle **bold** and newlines */\nfunction BotText({ text }: { text: string }) {\n  const lines = text.split("\\n");\n  return (\n    <span className="whitespace-pre-wrap">\n      {lines.map((line, li) => {\n        const parts = line.split(/\\*\\*(.+?)\\*\\*/g);\n        return (\n          // biome-ignore lint/suspicious/noArrayIndexKey: positional text lines\n          <span key={`line-${li}`}>\n            {li > 0 && <br />}\n            {parts.map((part, pi) =>\n              pi % 2 === 1 ? (\n                // biome-ignore lint/suspicious/noArrayIndexKey: positional inline parts\n                <strong key={`b-${li}-${pi}`}>{part}</strong>\n              ) : (\n                // biome-ignore lint/suspicious/noArrayIndexKey: positional inline parts\n                <span key={`s-${li}-${pi}`}>{part}</span>\n              ),\n            )}\n          </span>\n        );\n      })}\n    </span>\n  );\n}\n\nconst CHIP_LABELS = ["Courses \ud83d\udcda", "Fees \ud83d\udcb0", "Admissions \ud83c\udf93", "Contact \ud83d\udcde"];\n\nexport function ChatbotWidget() {\n  const [open, setOpen] = useState(false);\n  const [messages, setMessages] = useState<Message[]>([WELCOME]);\n  const [input, setInput] = useState("");\n  const [isPending, setIsPending] = useState(false);\n  const [isNavigating, setIsNavigating] = useState(false);\n  const [geminiHistory, setGeminiHistory] = useState<GeminiMessage[]>([]);\n  const scrollContainerRef = useRef<HTMLDivElement>(null);\n  const inputRef = useRef<HTMLInputElement>(null);\n  const navigate = useNavigate();\n\n  // Build legacy history for fallback engine\n  const getLegacyHistory = (): ChatMessage[] => {\n    return messages.slice(1).map((m) => ({\n      role: m.role === "user" ? ("user" as const) : ("model" as const),\n      text: m.text,\n    }));\n  };\n\n  // Scroll to bottom whenever messages or pending state change\n  // biome-ignore lint/correctness/useExhaustiveDependencies: scrollContainerRef is stable; messages/isPending are intentional triggers\n  useEffect(() => {\n    const container = scrollContainerRef.current;\n    if (container) {\n      container.scrollTop = container.scrollHeight;\n    }\n  }, [messages, isPending]);\n\n  useEffect(() => {\n    if (open) {\n      const t = setTimeout(() => inputRef.current?.focus(), 150);\n      return () => clearTimeout(t);\n    }\n  }, [open]);\n\n  const dispatchMessage = async (text: string) => {\n    if (!text || isPending) return;\n\n    const isMulti = detectMultipleQueries(text);\n    const userMsg: Message = {\n      id: `${Date.now()}`,\n      role: "user",\n      text,\n      isMulti,\n    };\n    setMessages((prev) => [...prev, userMsg]);\n    setIsPending(true);\n\n    // Natural typing delay 400\u2013700ms\n    const delay = 400 + Math.random() * 300;\n    await new Promise<void>((res) => setTimeout(res, delay));\n\n    let responseText = "";\n    let redirect: string | undefined;\n\n    try {\n      // Try Gemini API first\n      const newUserPart: GeminiMessage = {\n        role: "user",\n        parts: [{ text }],\n      };\n      const currentHistory = [...geminiHistory, newUserPart];\n      const result = await callGemini(text, geminiHistory);\n      responseText = result.text;\n      redirect = result.redirect;\n\n      // Update Gemini history with both user message and model response\n      const modelPart: GeminiMessage = {\n        role: "model",\n        parts: [\n          {\n            text:\n              result.text +\n              (result.redirect ? ` NAVIGATE:${result.redirect}` : ""),\n          },\n        ],\n      };\n      setGeminiHistory([...currentHistory, modelPart]);\n    } catch (_err) {\n      // Fallback to local rule-based engine\n      const fallback = generateResponse(text, getLegacyHistory());\n      responseText = fallback.text;\n      redirect = fallback.redirect;\n    }\n\n    const botMsg: Message = {\n      id: `${Date.now()}_bot`,\n      role: "bot",\n      text: redirect\n        ? `${responseText} *(Navigating in a moment...)*`\n        : responseText,\n    };\n    setMessages((prev) => [...prev, botMsg]);\n    setIsPending(false);\n\n    if (redirect) {\n      const target = redirect;\n      setIsNavigating(true);\n      setTimeout(() => {\n        setIsNavigating(false);\n        navigate({ to: target });\n      }, 1500);\n    }\n  };\n\n  const handleSend = () => {\n    const text = input.trim();\n    if (!text || isPending) return;\n    setInput("");\n    dispatchMessage(text);\n  };\n\n  const handleChip = (chip: string) => {\n    const text = chip.split(" ")[0];\n    dispatchMessage(text);\n  };\n\n  return (\n    <>\n      {/* Floating button */}\n      <button\n        type="button"\n        onClick={() => setOpen((v) => !v)}\n        data-ocid="chatbot.open_modal_button"\n        className="fixed bottom-6 right-6 z-50 glass-pill p-4 flex items-center gap-2 text-foreground"\n        aria-label="Open chatbot"\n      >\n        {open ? <X size={20} /> : <MessageCircle size={20} />}\n        {!open && <span className="text-sm font-medium pr-1">Ask SNGCE</span>}\n      </button>\n\n      {/* Chat panel */}\n      {open && (\n        <div\n          data-ocid="chatbot.modal"\n          className="fixed bottom-20 right-6 z-50 w-80 sm:w-96 rounded-2xl overflow-hidden flex flex-col"\n          style={{ height: "480px" }}\n        >\n          <div className="glass h-full flex flex-col rounded-2xl overflow-hidden">\n            {/* Header */}\n            <div className="px-4 py-3 flex items-center gap-2 border-b border-white/10 flex-shrink-0">\n              <div className="glass-sm p-1.5 rounded-lg">\n                <Bot size={16} className="text-foreground" />\n              </div>\n              <div>\n                <p className="font-display font-semibold text-sm text-foreground">\n                  SNGCE Assistant\n                </p>\n                <p className="text-xs text-muted-foreground flex items-center gap-1">\n                  {isNavigating ? (\n                    <>\n                      <Navigation\n                        size={10}\n                        className="animate-pulse text-foreground/60"\n                      />\n                      <span>Navigating\u2026</span>\n                    </>\n                  ) : (\n                    "AI-powered \u00b7 Always here to help"\n                  )}\n                </p>\n              </div>\n              <button\n                type="button"\n                onClick={() => setOpen(false)}\n                data-ocid="chatbot.close_button"\n                className="ml-auto glass-btn p-1.5 text-muted-foreground hover:text-foreground"\n                aria-label="Close chat"\n              >\n                <X size={14} />\n              </button>\n            </div>\n\n            {/* Messages \u2014 native scroll for reliable scrollIntoView */}\n            <div\n              ref={scrollContainerRef}\n              className="flex-1 overflow-y-auto px-3 py-3 min-h-0"\n              style={{ scrollBehavior: "smooth" }}\n            >\n              <div className="flex flex-col gap-3">\n                {messages.map((msg, msgIdx) => {\n                  // A user message with isMulti: show the badge while the very next message is pending\n                  const isLastUserMsg =\n                    msg.role === "user" &&\n                    msgIdx === messages.length - 1 &&\n                    isPending;\n                  const showMultiBadge = msg.isMulti && isLastUserMsg;\n\n                  return (\n                    <div key={msg.id} className="flex flex-col">\n                      <div\n                        className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}\n                      >\n                        {msg.role === "bot" && (\n                          <div className="w-6 h-6 rounded-full glass-sm flex items-center justify-center mr-1.5 mt-0.5 flex-shrink-0">\n                            <Bot size={12} className="text-foreground/70" />\n                          </div>\n                        )}\n                        <div\n                          className={`max-w-[78%] rounded-2xl px-3 py-2 text-sm leading-relaxed ${\n                            msg.role === "user"\n                              ? "bg-foreground text-background rounded-br-sm"\n                              : "glass-sm text-foreground rounded-bl-sm"\n                          }`}\n                        >\n                          {msg.role === "bot" ? (\n                            <BotText text={msg.text} />\n                          ) : (\n                            msg.text\n                          )}\n                        </div>\n                      </div>\n                      {showMultiBadge && (\n                        <div className="flex justify-end mt-1">\n                          <span className="glass-sm text-[10px] text-muted-foreground px-2 py-0.5 rounded-full flex items-center gap-1">\n                            \ud83d\udccb Organising multiple queries\u2026\n                          </span>\n                        </div>\n                      )}\n                    </div>\n                  );\n                })}\n\n                {isPending && (\n                  <div className="flex justify-start items-center gap-1.5">\n                    <div className="w-6 h-6 rounded-full glass-sm flex items-center justify-center flex-shrink-0">\n                      <Bot size={12} className="text-foreground/70" />\n                    </div>\n                    <div className="glass-sm rounded-2xl rounded-bl-sm px-3 py-2.5">\n                      <span\n                        className="flex gap-1 items-center"\n                        data-ocid="chatbot.loading_state"\n                      >\n                        <span className="w-1.5 h-1.5 rounded-full bg-muted-foreground animate-bounce [animation-delay:0ms]" />\n                        <span className="w-1.5 h-1.5 rounded-full bg-muted-foreground animate-bounce [animation-delay:150ms]" />\n                        <span className="w-1.5 h-1.5 rounded-full bg-muted-foreground animate-bounce [animation-delay:300ms]" />\n                      </span>\n                    </div>\n                  </div>\n                )}\n                <div />\n              </div>\n            </div>\n\n            {/* Quick suggestion chips \u2014 shown only on fresh chat */}\n            {messages.length <= 1 && !isPending && (\n              <div className="px-3 pb-2 flex gap-1.5 flex-wrap flex-shrink-0">\n                {CHIP_LABELS.map((chip) => (\n                  <button\n                    key={chip}\n                    type="button"\n                    onClick={() => handleChip(chip)}\n                    className="glass-sm text-xs px-2.5 py-1 rounded-full text-muted-foreground hover:text-foreground transition-colors cursor-pointer"\n                  >\n                    {chip}\n                  </button>\n                ))}\n              </div>\n            )}\n\n            {/* Input */}\n            <div className="px-3 pb-3 pt-2 border-t border-white/10 flex gap-2 flex-shrink-0">\n              <input\n                ref={inputRef}\n                type="text"\n                value={input}\n                onChange={(e) => setInput(e.target.value)}\n                onKeyDown={(e) => e.key === "Enter" && handleSend()}\n                placeholder="Ask anything about SNGCE\u2026"\n                data-ocid="chatbot.input"\n                className="flex-1 glass-sm px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground bg-transparent outline-none rounded-xl border-none"\n                disabled={isPending}\n              />\n              <button\n                type="button"\n                onClick={handleSend}\n                disabled={!input.trim() || isPending}\n                data-ocid="chatbot.submit_button"\n                className="glass-btn px-3 py-2 text-foreground disabled:opacity-40 disabled:cursor-not-allowed"\n                aria-label="Send message"\n              >\n                <Send size={16} />\n              </button>\n            </div>\n          </div>\n        </div>\n      )}\n    </>\n  );\n}\n\n\n================================================================================\nCATEGORY 5: CONTEXTS\n================================================================================\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/contexts/AuthContext.tsx\n--------------------------------------------------------------------------------\nimport type React from "react";\nimport {\n  createContext,\n  useCallback,\n  useContext,\n  useEffect,\n  useState,\n} from "react";\n\nexport type UserRole = "student" | "staff" | "admin" | null;\n\ninterface AuthState {\n  isLoggedIn: boolean;\n  role: UserRole;\n  studentId: string | null;\n  userName: string | null;\n}\n\ninterface AuthContextType extends AuthState {\n  login: (\n    role: NonNullable<UserRole>,\n    name: string,\n    studentId?: string,\n  ) => void;\n  logout: () => void;\n}\n\nconst AUTH_KEY = "sngce_auth";\n\nconst defaultState: AuthState = {\n  isLoggedIn: false,\n  role: null,\n  studentId: null,\n  userName: null,\n};\n\nconst AuthContext = createContext<AuthContextType>({\n  ...defaultState,\n  login: () => {},\n  logout: () => {},\n});\n\nexport function AuthProvider({ children }: { children: React.ReactNode }) {\n  const [auth, setAuth] = useState<AuthState>(() => {\n    try {\n      const stored = localStorage.getItem(AUTH_KEY);\n      return stored ? JSON.parse(stored) : defaultState;\n    } catch {\n      return defaultState;\n    }\n  });\n\n  useEffect(() => {\n    localStorage.setItem(AUTH_KEY, JSON.stringify(auth));\n  }, [auth]);\n\n  const login = useCallback(\n    (role: NonNullable<UserRole>, name: string, studentId?: string) => {\n      setAuth({\n        isLoggedIn: true,\n        role,\n        studentId: studentId ?? null,\n        userName: name,\n      });\n    },\n    [],\n  );\n\n  const logout = useCallback(() => {\n    setAuth(defaultState);\n  }, []);\n\n  return (\n    <AuthContext.Provider value={{ ...auth, login, logout }}>\n      {children}\n    </AuthContext.Provider>\n  );\n}\n\nexport function useAuth() {\n  return useContext(AuthContext);\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/contexts/ThemeContext.tsx\n--------------------------------------------------------------------------------\nimport type React from "react";\nimport {\n  createContext,\n  useCallback,\n  useContext,\n  useEffect,\n  useState,\n} from "react";\n\ntype Theme = "light" | "dark";\n\ninterface ThemeContextType {\n  theme: Theme;\n  toggleTheme: () => void;\n}\n\nconst ThemeContext = createContext<ThemeContextType>({\n  theme: "dark",\n  toggleTheme: () => {},\n});\n\nexport function ThemeProvider({ children }: { children: React.ReactNode }) {\n  const [theme, setTheme] = useState<Theme>(() => {\n    try {\n      const stored = localStorage.getItem("sngce_theme") as Theme | null;\n      return stored ?? "dark";\n    } catch {\n      return "dark";\n    }\n  });\n\n  useEffect(() => {\n    const root = document.documentElement;\n    if (theme === "dark") {\n      root.classList.add("dark");\n    } else {\n      root.classList.remove("dark");\n    }\n    localStorage.setItem("sngce_theme", theme);\n  }, [theme]);\n\n  const toggleTheme = useCallback(() => {\n    setTheme((t) => (t === "dark" ? "light" : "dark"));\n  }, []);\n\n  return (\n    <ThemeContext.Provider value={{ theme, toggleTheme }}>\n      {children}\n    </ThemeContext.Provider>\n  );\n}\n\nexport function useTheme() {\n  return useContext(ThemeContext);\n}\n\n\n================================================================================\nCATEGORY 6: UTILITIES\n================================================================================\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/utils/geminiApi.ts\n--------------------------------------------------------------------------------\n/**\n * Gemini API integration for SNGCE Chatbot\n * Uses Google\'s Gemini 2.0 Flash (free, no auth needed via public endpoint)\n */\n\nconst GEMINI_API_KEY = "AIzaSyB8qFpfOoZTBGKTlrz8FqxidRfIc-BSVIY"; // public demo key\nconst GEMINI_MODEL = "gemini-2.0-flash";\nconst GEMINI_URL = `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${GEMINI_API_KEY}`;\n\nconst SYSTEM_PROMPT = `You are SNGCE Assistant, the official AI chatbot for Sree Narayana Gurukulam College of Engineering (SNGCE).\n\nYour role is to help students, parents, visitors, and staff with ANY question \u2014 about SNGCE, education, courses, engineering, college life, career advice, general knowledge, or anything else. Be friendly, warm, and human-like. Keep answers concise but complete.\n\nMULTI-QUERY HANDLING (VERY IMPORTANT):\n- When the user asks multiple questions in one message, ALWAYS identify each question and answer ALL of them in the same response.\n- Format multi-question responses like this:\n  **1. [First Question Topic]**\n  [Answer]\n\n  **2. [Second Question Topic]**\n  [Answer]\n\n  (and so on for each question)\n- Never skip a question. Never say "I\'ll answer one at a time". Answer everything at once.\n- You can detect multiple questions by: multiple question marks, numbered items, bullet points, or questions joined by "and", "also", "what about", "plus".\n\nCRITICAL RULES \u2014 follow these without exception:\n1. NEVER say "ask the admin", "contact the office", "ask someone else", "I don\'t know", or redirect the user to another person.\n2. NEVER say you cannot answer something. If you lack specific data, give your best answer using general knowledge.\n3. For questions about specific student data (marks, attendance, fees due) that you can\'t access, explain what the student dashboard shows and offer to navigate there \u2014 but NEVER say "ask someone else".\n4. Answer EVERYTHING: college info, education advice, career guidance, engineering topics, general knowledge, fun facts, jokes, motivation \u2014 anything.\n5. If asked about something very specific (like a particular professor\'s phone number) that you truly don\'t have, give a reasonable general answer and offer to navigate to the relevant page.\n6. Always answer in a confident, helpful, human-like tone. Never be dismissive.\n\nKey facts about SNGCE:\n- Full Name: Sree Narayana Gurukulam College of Engineering\n- Established: 2002\n- College Code: SNG (B.Tech/M.Tech), SRA (MCA)\n- Managed by: Sree Narayana Gurukulam Charitable Trust (under SNDP Kunnathunadu Union)\n- Affiliated to: APJ Abdul Kalam Technological University (KTU)\n- Approved by: AICTE\n- Accreditation: International Accreditation Organization (IAO)\n- Collaboration: Universities in USA\n- Research Centre: Affiliated to KUFOS\n- Location: Kadayirippu P.O, Kolenchery, Ernakulam, Kerala 682311\n- Phone: 0484-2597800 (30 Lines)\n- Principal: +91 9497417700\n- Manager: +91 9188918243\n- Email: info@sngce.ac.in, principal@sngce.ac.in\n- Website: www.sngce.ac.in\n- Campus ERP: https://sngce.etlab.in/user/login\n- Fee Payment: https://instapay.csb.co.in\n- Students: 3000+, Faculty: 150+, Departments: 10\n\nB.Tech Programs (8 semesters, affiliated to KTU):\n1. Civil Engineering \u2013 60 seats\n2. Mechanical Engineering \u2013 60 seats\n3. Electrical and Electronics Engineering (EEE) \u2013 30 seats\n4. Electronics and Communication Engineering (ECE) \u2013 60 seats\n5. Computer Science and Engineering (CSE) \u2013 180 seats\n6. Naval Architecture and Ship Building \u2013 120 seats\n7. ECE (VLSI Design and Technology) \u2013 60 seats\n8. Artificial Intelligence and Machine Learning \u2013 60 seats\n9. CSE (Cyber Security) \u2013 60 seats\n\nM.Tech Programs (2 years):\n1. Computer Science and Engineering\n2. VLSI and Embedded Systems\n3. Structural Engineering\n\nPG Programs:\n- MBA (Business Administration) \u2013 2 years (via KMAT/CMAT)\n- MCA (Computer Applications) \u2013 via KMAT/KTU allotment (College Code: SRA)\n\nPh.D: Research programs available\n\nFees (approximate, per year):\n- B.Tech (General Quota): \u20b980,000\u2013\u20b995,000/year\n- B.Tech (Management Quota): \u20b91,00,000\u2013\u20b91,20,000/year\n- M.Tech: \u20b970,000\u2013\u20b980,000/year\n- MBA: \u20b985,000/year\n- Hostel: \u20b955,000\u2013\u20b965,000 (including food)\n\nAdmissions:\n- B.Tech: Through KEAM (Kerala Engineering Architecture Medical) or Management Quota\n- M.Tech: Through GATE/PGCET/KTU allotment\n- MBA: Through KMAT/CMAT\n- MCA: Through KMAT/KTU allotment\n- Admission Enquiry 2026: https://docs.google.com/forms/d/1Zj1BS3OH9ze6-84oLVSVeAbKG0VFEnMKF3qTQXWJIYg\n\nDepartments:\n1. Science and Humanities\n2. Civil Engineering\n3. Electrical and Electronics Engineering\n4. Electronics and Communication Engineering\n5. Computer Science and Engineering\n6. Mechanical Engineering\n7. Naval Architecture and Ship Building\n8. Computer Applications (MCA)\n9. Management Studies (MBA)\n10. Artificial Intelligence and Cyber Security\n\nPlacement Stats (recent):\n- 2023-24: 64 companies, 56% placement\n- 2022-23: 103 companies, 62% placement\n- 2021-22: 101 companies, 92% placement\n- Key recruiters: UST Global, Infosys, Wipro, HCL, Cognizant, TCS, Accenture, Deloitte, Oracle, Bosch, Cisco, EY, ICICI Prudential, SBI Cards\n\nInfrastructure:\n- State-of-the-art laboratories\n- Library with digital resources\n- Conference and seminar halls\n- Boys\' and Girls\' hostels with food\n- College bus service\n- IEDC (Innovation & Entrepreneurship Development Centre)\n- IEEE Student Chapter\n- NSS Unit\n- IIC (Institution\'s Innovation Council)\n\nCampus Life:\n- SNGCE in NEWS\n- IEDC, IEEE, NSS\n- Extra-curricular activities\n- RESILIENZ (National Level Management Fest)\n- AI BootCamps, Tech Fests, Hackathons\n\nVision: Realization of a self contained center of excellence for value based transformative education, research and innovation.\n\nThis web app has the following pages:\n- /home - Home/Dashboard\n- /courses - Courses offered\n- /fees - Fee structure\n- /faculty - Faculty directory\n- /login - Login for students and staff\n- /student-dashboard - Student portal (attendance, marks, timetable, fees due)\n- /staff-dashboard - Staff portal (manage student records)\n- /classified - Classified documents (staff/admin only, requires unique password per document)\n- /admin-dashboard - Admin panel (admin only, for creating classified docs and setting their passwords)\n\nIMPORTANT: If the user asks to navigate somewhere or view a page, always end your response with exactly this format on a new line:\nNAVIGATE:/path\n\nFor example if they say "show me courses" end with:\nNAVIGATE:/courses\n\nOnly add NAVIGATE: if there\'s a clear navigation intent. Otherwise do not include it.\n\nRespond in the same language the user writes in. Be conversational, helpful, and never robotic.`;\n\nexport interface GeminiMessage {\n  role: "user" | "model";\n  parts: { text: string }[];\n}\n\nexport async function callGemini(\n  userMessage: string,\n  history: GeminiMessage[],\n): Promise<{ text: string; redirect?: string }> {\n  const contents: GeminiMessage[] = [\n    ...history,\n    { role: "user", parts: [{ text: userMessage }] },\n  ];\n\n  const body = {\n    system_instruction: {\n      parts: [{ text: SYSTEM_PROMPT }],\n    },\n    contents,\n    generationConfig: {\n      temperature: 0.9,\n      maxOutputTokens: 800,\n      topP: 0.95,\n    },\n  };\n\n  const response = await fetch(GEMINI_URL, {\n    method: "POST",\n    headers: { "Content-Type": "application/json" },\n    body: JSON.stringify(body),\n  });\n\n  if (!response.ok) {\n    throw new Error(`Gemini API error: ${response.status}`);\n  }\n\n  const data = await response.json();\n  const rawText: string =\n    data?.candidates?.[0]?.content?.parts?.[0]?.text ?? "";\n\n  // Parse navigation intent\n  const navigateMatch = rawText.match(/NAVIGATE:(\\S+)/);\n  const redirect = navigateMatch ? navigateMatch[1] : undefined;\n  const text = rawText.replace(/NAVIGATE:\\S+/g, "").trim();\n\n  return { text, redirect };\n}\n\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/utils/chatEngine.ts\n--------------------------------------------------------------------------------\n/**\n * SNGCE Chat Engine\n * Comprehensive, human-like response system for the SNGCE College Assistant.\n * Handles navigation, college info, student queries, general conversation, and more.\n */\n\nexport interface ChatMessage {\n  role: "user" | "model";\n  text: string;\n}\n\nexport interface BotResponse {\n  text: string;\n  redirect?: string;\n}\n\n// \u2500\u2500 Utilities \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nfunction normalize(text: string): string {\n  return text\n    .toLowerCase()\n    .replace(/[^a-z0-9\\s]/g, "")\n    .trim();\n}\n\nfunction contains(msg: string, ...terms: string[]): boolean {\n  return terms.some((t) => msg.includes(t));\n}\n\nfunction pick<T>(arr: T[]): T {\n  return arr[Math.floor(Math.random() * arr.length)];\n}\n\n// \u2500\u2500 Knowledge Base \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nconst COLLEGE_INFO = {\n  name: "Sree Narayana Gurukulam College of Engineering",\n  shortName: "SNGCE",\n  established: 1999,\n  location: "Kadayirippu P.O., Koothattukulam, Ernakulam, Kerala 686 670",\n  phone: "+91 485 2234567",\n  email: "info@sngce.ac.in",\n  website: "www.sngce.ac.in",\n  affiliation: "APJ Abdul Kalam Technological University (KTU)",\n  approval: "AICTE",\n  students: "3000+",\n  faculty: "150+",\n  departments: 8,\n  principal:\n    "The college is headed by a distinguished principal with decades of academic experience.",\n};\n\nconst COURSES_INFO = `\n**B.Tech Programs (4-year):**\n- Computer Science & Engineering (CSE)\n- Electronics & Communication Engineering (ECE)\n- Electrical & Electronics Engineering (EEE)\n- Mechanical Engineering (ME)\n- Civil Engineering (CE)\n- Information Technology (IT)\n\n**M.Tech Programs (2-year):**\n- Computer Science & Engineering\n- VLSI & Embedded Systems\n- Structural Engineering\n\n**MBA Program (2-year):**\n- Business Administration\n`;\n\nconst FEES_INFO = `\n**B.Tech (per year):**\n- General Category: \u20b975,000 \u2013 \u20b990,000\n- Management Quota: \u20b91,00,000 \u2013 \u20b91,10,000\n\n**M.Tech (per year):**\n- \u20b965,000 \u2013 \u20b980,000\n\n**MBA (per year):**\n- \u20b970,000 \u2013 \u20b985,000\n\n**Hostel (per year):**\n- \u20b955,000 \u2013 \u20b965,000 (including food)\n\n**Scholarships Available:**\n- Government merit scholarships\n- SC/ST fee concessions\n- Management scholarships for toppers\n`;\n\nconst ADMISSION_INFO = `\n**B.Tech Admission:**\n- Through KEAM (Kerala Engineering Architecture Medical) entrance exam\n- Application: usually March\u2013April\n- Results & allotment: May\u2013June\n\n**M.Tech Admission:**\n- GATE score based\n- University-level allotment through KTU\n\n**MBA Admission:**\n- Through KMAT / CMAT scores\n- Application: usually February\u2013March\n\nAll admissions are through the centralized Kerala Engineering Admissions (KEA) process.\n`;\n\nconst FACULTY_INFO =\n  "SNGCE has 150+ faculty members across 8 departments. Each department is headed by experienced professors with Ph.D. qualifications. Faculty are actively involved in research, publications, and industry collaborations. You can browse the complete faculty directory for names, qualifications, subjects taught, and department details.";\n\nconst DEPARTMENTS = [\n  "Computer Science & Engineering",\n  "Electronics & Communication Engineering",\n  "Electrical & Electronics Engineering",\n  "Mechanical Engineering",\n  "Civil Engineering",\n  "Information Technology",\n  "Applied Sciences & Humanities",\n  "Management Studies (MBA)",\n];\n\nconst FACILITIES = `\n**Campus Facilities:**\n- Well-equipped laboratories for all departments\n- Central library with 50,000+ books and digital resources\n- High-speed Wi-Fi campus\n- Sports complex with cricket ground, basketball & volleyball courts\n- Hostel for boys and girls separately\n- Cafeteria with hygienic food\n- Auditorium and seminar halls\n- Innovation & entrepreneurship cell\n- Placement cell with active industry connections\n`;\n\nconst PLACEMENT_INFO =\n  "SNGCE has a dedicated Placement & Training Cell. Top companies like TCS, Infosys, Wipro, Cognizant, and many more recruit from campus. The college organizes soft skills training, aptitude workshops, and mock interviews throughout the year. Average placement rate is above 80% for eligible students.";\n\nconst CONTACT_INFO = `You can reach SNGCE at:\n- **Address:** Kadayirippu P.O., Koothattukulam, Ernakulam, Kerala 686 670\n- **Phone:** +91 485 2234567\n- **Email:** info@sngce.ac.in\n- **Website:** www.sngce.ac.in`;\n\n// \u2500\u2500 Response Categories \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nconst greetingResponses = [\n  "Hey there! \ud83d\udc4b I\'m SNGCE Assistant, your college guide. How can I help you today?",\n  "Hi! Welcome to SNGCE\'s virtual assistant. What would you like to know?",\n  "Hello! Great to see you here. I\'m here to help you with anything about SNGCE. What\'s on your mind?",\n  "Hey! I\'m your SNGCE guide. Whether it\'s courses, fees, faculty, or just finding your way around \u2014 I\'ve got you! What do you need?",\n  "Hi there! \ud83d\ude0a I\'m SNGCE Assistant. Feel free to ask me anything about the college!",\n];\n\nconst howAreYouResponses = [\n  "I\'m doing great, thanks for asking! I\'m always ready to help you navigate SNGCE. What can I do for you?",\n  "All good here! I\'m an AI assistant, so I\'m always at 100% \ud83d\ude04 How can I help you today?",\n  "Fantastic, thanks! Running on good vibes and college knowledge. What would you like to know?",\n];\n\nconst thankYouResponses = [\n  "You\'re very welcome! \ud83d\ude0a Don\'t hesitate to ask if you have more questions.",\n  "Happy to help! That\'s what I\'m here for. Anything else you\'d like to know?",\n  "Anytime! Feel free to come back if you need anything else.",\n  "Of course! Always glad to assist. Is there anything else I can help you with?",\n];\n\nconst goodbyeResponses = [\n  "Goodbye! It was great chatting with you. Good luck with everything! \ud83d\udc4b",\n  "Take care! Feel free to come back anytime you have questions. Bye for now! \ud83d\ude0a",\n  "See you around! Don\'t hesitate to reach out whenever you need help. Goodbye!",\n];\n\nconst unknownResponses = [\n  "Great question! Let me think about that. SNGCE is a KTU-affiliated engineering college in Kerala \u2014 whatever you need to know about courses, career, campus, education, or anything else, I\'m here for it. Could you give me a bit more context so I can give you a precise answer?",\n  "Interesting! I want to make sure I give you the most useful answer. Are you asking about SNGCE specifically, or is this a general education/engineering question? Either way, I\'ve got you covered!",\n  "I\'m on it! That\'s a broad topic \u2014 could you tell me a bit more so I can tailor the answer? Or if you want, I can give you a general overview right now.",\n  "Let me help you with that! To give you the best answer, could you share a little more detail about what you\'re looking for? I can cover anything from SNGCE info to engineering topics to career advice.",\n];\n\n// \u2500\u2500 Main Response Engine \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nexport function generateResponse(\n  message: string,\n  history: ChatMessage[],\n): BotResponse {\n  const msg = normalize(message);\n  const historyLength = history.length;\n\n  // \u2500\u2500 Greetings \u2500\u2500\n  if (\n    contains(\n      msg,\n      "hello",\n      "hi ",\n      "hey",\n      "howdy",\n      "sup ",\n      "what\'s up",\n      "whats up",\n      "good morning",\n      "good evening",\n      "good afternoon",\n    ) &&\n    msg.length < 40\n  ) {\n    return { text: pick(greetingResponses) };\n  }\n\n  // \u2500\u2500 How are you \u2500\u2500\n  if (\n    contains(\n      msg,\n      "how are you",\n      "how r u",\n      "how do you do",\n      "you doing",\n      "hows it going",\n    )\n  ) {\n    return { text: pick(howAreYouResponses) };\n  }\n\n  // \u2500\u2500 Bot identity \u2500\u2500\n  if (\n    contains(\n      msg,\n      "who are you",\n      "what are you",\n      "your name",\n      "what is your name",\n      "tell me about yourself",\n      "introduce yourself",\n    )\n  ) {\n    return {\n      text: "I\'m **SNGCE Assistant** \u2014 your friendly college guide! I can help you with info about courses, fees, faculty, admissions, and help you navigate the student or staff portal. What would you like to know?",\n    };\n  }\n\n  // \u2500\u2500 Thanks \u2500\u2500\n  if (\n    contains(\n      msg,\n      "thank you",\n      "thanks",\n      "thank u",\n      "thx",\n      "ty ",\n      "appreciate",\n      "helpful",\n    )\n  ) {\n    return { text: pick(thankYouResponses) };\n  }\n\n  // \u2500\u2500 Goodbye \u2500\u2500\n  if (contains(msg, "bye", "goodbye", "see you", "later", "take care", "cya")) {\n    return { text: pick(goodbyeResponses) };\n  }\n\n  // \u2500\u2500 Navigation: Home \u2500\u2500\n  if (\n    contains(\n      msg,\n      "go home",\n      "go back",\n      "main page",\n      "home page",\n      "back to home",\n      "homepage",\n    )\n  ) {\n    return {\n      text: "Sure! Taking you to the home page now. \ud83c\udfe0",\n      redirect: "/home",\n    };\n  }\n\n  // \u2500\u2500 Navigation: Courses \u2500\u2500\n  if (\n    contains(\n      msg,\n      "show courses",\n      "see courses",\n      "take me to courses",\n      "go to courses",\n      "open courses",\n      "show programs",\n      "go to programs",\n      "navigate to course",\n    )\n  ) {\n    return {\n      text: "Sure! Let me take you to the Courses page where you can explore all our B.Tech, M.Tech and MBA programs. \ud83d\udcda",\n      redirect: "/courses",\n    };\n  }\n\n  // \u2500\u2500 Navigation: Fees \u2500\u2500\n  if (\n    contains(\n      msg,\n      "show fees",\n      "go to fees",\n      "open fees",\n      "see fees",\n      "navigate to fees",\n      "fee page",\n      "show fee structure",\n    )\n  ) {\n    return {\n      text: "Of course! Taking you to the Fee Structure page right now. \ud83d\udcb0",\n      redirect: "/fees",\n    };\n  }\n\n  // \u2500\u2500 Navigation: Faculty \u2500\u2500\n  if (\n    contains(\n      msg,\n      "show faculty",\n      "go to faculty",\n      "open faculty",\n      "see faculty",\n      "navigate to faculty",\n      "show teachers",\n      "show professors",\n    )\n  ) {\n    return {\n      text: "Sure thing! Let me take you to the Faculty Directory. \ud83d\udc68\u200d\ud83c\udfeb",\n      redirect: "/faculty",\n    };\n  }\n\n  // \u2500\u2500 Navigation: Login \u2500\u2500\n  if (\n    contains(\n      msg,\n      "login page",\n      "sign in page",\n      "go to login",\n      "open login",\n      "student portal link",\n      "go to portal",\n    )\n  ) {\n    return {\n      text: "Taking you to the login page! You can sign in as a student or staff member there.",\n      redirect: "/login",\n    };\n  }\n\n  // \u2500\u2500 Navigation: Staff \u2500\u2500\n  if (\n    contains(\n      msg,\n      "staff login",\n      "staff portal",\n      "staff sign in",\n      "go to staff",\n      "open staff portal",\n    )\n  ) {\n    return {\n      text: "Heading to the staff portal now! Staff can manage student academic records from there. \ud83d\udd10",\n      redirect: "/login",\n    };\n  }\n\n  // \u2500\u2500 Navigation: Student Dashboard \u2500\u2500\n  if (\n    contains(\n      msg,\n      "my dashboard",\n      "student dashboard",\n      "my attendance",\n      "check attendance",\n      "see my marks",\n      "my results",\n      "my timetable",\n      "my fees due",\n    )\n  ) {\n    return {\n      text: "Your academic details like attendance, marks, exam timetable, and fee dues are all in your student dashboard. Please log in first to access them!",\n      redirect: "/login",\n    };\n  }\n\n  // \u2500\u2500 About SNGCE \u2500\u2500\n  if (\n    contains(\n      msg,\n      "about sngce",\n      "about the college",\n      "tell me about",\n      "what is sngce",\n      "history of",\n      "when was",\n      "established",\n      "founded",\n      "about this college",\n      "college info",\n      "college information",\n    )\n  ) {\n    return {\n      text: `**${COLLEGE_INFO.name} (SNGCE)** was established in **${COLLEGE_INFO.established}** in ${COLLEGE_INFO.location}. It\'s affiliated to **${COLLEGE_INFO.affiliation}** and approved by **${COLLEGE_INFO.approval}**.\\n\\nWith **${COLLEGE_INFO.students} students** and **${COLLEGE_INFO.faculty} faculty** across **${COLLEGE_INFO.departments} departments**, SNGCE is one of Kerala\'s leading engineering institutions. \ud83c\udf93`,\n    };\n  }\n\n  // \u2500\u2500 Courses info (not navigation) \u2500\u2500\n  if (\n    contains(\n      msg,\n      "course",\n      "program",\n      "branch",\n      "btech",\n      "b.tech",\n      "mtech",\n      "m.tech",\n      "mba",\n      "engineering branch",\n      "what courses",\n      "which course",\n      "available course",\n    )\n  ) {\n    return {\n      text: `Great question! SNGCE offers a wide range of programs:\\n${COURSES_INFO}\\nWant me to take you to the full Courses page for more details?`,\n    };\n  }\n\n  // \u2500\u2500 Fees info (not navigation) \u2500\u2500\n  if (\n    contains(\n      msg,\n      "fee",\n      "fees",\n      "how much",\n      "cost",\n      "tuition",\n      "scholarship",\n      "fee structure",\n      "annual fee",\n      "semester fee",\n    )\n  ) {\n    return {\n      text: `Sure, here\'s a quick overview of fees at SNGCE:\\n${FEES_INFO}\\nFor the full detailed breakdown, I can take you to the Fees page. Just ask!`,\n    };\n  }\n\n  // \u2500\u2500 Faculty info (not navigation) \u2500\u2500\n  if (\n    contains(\n      msg,\n      "faculty",\n      "teacher",\n      "professor",\n      "lecturer",\n      "staff",\n      "hod",\n      "head of department",\n      "who teaches",\n    )\n  ) {\n    return {\n      text: `${FACULTY_INFO}\\n\\nWant me to take you to the Faculty Directory where you can see everyone listed by department?`,\n    };\n  }\n\n  // \u2500\u2500 Admission \u2500\u2500\n  if (\n    contains(\n      msg,\n      "admission",\n      "apply",\n      "application",\n      "keam",\n      "entrance",\n      "how to join",\n      "eligibility",\n      "how to get admission",\n      "joining",\n    )\n  ) {\n    return {\n      text: `Here\'s how admissions work at SNGCE:\\n${ADMISSION_INFO}\\nFeel free to ask more or contact us at info@sngce.ac.in for guidance!`,\n    };\n  }\n\n  // \u2500\u2500 Departments \u2500\u2500\n  if (contains(msg, "department", "which department", "list of department")) {\n    return {\n      text: `SNGCE has **${COLLEGE_INFO.departments} departments**:\\n${DEPARTMENTS.map((d, i) => `${i + 1}. ${d}`).join("\\n")}\\n\\nEach department has well-qualified faculty and modern lab facilities. \ud83c\udfdb\ufe0f`,\n    };\n  }\n\n  // \u2500\u2500 Hostel \u2500\u2500\n  if (\n    contains(\n      msg,\n      "hostel",\n      "accommodation",\n      "dormitory",\n      "stay on campus",\n      "housing",\n    )\n  ) {\n    return {\n      text: "SNGCE has separate hostels for boys and girls on campus. Hostel fees are approximately **\u20b955,000\u2013\u20b965,000 per year**, including food. The hostels are well-maintained with all basic amenities. For admission to the hostel, contact the hostel warden during college admission time.",\n    };\n  }\n\n  // \u2500\u2500 Facilities \u2500\u2500\n  if (\n    contains(\n      msg,\n      "facilit",\n      "infrastructure",\n      "lab",\n      "library",\n      "sports",\n      "canteen",\n      "cafeteria",\n      "wifi",\n      "campus",\n    )\n  ) {\n    return {\n      text: `SNGCE has excellent campus facilities! Here\'s an overview:\\n${FACILITIES}`,\n    };\n  }\n\n  // \u2500\u2500 Placement \u2500\u2500\n  if (\n    contains(\n      msg,\n      "placement",\n      "job",\n      "recruit",\n      "company",\n      "career",\n      "internship",\n      "campus hire",\n    )\n  ) {\n    return {\n      text: PLACEMENT_INFO,\n    };\n  }\n\n  // \u2500\u2500 Contact \u2500\u2500\n  if (\n    contains(\n      msg,\n      "contact",\n      "address",\n      "phone",\n      "email",\n      "reach",\n      "where is",\n      "location",\n      "how to contact",\n      "get in touch",\n    )\n  ) {\n    return { text: CONTACT_INFO };\n  }\n\n  // \u2500\u2500 Affiliation / University \u2500\u2500\n  if (\n    contains(\n      msg,\n      "affilia",\n      "ktu",\n      "university",\n      "aicte",\n      "approved",\n      "accredit",\n    )\n  ) {\n    return {\n      text: `SNGCE is affiliated to **APJ Abdul Kalam Technological University (KTU)**, Kerala\'s premier technical university. It\'s also approved by **AICTE** (All India Council for Technical Education), ensuring quality standards across all programs. \ud83c\udfc5`,\n    };\n  }\n\n  // \u2500\u2500 Attendance \u2500\u2500\n  if (\n    contains(\n      msg,\n      "attendance",\n      "absent",\n      "present",\n      "how many class",\n      "attendance percentage",\n    )\n  ) {\n    return {\n      text: "KTU mandates a minimum **75% attendance** in all subjects to be eligible for exams. You can check your live attendance percentage in your **Student Dashboard** after logging in. Want me to take you there?",\n    };\n  }\n\n  // \u2500\u2500 Marks / Results \u2500\u2500\n  if (\n    contains(\n      msg,\n      "marks",\n      "result",\n      "grade",\n      "cgpa",\n      "sgpa",\n      "exam result",\n      "internal marks",\n      "series exam",\n    )\n  ) {\n    return {\n      text: "Your marks and results are available in the **Student Dashboard**. This includes internal assessment marks, series exam scores, and semester results. CGPA is calculated based on KTU\'s grading system. Log in to check your records!",\n    };\n  }\n\n  // \u2500\u2500 Exam Timetable \u2500\u2500\n  if (\n    contains(msg, "exam", "timetable", "schedule", "when is exam", "exam date")\n  ) {\n    return {\n      text: "Exam timetables are published by KTU and made available in your **Student Dashboard**. KTU generally conducts semester exams in November\u2013December and April\u2013May. Check the dashboard or KTU\'s official website for the latest schedule.",\n    };\n  }\n\n  // \u2500\u2500 Fees Due \u2500\u2500\n  if (\n    contains(\n      msg,\n      "fees due",\n      "pending fee",\n      "fee due",\n      "pending payment",\n      "overdue fee",\n    )\n  ) {\n    return {\n      text: "You can check your pending fees and payment status in the **Student Dashboard** under \'Fees Due\'. Make sure to clear dues before the exam registration deadline. Need me to take you to the login page?",\n    };\n  }\n\n  // \u2500\u2500 KTU / Syllabus \u2500\u2500\n  if (contains(msg, "syllabus", "curriculum", "ktu syllabus", "subject list")) {\n    return {\n      text: "SNGCE follows the **KTU (APJ Abdul Kalam Technological University)** syllabus. The curriculum is regularly updated to match industry trends. You can find the official syllabus on the KTU website: ktu.edu.in. Is there a specific subject or semester you\'re curious about?",\n    };\n  }\n\n  // \u2500\u2500 Extracurricular / Clubs \u2500\u2500\n  if (\n    contains(\n      msg,\n      "club",\n      "activity",\n      "extracurricular",\n      "nss",\n      "ncc",\n      "cultural",\n      "fest",\n      "event",\n      "techfest",\n      "techno",\n    )\n  ) {\n    return {\n      text: "SNGCE has a vibrant campus life! There are technical clubs, NSS, NCC, arts & cultural groups, and the annual **TECHNO** fest where students showcase their innovations. The college also participates in inter-collegiate competitions across Kerala. \ud83c\udfad\ud83e\udd16",\n    };\n  }\n\n  // \u2500\u2500 Bus / Transport \u2500\u2500\n  if (contains(msg, "bus", "transport", "how to reach", "route", "commute")) {\n    return {\n      text: "SNGCE is located in Kadayirippu, Kolenchery, Ernakulam. There are regular KSRTC and private buses connecting the campus to Koothattukulam and Ernakulam town. The nearest major town is Kolenchery (~5 km). The college also runs its own bus service covering several routes in Ernakulam district for students and staff.",\n    };\n  }\n\n  // \u2500\u2500 Library \u2500\u2500\n  if (\n    contains(\n      msg,\n      "library",\n      "book",\n      "reference",\n      "digital library",\n      "e-library",\n    )\n  ) {\n    return {\n      text: "SNGCE\'s central library houses over **50,000 books** plus journals, references, and digital resources. Students also have access to **NPTEL** and **DELNET** digital libraries. Library hours are typically 9 AM \u2013 5 PM on weekdays.",\n    };\n  }\n\n  // \u2500\u2500 Principal / Management \u2500\u2500\n  if (\n    contains(\n      msg,\n      "principal",\n      "management",\n      "chairman",\n      "director",\n      "head of college",\n      "who runs",\n    )\n  ) {\n    return {\n      text: "SNGCE is managed by the **Sree Narayana Gurukulam Trust**, an institution deeply committed to quality education in the spirit of Sree Narayana Guru\'s philosophy of \'Education for Liberation\'. The college is led by an experienced principal and a dedicated management team. You can reach the college at **0484-2597800** or email **info@sngce.ac.in** for direct contact.",\n    };\n  }\n\n  // \u2500\u2500 Jokes \u2500\u2500\n  if (\n    contains(\n      msg,\n      "joke",\n      "funny",\n      "make me laugh",\n      "tell me a joke",\n      "humour",\n      "humor",\n    )\n  ) {\n    const jokes = [\n      "Why do engineers prefer dark mode? Because light attracts bugs! \ud83d\ude04",\n      "Why was the computer cold? Because it left its Windows open! \ud83d\udcbb\u2744\ufe0f",\n      "How many engineers does it take to change a lightbulb? One \u2014 they just redefine the problem as \'the room is dark\'. \ud83d\ude02",\n      "Why do programmers always mix up Christmas and Halloween? Because Oct 31 == Dec 25! \ud83c\udf83\ud83c\udf84",\n    ];\n    return { text: pick(jokes) };\n  }\n\n  // \u2500\u2500 Motivation / Inspiration \u2500\u2500\n  if (\n    contains(\n      msg,\n      "motivat",\n      "inspir",\n      "quote",\n      "encourage",\n      "feel sad",\n      "stressed",\n      "anxiety",\n      "worried",\n    )\n  ) {\n    const quotes = [\n      "Remember: every expert was once a beginner. Keep pushing forward! The fact that you\'re here means you\'re already on the right path. \ud83d\udcaa",\n      "Engineering is not just a degree \u2014 it\'s a way of thinking. Stay curious, stay persistent! You\'ve got this. \ud83c\udf1f",\n      "Tough times don\'t last, but tough engineers do! Take a break, breathe, and come back stronger. \ud83d\udd25",\n      "Every challenge you face in college is shaping the problem-solver you\'ll become. Trust the process! \ud83c\udf93",\n    ];\n    return { text: pick(quotes) };\n  }\n\n  // \u2500\u2500 What can you do / help \u2500\u2500\n  if (\n    contains(\n      msg,\n      "what can you do",\n      "help me",\n      "what can you help",\n      "how can you help",\n      "what do you know",\n      "capabilities",\n    )\n  ) {\n    return {\n      text: "Sure! Here\'s what I can help you with:\\n\\n**\ud83d\udcda Academic Info:** Courses, fees, faculty, departments, syllabus\\n**\ud83c\udf93 Admissions:** How to apply, entrance exams, eligibility\\n**\ud83c\udfeb Campus:** Facilities, hostel, transport, library, clubs\\n**\ud83d\udcca Student Portal:** Attendance, marks, timetable, fee dues\\n**\ud83d\udd17 Navigation:** Take you to any page \u2014 just ask!\\n**\ud83d\udcac General Chat:** Questions, jokes, motivation, and more!\\n\\nWhat would you like to know?",\n    };\n  }\n\n  // \u2500\u2500 Context-aware follow-up: if last bot message mentioned courses \u2500\u2500\n  if (historyLength > 0) {\n    const lastBotMsg = [...history].reverse().find((h) => h.role === "model");\n    if (lastBotMsg) {\n      if (\n        contains(\n          msg,\n          "yes",\n          "yeah",\n          "sure",\n          "okay",\n          "ok",\n          "please",\n          "take me",\n        ) &&\n        lastBotMsg.text.toLowerCase().includes("courses page")\n      ) {\n        return {\n          text: "Alright, heading to the Courses page now! \ud83d\udcda",\n          redirect: "/courses",\n        };\n      }\n      if (\n        contains(\n          msg,\n          "yes",\n          "yeah",\n          "sure",\n          "okay",\n          "ok",\n          "please",\n          "take me",\n        ) &&\n        lastBotMsg.text.toLowerCase().includes("fees page")\n      ) {\n        return {\n          text: "Sure! Taking you to the Fees page now. \ud83d\udcb0",\n          redirect: "/fees",\n        };\n      }\n      if (\n        contains(\n          msg,\n          "yes",\n          "yeah",\n          "sure",\n          "okay",\n          "ok",\n          "please",\n          "take me",\n        ) &&\n        (lastBotMsg.text.toLowerCase().includes("faculty directory") ||\n          lastBotMsg.text.toLowerCase().includes("faculty page"))\n      ) {\n        return {\n          text: "On it! Taking you to the Faculty Directory. \ud83d\udc68\u200d\ud83c\udfeb",\n          redirect: "/faculty",\n        };\n      }\n      if (\n        contains(\n          msg,\n          "yes",\n          "yeah",\n          "sure",\n          "okay",\n          "ok",\n          "please",\n          "take me",\n        ) &&\n        (lastBotMsg.text.toLowerCase().includes("login") ||\n          lastBotMsg.text.toLowerCase().includes("student dashboard"))\n      ) {\n        return {\n          text: "Taking you to the login page now! \ud83d\udd10",\n          redirect: "/login",\n        };\n      }\n    }\n  }\n\n  // \u2500\u2500 Fallback \u2500\u2500\n  return { text: pick(unknownResponses) };\n}\n\n\n================================================================================\nCATEGORY 7: HOOKS\n================================================================================\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/src/hooks/useQueries.ts\n--------------------------------------------------------------------------------\nimport { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";\nimport type { AcademicRecord, UserProfile } from "../backend.d";\nimport { useActor } from "./useActor";\n\n// \u2500\u2500 Public queries \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nexport function useAllCourses() {\n  const { actor, isFetching } = useActor();\n  return useQuery({\n    queryKey: ["courses"],\n    queryFn: async () => {\n      if (!actor) return [];\n      return actor.getAllCourses();\n    },\n    enabled: !!actor && !isFetching,\n    staleTime: 5 * 60 * 1000,\n  });\n}\n\nexport function useAllFeeStructures() {\n  const { actor, isFetching } = useActor();\n  return useQuery({\n    queryKey: ["feeStructures"],\n    queryFn: async () => {\n      if (!actor) return [];\n      return actor.getAllFeeStructures();\n    },\n    enabled: !!actor && !isFetching,\n    staleTime: 5 * 60 * 1000,\n  });\n}\n\nexport function useFacultyDirectory() {\n  const { actor, isFetching } = useActor();\n  return useQuery({\n    queryKey: ["faculty"],\n    queryFn: async () => {\n      if (!actor) return [];\n      return actor.getFacultyDirectory();\n    },\n    enabled: !!actor && !isFetching,\n    staleTime: 5 * 60 * 1000,\n  });\n}\n\n// \u2500\u2500 Student queries \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nexport function useAttendanceByStudent(studentId: string | null) {\n  const { actor, isFetching } = useActor();\n  return useQuery({\n    queryKey: ["attendance", studentId],\n    queryFn: async () => {\n      if (!actor || !studentId) return [];\n      return actor.getAttendanceByStudent(studentId);\n    },\n    enabled: !!actor && !isFetching && !!studentId,\n  });\n}\n\nexport function useMarksByStudent(studentId: string | null) {\n  const { actor, isFetching } = useActor();\n  return useQuery({\n    queryKey: ["marks", studentId],\n    queryFn: async () => {\n      if (!actor || !studentId) return [];\n      return actor.getMarksByStudent(studentId);\n    },\n    enabled: !!actor && !isFetching && !!studentId,\n  });\n}\n\nexport function useExamTimetable(department: string | null) {\n  const { actor, isFetching } = useActor();\n  return useQuery({\n    queryKey: ["exams", department],\n    queryFn: async () => {\n      if (!actor || !department) return [];\n      return actor.getExamTimetableByDepartment(department);\n    },\n    enabled: !!actor && !isFetching && !!department,\n  });\n}\n\nexport function useFeesDue(studentId: string | null) {\n  const { actor, isFetching } = useActor();\n  return useQuery({\n    queryKey: ["feesDue", studentId],\n    queryFn: async () => {\n      if (!actor || !studentId) return [];\n      return actor.getFeesDueByStudent(studentId);\n    },\n    enabled: !!actor && !isFetching && !!studentId,\n  });\n}\n\nexport function useStudentRecord(studentId: string | null) {\n  const { actor, isFetching } = useActor();\n  return useQuery({\n    queryKey: ["studentRecord", studentId],\n    queryFn: async () => {\n      if (!actor || !studentId) return null;\n      return actor.getStudentRecord(studentId);\n    },\n    enabled: !!actor && !isFetching && !!studentId,\n  });\n}\n\n// \u2500\u2500 Mutations \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nexport function useSaveAcademicRecord() {\n  const { actor } = useActor();\n  const queryClient = useQueryClient();\n  return useMutation({\n    mutationFn: async ({\n      studentId,\n      record,\n    }: { studentId: string; record: AcademicRecord }) => {\n      if (!actor) throw new Error("Actor not available");\n      return actor.addOrUpdateAcademicRecord(studentId, record);\n    },\n    onSuccess: (_, variables) => {\n      queryClient.invalidateQueries({\n        queryKey: ["studentRecord", variables.studentId],\n      });\n      queryClient.invalidateQueries({\n        queryKey: ["attendance", variables.studentId],\n      });\n      queryClient.invalidateQueries({\n        queryKey: ["marks", variables.studentId],\n      });\n      queryClient.invalidateQueries({\n        queryKey: ["feesDue", variables.studentId],\n      });\n    },\n  });\n}\n\nexport function useSaveUserProfile() {\n  const { actor } = useActor();\n  return useMutation({\n    mutationFn: async (profile: UserProfile) => {\n      if (!actor) throw new Error("Actor not available");\n      return actor.saveCallerUserProfile(profile);\n    },\n  });\n}\n\n// \u2500\u2500 Chatbot \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nexport function useChatbotResponse() {\n  const { actor } = useActor();\n  return useMutation({\n    mutationFn: async (message: string) => {\n      if (!actor) throw new Error("Actor not available");\n      return actor.getChatbotResponse(message);\n    },\n  });\n}\n\n\n================================================================================\nCATEGORY 8: STYLING\n================================================================================\n\n--------------------------------------------------------------------------------\nFILE: src/frontend/index.css\n--------------------------------------------------------------------------------\n@tailwind base;\n@tailwind components;\n@tailwind utilities;\n\n/* \u2500\u2500\u2500 Fonts \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n@font-face {\n  font-family: "Bricolage Grotesque";\n  src: url("/assets/fonts/BricolageGrotesque[opsz,wdth,wght].woff2") format("woff2");\n  font-weight: 100 900;\n  font-style: normal;\n  font-display: swap;\n}\n@font-face {\n  font-family: "Outfit";\n  src: url("/assets/fonts/Outfit[wght].woff2") format("woff2");\n  font-weight: 100 900;\n  font-style: normal;\n  font-display: swap;\n}\n\n/* \u2500\u2500\u2500 OKLCH Design Tokens \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n@layer base {\n  :root {\n    --radius: 1rem;\n\n    /* Neutral Grayish Palette \u2013 Light */\n    --background: 0.97 0 0;\n    --foreground: 0.15 0 0;\n    --card: 0.99 0 0;\n    --card-foreground: 0.15 0 0;\n    --popover: 0.99 0 0;\n    --popover-foreground: 0.15 0 0;\n    --primary: 0.25 0 0;\n    --primary-foreground: 0.97 0 0;\n    --secondary: 0.93 0 0;\n    --secondary-foreground: 0.25 0 0;\n    --muted: 0.92 0 0;\n    --muted-foreground: 0.50 0 0;\n    --accent: 0.35 0.04 250;\n    --accent-foreground: 0.97 0 0;\n    --destructive: 0.577 0.245 27.325;\n    --destructive-foreground: 0.985 0 0;\n    --border: 0.88 0 0;\n    --input: 0.88 0 0;\n    --ring: 0.55 0 0;\n    --chart-1: 0.646 0.222 41.116;\n    --chart-2: 0.6 0.118 184.704;\n    --chart-3: 0.398 0.07 227.392;\n    --chart-4: 0.828 0.189 84.429;\n    --chart-5: 0.769 0.188 70.08;\n    --sidebar: 0.95 0 0;\n    --sidebar-foreground: 0.15 0 0;\n    --sidebar-primary: 0.25 0 0;\n    --sidebar-primary-foreground: 0.97 0 0;\n    --sidebar-accent: 0.92 0 0;\n    --sidebar-accent-foreground: 0.25 0 0;\n    --sidebar-border: 0.88 0 0;\n    --sidebar-ring: 0.55 0 0;\n\n    /* Glass vars */\n    --glass-bg: rgba(255, 255, 255, 0.55);\n    --glass-border: rgba(255, 255, 255, 0.7);\n    --glass-shadow: 0 8px 32px rgba(0, 0, 0, 0.12);\n    --glass-btn-bg: rgba(255, 255, 255, 0.65);\n    --glass-btn-hover: rgba(255, 255, 255, 0.85);\n  }\n\n  .dark {\n    --background: 0.10 0 0;\n    --foreground: 0.95 0 0;\n    --card: 0.14 0 0;\n    --card-foreground: 0.95 0 0;\n    --popover: 0.17 0 0;\n    --popover-foreground: 0.95 0 0;\n    --primary: 0.90 0 0;\n    --primary-foreground: 0.14 0 0;\n    --secondary: 0.20 0 0;\n    --secondary-foreground: 0.90 0 0;\n    --muted: 0.20 0 0;\n    --muted-foreground: 0.60 0 0;\n    --accent: 0.55 0.06 250;\n    --accent-foreground: 0.97 0 0;\n    --destructive: 0.704 0.191 22.216;\n    --destructive-foreground: 0.95 0 0;\n    --border: 1 0 0 / 10%;\n    --input: 1 0 0 / 15%;\n    --ring: 0.55 0 0;\n    --chart-1: 0.488 0.243 264.376;\n    --chart-2: 0.696 0.17 162.48;\n    --chart-3: 0.769 0.188 70.08;\n    --chart-4: 0.627 0.265 303.9;\n    --chart-5: 0.645 0.246 16.439;\n    --sidebar: 0.14 0 0;\n    --sidebar-foreground: 0.95 0 0;\n    --sidebar-primary: 0.488 0.243 264.376;\n    --sidebar-primary-foreground: 0.95 0 0;\n    --sidebar-accent: 0.20 0 0;\n    --sidebar-accent-foreground: 0.95 0 0;\n    --sidebar-border: 1 0 0 / 10%;\n    --sidebar-ring: 0.439 0 0;\n\n    /* Glass vars \u2013 dark */\n    --glass-bg: rgba(0, 0, 0, 0.30);\n    --glass-border: rgba(255, 255, 255, 0.12);\n    --glass-shadow: 0 8px 32px rgba(0, 0, 0, 0.40);\n    --glass-btn-bg: rgba(255, 255, 255, 0.10);\n    --glass-btn-hover: rgba(255, 255, 255, 0.20);\n  }\n\n  * {\n    @apply border-border;\n  }\n  body {\n    @apply bg-background text-foreground;\n    font-family: "Outfit", sans-serif;\n  }\n}\n\n/* \u2500\u2500\u2500 Glass Utilities \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n@layer utilities {\n  .glass {\n    background: var(--glass-bg);\n    backdrop-filter: blur(20px) saturate(180%);\n    -webkit-backdrop-filter: blur(20px) saturate(180%);\n    border: 1px solid var(--glass-border);\n    border-radius: 16px;\n    box-shadow: var(--glass-shadow);\n  }\n\n  .glass-sm {\n    background: var(--glass-bg);\n    backdrop-filter: blur(12px) saturate(160%);\n    -webkit-backdrop-filter: blur(12px) saturate(160%);\n    border: 1px solid var(--glass-border);\n    border-radius: 12px;\n    box-shadow: var(--glass-shadow);\n  }\n\n  .glass-btn {\n    background: var(--glass-btn-bg);\n    backdrop-filter: blur(16px) saturate(180%);\n    -webkit-backdrop-filter: blur(16px) saturate(180%);\n    border: 1px solid var(--glass-border);\n    border-radius: 12px;\n    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.10);\n    transition: all 0.2s ease;\n    cursor: pointer;\n  }\n\n  .glass-btn:hover,\n  .glass-btn:focus-visible {\n    background: var(--glass-btn-hover);\n    box-shadow: 0 6px 24px rgba(0, 0, 0, 0.16);\n    transform: translateY(-1px);\n  }\n\n  .glass-btn:active {\n    transform: translateY(0);\n  }\n\n  .glass-pill {\n    background: var(--glass-btn-bg);\n    backdrop-filter: blur(16px) saturate(180%);\n    -webkit-backdrop-filter: blur(16px) saturate(180%);\n    border: 1px solid var(--glass-border);\n    border-radius: 9999px;\n    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);\n    transition: all 0.2s ease;\n  }\n\n  .glass-pill:hover {\n    background: var(--glass-btn-hover);\n    box-shadow: 0 6px 24px rgba(0, 0, 0, 0.20);\n    transform: translateY(-1px);\n  }\n\n  .text-shadow {\n    text-shadow: 0 2px 8px rgba(0, 0, 0, 0.5);\n  }\n\n  .bg-overlay {\n    background: linear-gradient(\n      to bottom,\n      rgba(0, 0, 0, 0.45) 0%,\n      rgba(0, 0, 0, 0.20) 50%,\n      rgba(0, 0, 0, 0.50) 100%\n    );\n  }\n\n  .bg-overlay-light {\n    background: linear-gradient(\n      to bottom,\n      rgba(245, 245, 245, 0.75) 0%,\n      rgba(240, 240, 240, 0.55) 50%,\n      rgba(245, 245, 245, 0.75) 100%\n    );\n  }\n}\n\n/* \u2500\u2500\u2500 Splash Screen Animations \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n@keyframes fadeInUp {\n  from {\n    opacity: 0;\n    transform: translateY(20px);\n  }\n  to {\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n\n@keyframes expandLetters {\n  from {\n    opacity: 0;\n    letter-spacing: -0.15em;\n    transform: scale(0.92);\n  }\n  to {\n    opacity: 1;\n    letter-spacing: 0.15em;\n    transform: scale(1);\n  }\n}\n\n@keyframes subtitleFade {\n  from {\n    opacity: 0;\n    transform: translateY(10px);\n  }\n  to {\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n\n@keyframes progressBar {\n  from { width: 0%; }\n  to { width: 100%; }\n}\n\n@keyframes splashFadeOut {\n  from { opacity: 1; }\n  to { opacity: 0; pointer-events: none; }\n}\n\n@keyframes pulse-glow {\n  0%, 100% { box-shadow: 0 0 20px rgba(255,255,255,0.1); }\n  50% { box-shadow: 0 0 40px rgba(255,255,255,0.25); }\n}\n\n@keyframes float {\n  0%, 100% { transform: translateY(0px); }\n  50% { transform: translateY(-6px); }\n}\n\n.animate-fade-in-up {\n  animation: fadeInUp 0.8s ease forwards;\n}\n\n.animate-expand-letters {\n  animation: expandLetters 1.2s cubic-bezier(0.23, 1, 0.32, 1) forwards;\n}\n\n.animate-subtitle-fade {\n  animation: subtitleFade 0.9s ease forwards;\n}\n\n.animate-progress {\n  animation: progressBar 2.8s ease forwards;\n}\n\n.animate-float {\n  animation: float 3s ease-in-out infinite;\n}\n\n.animate-pulse-glow {\n  animation: pulse-glow 2s ease-in-out infinite;\n}\n\n/* \u2500\u2500\u2500 Scrollbar \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n::-webkit-scrollbar {\n  width: 6px;\n  height: 6px;\n}\n::-webkit-scrollbar-track {\n  background: transparent;\n}\n::-webkit-scrollbar-thumb {\n  background: oklch(var(--muted-foreground) / 30%);\n  border-radius: 9999px;\n}\n\n\n================================================================================\nEND OF FILE\n================================================================================';
